/** Etymology data for lemma IDs in chunk 2 */
export const etymologyChunk2: Record<number, string> = {
  "959": "تَسْتَقْسِمُوا and related words stem from the root ق-س-م, with the root verb قَسَمَ meaning \"he divided\" or \"he allotted.\" اِسْتَقْسَمَ means \"he sought to divide\" or \"he sought to apportion.\" تَسْتَقْسِمُوا means \"you seek to divide\" or \"you seek to apportion,\" emphasizing the deliberate attempt to divide or allocate something, often with precision or fairness. The connection lies in the intentionality of the action, highlighting the importance of careful deliberation when seeking division or apportionment. This term reflects themes of fairness, accountability, and the pursuit of equitable distribution, particularly in contexts requiring justice and integrity.",
  "960": "تَسْرَحُ and related words stem from the root س-ر-ح, with the root verb سَرَحَ meaning \"he went out to pasture,\" \"he roamed freely,\" or \"he let loose.\" تَسْرَحُ means \"it goes forth,\" \"it grazes,\" or \"it wanders freely.\" The connection lies in the concept of movement without restraint, reflecting the root's emphasis on freedom and release. It conveys the idea of animals being allowed to graze openly, symbolizing liberty and natural progression.",
  "961": "تَسْرِيحٌ and related words stem from the root س-ر-ح, with the root verb سَرَحَ meaning \"he let loose,\" \"he released,\" or \"he sent forth.\" تَسْرِيحٌ means \"releasing,\" \"setting free,\" or \"divorcing.\" The connection lies in the act of letting go or granting freedom, directly relating to the root's emphasis on release. In marital contexts, it signifies the act of releasing a spouse with kindness and dignity, highlighting the importance of respectful separation.",
  "962": "تَسْلِيمٌ and related words stem from the root س-ل-م, with the root verb سَلِمَ meaning \"he was safe,\" \"he was sound,\" or \"he was unharmed.\" تَسْلِيمٌ means \"salutations,\" \"peace,\" or \"submission.\" The connection lies in offering peace or surrendering, reflecting the root’s focus on safety and well-being. It highlights extending peace to others through greetings and submitting to divine will. This term emphasizes themes of harmony, respect, and mutual well-being through sincere interactions and spiritual obedience.",
  "963": "تَسْمِيَةٌ and related words stem from the root س-م-و, with the root verb سَمَا meaning \"he was high\" or \"he elevated.\" تَسْمِيَةٌ means \"naming\" or \"designation.\" It represents the act of assigning a name, thus elevating or distinguishing something or someone. The connection emphasizes the power of naming in granting identity and significance, aligning with the root's theme of elevation.",
  "964": "تَسْنِيمٌ and related words stem from the root س-ن-م, with the root verb سَنَمَ meaning \"it was high\" or \"it elevated.\" تَسْنِيمٌ refers to \"a fountain in Paradise\" described as the highest and most elevated. The connection emphasizes the concept of elevation and excellence. It symbolizes the ultimate reward and purity, aligning with the root's theme of height and superiority.",
  "965": "تَشابَهَ and related words stem from the root ش-ب-ه, with the root verb شَبَهَ meaning \"he resembled\" or \"he was similar to.\" تَشابَهَ means \"it seemed alike\" or \"it appeared similar.\" The root conveys the idea of likeness, focusing on the appearance or nature of two things being comparable. تَشابَهَ emphasizes the perception of similarity, where things or situations are seen to resemble one another, whether in appearance, characteristics, or behavior. This connection reflects how resemblance can shape understanding or judgment, allowing for comparisons to be made based on shared qualities.",
  "966": "تَشَاوُرٌ and related words stem from the root ش-و-ر, with the root verb شَاوَرَ meaning \"he consulted\" or \"he sought counsel.\" تَشَاوُرٌ means \"mutual consultation\" or \"deliberation.\" The connection lies in the root's emphasis on sharing opinions and seeking collective wisdom. تَشَاوُرٌ embodies the practice of engaging in collaborative decision-making, reflecting the value of diverse perspectives in reaching sound conclusions, a principle encouraged in Islamic teachings.",
  "967": "تَشِيعَ and related words stem from the root ش-ي-ع, with the root verb شَاعَ meaning \"it spread\" or \"it became public.\" تَشِيعَ means \"it spreads\" or \"it becomes widespread.\" The connection lies in the root's concept of dissemination. It emphasizes the process by which something becomes commonly known or prevalent among people. In the Qur'an, it warns against the spread of immorality, highlighting the impact of publicizing vice and the responsibility to prevent it.",
  "968": "تَشْتَكِي and related words stem from the root ش-ك-و, with the root verb شَكَا meaning \"he complained\" or \"he lamented.\" تَشْتَكِي means \"you complain\" or \"she complains.\" The connection lies in the root's concept of expressing grievance or hardship. تَشْتَكِي reflects the act of articulating one's distress or seeking help by voicing troubles, highlighting the importance of communication in addressing and alleviating suffering.",
  "969": "تَشْخَصُ and related words stem from the root ش-خ-ص, with the root verb شَخَصَ meaning \"he stared\" or \"his eyes became fixed.\" تَشْخَصُ means \"they stare\" or \"they fix their gaze,\" reflecting intense focus or shock. The connection lies in the root's emphasis on fixed attention, often associated with awe or fear, where one's eyes become motionless due to intensity.",
  "970": "تَصَدَّقَ and related words stem from the root ص-د-ق, with the root verb صَدَقَ meaning \"he spoke the truth\" or \"he was sincere.\" تَصَدَّقَ means \"he gave charity\" or \"he was charitable.\" The connection lies in the root's concept of sincerity, extending to acts of genuine generosity. تَصَدَّقَ emphasizes giving as a reflection of one's truthful commitment to faith and compassion. In the Qur'an, it encourages believers to give selflessly, highlighting charity as a tangible expression of sincerity and truth in one's devotion.",
  "971": "تَصَدَّىٰ and related words stem from the root ص-د-ي, with the root verb صَدَىٰ meaning \"he echoed\" or \"he responded.\" تَصَدَّىٰ means \"he turned towards\" or \"he paid attention to.\" The connection lies in the root's concept of responding or giving attention, akin to an echo responding to a sound. تَصَدَّى emphasizes actively engaging with or addressing someone.",
  "972": "تَصِيرُ and related words stem from the root ص-ي-ر, with the root verb صَارَ meaning \"he became\" or \"he turned into.\" تَصِيرُ means \"it becomes\" or \"it reaches,\" reflecting a transformation or a point of arrival. The connection lies in the concept of change or progression, emphasizing the transition from one state to another. This term highlights the notion of development, whether in a physical, temporal, or metaphorical sense, marking the arrival at a new stage or condition.",
  "973": "تَصْدِيقٌ and related words stem from the root ص-د-ق, with the root verb صَدَّقَ meaning \"he confirmed\" or \"he believed.\" تَصْدِيقٌ means \"confirmation,\" \"affirmation,\" or \"belief.\" The connection lies in the root's focus on upholding truth. تَصْدِيقٌ represents the act of affirming the veracity of something, reinforcing its credibility. It emphasizes verification, particularly in belief and acceptance of truth. This term highlights the importance of standing firm in truth and confirming its accuracy. In a deeper sense, it embodies the idea of actively reinforcing truth, not just through words but with sincere actions.",
  "974": "تَصْدِيَةٌ and related words stem from the root ص-د-ي, with the root verb صَدَىٰ meaning \"he echoed\" or \"he clapped.\" تَصْدِيَةٌ means \"clapping\" or \"vain noisy rituals.\" The connection lies in the root's association with sounds that echo or reverberate. In the Qur'an, تَصْدِيَةٌ refers to the clapping practiced by the pagans at the Kaaba as a form of worship, which is deemed empty and devoid of true devotion. It highlights the difference between meaningful worship and superficial acts that lack sincerity.",
  "975": "تَصْرِيفٌ and related words stem from the root ص-ر-ف, with the root verb صَرَفَ meaning \"he turned away\" or \"he varied.\" تَصْرِيفٌ means \"alternation,\" \"diversification,\" or \"dispersion.\" The connection lies in the act of changing or varying something in different ways, symbolizing the process of shifting, altering, or distributing in multiple forms or directions. This term emphasizes the concept of variety, movement, and adjustment, whether in circumstances, actions, or states.",
  "976": "تَصْطَلُونَ and related words stem from the root ص-ل-ي, with the root verb صَلِيَ meaning \"he was burned\" or \"he was exposed to intense heat.\" تَصْطَلُونَ means \"you warm yourselves\" or \"you seek warmth by the fire.\" The connection lies in the idea of approaching a source of heat—specifically fire—either to be warmed or to take refuge from cold. It reflects the root's emphasis on the act of enduring or being subjected to heat, but here, the heat is being sought for a beneficial purpose: warmth or comfort.",
  "977": "تَصْلِيَةٌ and related words stem from the root ص-ل-ي, with the root verb صَلَى meaning \"he burned.\" تَصْلِيَةٌ means \"roasting\" or \"burning.\" The connection lies in the act of exposing something to fire, reflecting the root's emphasis on heat and combustion. In the Qur'an, it refers to the punishment of being burned in Hellfire, highlighting the severe consequences of disbelief and disobedience, and serving as a warning to adhere to righteous conduct.",
  "978": "تَضَرَّعُوا and related words stem from the root ض-ر-ع, with the root verb ضَرَعَ meaning \"he was humble\" or \"he supplicated.\" تَضَرَّعُوا means \"they humbled themselves\" or \"they supplicated,\" emphasizing an active act of earnest prayer. The connection lies in the root's focus on humility and submission, reflecting the lowering of oneself in supplication. This term highlights the outward expression of seeking divine assistance, showing a deep sense of submission and dependency.",
  "979": "تَضَرُّعٌ and related words stem from the root ض-ر-ع, with the root verb ضَرَعَ meaning \"he was humble\" or \"he supplicated.\" تَضَرُّعٌ means \"supplication\" or \"earnest humility,\" representing the act of humbly imploring. The connection lies in embodying the root's concept of humility, emphasizing the internal, personal aspect of seeking divine mercy and recognizing one's vulnerability. This term reflects deep spiritual devotion, highlighting the intimate, humble appeal for Allah's (ﷻ) help, often in moments of distress or need.",
  "980": "تَضْحَىٰ and related words stem from the root ض-ح-و, with the root verb ضَحَا meaning \"it was forenoon\" or \"it became bright.\" تَضْحَىٰ means \"you be exposed to the sun's heat\" or \"you experience the forenoon.\" The connection lies in the idea of daylight or brightness, referring to the time when the sun is at its peak in the early part of the day. This term metaphorically evokes a sense of exposure or experiencing the effects of sunlight, highlighting the time of day when the world is most illuminated.",
  "981": "تَضْلِيلٌ and related words stem from the root ض-ل-ل, with the root verb ضَلَّ meaning \"he went astray.\" تَضْلِيلٌ means \"misguidance\" or \"deception,\" representing the act of leading others astray. The connection lies in the root's concept of error, emphasizing the deliberate act of causing misguidance. This term highlights the serious impact of spreading falsehood and misleading others from the right path, stressing the ethical responsibility to guide others correctly and avoid causing them to deviate from truth.",
  "982": "تَطَاوَلَ and related words stem from the root ط-و-ل, with the root verb طَالَ meaning \"he was long\" or \"he extended.\" تَطَاوَلَ means \"he became prolonged\" or \"he grew long.\" The connection reflects the idea of something being extended or lengthened over time. It implies an action or state where a certain duration, whether of time or physical extension, increases or continues beyond its usual or expected limit. This term emphasizes gradual elongation or stretching, whether in terms of time, space, or even human life.",
  "983": "تَطَهَّرْنَ and related words stem from the root ط-ه-ر, with the root verb طَهَرَ meaning \"he was or became clean or pure.\" تَطَهَّرْنَ means \"they are purified.\" This reflexive command emphasizes personal responsibility in seeking purity. It connects to the root by highlighting the active effort required to cleanse oneself from impurities, both physically and spiritually, to attain closeness to Allah (ﷻ).",
  "984": "تَطَوَّعَ and related words stem from the root ط-و-ع, with the root verb طَاعَ meaning \"he obeyed\" or \"he complied willingly.\" تَطَوَّعَ means \"he volunteered\" or \"he performed willingly.\" This form emphasizes the act of offering oneself voluntarily for a task or good deed. The connection to the root highlights the aspect of willing compliance and self-motivation. In a spiritual context, it signifies the merit of performing voluntary acts of worship or charity beyond obligatory duties.",
  "985": "تَطْهِيرٌ and related words stem from the root ط-ه-ر, with the root verb طَهَرَ meaning \"he was or became clean or pure.\" تَطْهِيرٌ means \"purification\" or \"the act of purifying.\" This term embodies the process of making something pure, extending the root's concept of cleanliness to deliberate actions taken to remove impurities. It signifies the importance of purification rituals and moral cleansing in spiritual practice.",
  "986": "تَظْمَؤُوا and related words stem from the root ظ-م-أ, with the root verb ظَمِئَ meaning \"he thirsted.\" تَظْمَؤُونَ means \"you become thirsty.\" The connection is direct, expressing the state of experiencing thirst. This reflects the root's concept of longing or need for sustenance, emphasizing the essential human experience and dependence on life's necessities.",
  "987": "تَعَاسَرْتُمْ and related words stem from the root ع-س-ر, meaning \"it was difficult,\" \"it was hard,\" or \"it was tight.\" تَعَاسَرْتُمْ means \"you mutually made things difficult for each other,\" or \"you found difficulty with one another.\" The nuance here is the reciprocal action of causing or experiencing difficulty together. This connects to the root's concept of hardship and tightness, emphasizing how lack of cooperation or understanding can lead to mutual strain in relationships or interactions.",
  "988": "تَعَاطَىٰ and related words stem from the root ع-ط-و, with the root verb عَطَا meaning \"he gave.\" تَعَاطَىٰ means \"he undertook,\" \"he engaged in,\" or \"he took upon himself,\" emphasizing the act of willingly involving oneself in an action or practice. The connection lies in the reciprocal nature of giving and taking, reflecting the root’s broader themes of exchange, involvement, and active participation. This term highlights a deliberate commitment to an action, emphasizing the importance of engagement and responsibility in one’s undertakings.",
  "989": "تَعَالَوْا and related words stem from the root ع-ل-و, with the root verb عَلا meaning \"he rose\" or \"he ascended.\" تَعَالَ means \"come,\" \"come up,\" or \"ascend,\" often used as an invitation or command to rise or approach. تَعَالَوْا, addressing a group, means \"come,\" \"come forward,\" or \"ascend together,\" urging others to move upward or closer, either physically or metaphorically. The root’s themes of elevation and rising are evident here, as it signifies an act of leaving a lower position for a higher one, reflecting an invitation to a better state, understanding, or action.",
  "990": "تَعَالَىٰ stems from the root ع-ل-و, with the root verb عَلا meaning \"he rose\" or \"he ascended.\" تَعَالَىٰ means \"He is exalted\" or \"He is Most High,\" emphasizing Allah’s (ﷻ) absolute transcendence, elevation, and perfection. It conveys not only Allah’s (ﷻ) supremacy in essence, attributes, and authority but also His complete freedom from any imperfection or limitation. The term reflects the root’s themes of height and elevation in their most sublime and exclusive sense, highlighting that Allah’s (ﷻ) exaltation is unparalleled and beyond human comprehension, distinct from all creation.",
  "991": "تَعَاوَنُوا and related words stem from the root ع-و-ن, with the root verb عَانَ meaning \"he helped,\" \"he assisted,\" or \"he supported.\" تَعَاوَنُوا means \"help one another,\" emphasizing the mutual and collective effort in providing assistance or support. The connection lies in the root’s focus on aid and support, which, in this form, highlights the reciprocal nature of helping each other. This term reflects the themes of unity, collaboration, and shared responsibility, highlighting the importance of working together to achieve common goals or overcome challenges.",
  "992": "تَعَجَّلَ and related words stem from the root ع-ج-ل, with the root verb عَجِلَ meaning \"he was hasty\" or \"he hurried.\" تَعَجَّلَ means \"he hastened himself\" or \"he acted prematurely.\" The reflexive form emphasizes the subject's own action of hurrying, reflecting the root's concept of haste applied to oneself. It highlights the personal choice to act quickly.",
  "993": "تَعَفُّفٌ and related words stem from the root ع-ف-ف, with the root verb عَفَّ meaning \"he was chaste\" or \"he abstained.\" تَعَفُّفٌ means \"abstinence,\" \"chastity,\" or \"self-restraint.\" The connection lies in the conscious effort to refrain from forbidden or excessive desires, reflecting the root's emphasis on purity and self-control. This term highlights the moral virtue of restraining oneself from indulgence, promoting modesty and integrity.",
  "994": "تَعَمَّدَتْ and related words stem from the root ع-م-د, with the root verb عَمَدَ meaning \"he intended,\" \"he aimed,\" or \"he acted purposefully.\" تَعَمَّدَتْ means \"she or it intended\" or \"she or it acted deliberately,\" emphasizing conscious and purposeful intent. The root dimensions include themes of directness and resolve, highlighting actions carried out with clear aim. These dimensions connect to تَعَمَّدَتْ by portraying deliberate actions as intentional and marked by determination. The word reflects the broader concept of عَمَدَ, where intentionality underpins purposeful efforts, signifying not just intent but decisive and directed actions.",
  "995": "تَعُولُوا and related words stem from the root ع-و-ل, with the root verb عَالَ meaning \"he became burdened with dependents,\" \"he fell into poverty,\" or \"he was overextended.\" تَعُولُوا means \"you overburden\" or \"you become overextended,\" particularly in the context of managing responsibilities, such as supporting dependents or family. The root’s focus is on the strain and imbalance that arise when one takes on more than they can handle. This term highlights the challenges of fulfilling obligations while maintaining balance, serving as a reminder to avoid being overwhelmed by responsibilities to the point of injustice or failure in one’s duties.",
  "996": "تَعِيَ and related words stem from the root و-ع-ى, with the root verb وَعَى meaning \"he comprehended\" or \"he retained.\" تَعِيَ means \"she or it understands\" or \"she or it retains.\" The connection emphasizes the act of conscious comprehension and retention, reflecting the root's focus on awareness and mindfulness. This highlights the importance of being receptive and attentive to knowledge or guidance, ensuring that valuable information is not lost but internalized.",
  "997": "تَعْبَثُونَ and related words stem from the root ع-ب-ث, with the root verb عَبَثَ meaning \"he amused himself idly\" or \"he acted in vain.\" تَعْبَثُونَ means \"you are trifling\" or \"you are acting frivolously.\" The connection lies in engaging in purposeless actions, reflecting the root's concept of vanity and idle play. This term emphasizes the lack of meaningful intent, highlighting the futility of such actions.",
  "998": "تَعْبُرُونَ and related words stem from the root ع-ب-ر, with the root verb عَبَرَ meaning \"he crossed\" or \"he traversed.\" تَعْبُرُونَ means \"you cross\" or \"you traverse,\" but in a figurative sense, it can also mean \"you interpret.\" The connection between crossing and interpretation reflects the act of moving from one point to another, whether physically or mentally, as interpretation involves crossing from one understanding to another. This term emphasizes the transition from literal to metaphorical, highlighting the process of reaching new insights or perspectives.",
  "999": "تَعْتَدُّونَ and related words stem from the root ع-د-د, with the root verb عَدَّ meaning \"he counted\" or \"he enumerated.\" اِعْتَدَّ conveys \"he considered\" or \"he counted for himself.\" تَعْتَدُّونَ means \"you count\" or \"she observes the waiting period (ʿiddah).\" The connection lies in the personal act of counting or reckoning time, reflecting the root's focus on enumeration. This term is significant in Islamic law, where a woman observes ʿiddah after divorce or the death of her husband, carefully counting the prescribed days. It underscores the importance of patience and mindfulness in observing divine commandments.",
  "1000": "تَعْثَوْا and related words stem from the root ع-ث-و, with the root verb عَثَا meaning \"he acted corruptly,\" \"he spread mischief,\" or \"he caused ruin.\" تَعْثَوْا means \"you act corruptly\" or \"you spread corruption.\" The connection lies in engaging in actions that cause disorder and destruction, reflecting the root's emphasis on widespread mischief. It serves as a warning against corrupt behavior that undermines societal harmony.",
  "1001": "تَعْرَىٰ and related words stem from the root ع-ر-ي, with the root verb عَرِيَ meaning \"he was naked,\" \"he was bare,\" or \"he was devoid of something.\" تَعْرَىٰ means \"he became naked,\" \"he was stripped,\" or \"he became exposed.\" The nuance here is the reflexive action of becoming uncovered or stripped of coverings. This connects to the root's concept of bareness or being devoid, emphasizing vulnerability and exposure when one is without protection or concealment, whether physically or metaphorically.",
  "1002": "تَعْسٌ and related words stem from the root ت-ع-س, with the root verb تَعَسَ meaning \"he stumbled and fell upon his face,\" \"he perished,\" or \"he became lowered or degraded.\" تَعْسٌ means \"downfall\" or \"destruction,\" emphasizing a complete fall or state of ruin. The root suggests a condition of degradation or humiliation, where one is brought low, often by one’s own misdeeds or as a consequence of divine punishment. The phrase تَعْسًا لَهُمْ translates as \"for them is downfall,\" conveying a curse or condemnation, where ruin is invoked upon those deserving of it.",
  "1003": "تَغَابُنٌ and related words stem from the root غ-ب-ن, with the root verb غَبَنَ meaning \"he cheated,\" \"he deceived,\" or \"he suffered loss.\" تَغَابُنٌ means \"mutual loss,\" \"mutual deception,\" or \"mutual defrauding.\" The connection lies in the concept of parties causing loss to one another or both suffering loss, reflecting the root's emphasis on deception and loss. In a moral context, this term highlights the consequences of deceit and the ultimate realization of loss, particularly in the hereafter, emphasizing accountability and the rectification of injustices.",
  "1004": "تَغَشَّىٰ and related words stem from the root غ-ش-و, with the root verb غَشِيَ meaning \"he covered,\" \"he enveloped,\" or \"he came over (someone).\" تَغَشَّىٰ means \"he was covered,\" \"he enveloped himself,\" or \"he was enveloped.\" The connection lies in the reflexive or intensive action of covering or being enveloped, directly relating to the root's meaning of covering. This term emphasizes a thorough or complete covering, often used to describe natural phenomena like darkness enveloping the sky or a person being overtaken by sleep.",
  "1005": "تَغَيُّظٌ and related words stem from the root غ-ي-ظ, with the root verb غَاظَ meaning \"he angered\" or \"he provoked.\" تَغَيَّظَ means \"he became enraged\" or \"he was filled with fury,\" and تَغَيُّظٌ refers to \"rage\" or \"fury,\" highlighting an intense internal state of seething anger. Broader root meanings emphasize boiling emotions, internal agitation, and the overwhelming intensity of displeasure. The connection lies in the root’s focus on the powerful and consuming nature of such emotions, reflecting their ability to impact both inner states and outward actions.",
  "1006": "تَغْتَسِلُوا and related words stem from the root غ-س-ل, with the root verb غَسَلَ meaning \"he washed\" or \"he cleansed.\" تَغْتَسِلُوا means \"you bathe yourselves\" or \"you wash yourselves thoroughly.\" The connection lies in the reflexive act of washing oneself, directly relating to the root's meaning of cleansing. This term highlights self-purification and personal responsibility in maintaining cleanliness.",
  "1007": "تَغْفُلُونَ and related words stem from the root غ-ف-ل, with the root verb غَفَلَ meaning \"he was heedless,\" \"negligent,\" or \"unmindful.\" تَغْفُلُونَ means \"you neglect\" or \"you are being heedless.\" This form addresses the ongoing state of personal inattentiveness or negligence. The connection emphasizes the individual's current engagement in unmindfulness, directly relating to the root's concept of being oblivious. It serves as a reminder of the importance of staying alert and conscientious in one's actions to avoid the pitfalls of negligence.",
  "1008": "تَغْلُوا and related words stem from the root غ-ل-و, with the root verb غَلَا meaning \"he exceeded proper bounds,\" \"was excessive,\" or \"overvalued.\" تَغْلُوا means \"you exaggerate\" or \"you overstep bounds.\" This form addresses the act of going beyond limits or being extreme. The connection lies in cautioning against excessiveness and the dangers of exaggeration, reflecting the root's emphasis on moderation. It underscores the importance of balance and restraint in actions and beliefs to maintain harmony and avoid negative consequences.",
  "1009": "تَفَاخُرٌ and related words stem from the root ف-خ-ر, with the root verb فَخَرَ meaning \"he boasted\" or \"he was proud.\" تَفَاخُرٌ means \"mutual boasting\" or \"vying in pride.\" The connection lies in the reciprocal action of individuals boasting to surpass one another, reflecting the root's concept of pride and self-glorification. This term emphasizes competitive arrogance, highlighting the vanity and divisiveness that can result from excessive pride.",
  "1010": "تَفَاوُتٌ and related words stem from the root ف-و-ت, with the root verb فَاتَ meaning \"he passed by\" or \"he escaped.\" تَفَاوُتٌ means \"disparity,\" \"difference,\" or \"inconsistency.\" The connection lies in the concept of things being apart or not aligning, reflecting gaps or variations. This term emphasizes the presence of inequality or lack of uniformity, often highlighting contrasts in creation or circumstances.",
  "1011": "تَفَثَهُمْ and related words stem from the root ت-ف-ث, with the root verb تَفِثَ meaning \"he left himself in a state of untidiness or dirtiness,\" particularly referring to personal hygiene, including hair, nails, and private parts. تَفَثَهُمْ refers to the state of being dirty and untidy, specifically indicating a lack of grooming or care for cleanliness. In the context of Hajj, it relates to pilgrims cutting their hair, trimming nails, and cleaning themselves after the restrictions of Ihram, marking the completion of the pilgrimage with physical cleanliness and the fulfillment of spiritual commitments.",
  "1012": "تَفَرَّقَ and related words stem from the root ف-ر-ق, with the root verb فَرَقَ meaning \"he separated\" or \"he divided.\" تَفَرَّقَ, means \"he dispersed,\" \"he scattered,\" or \"he became divided.\" The reflexive form indicates an action affecting oneself or occurring within a group. The connection lies in the process of division or dispersion, directly relating to the root's concept of separation. This term emphasizes the fragmentation of unity, highlighting the consequences of disunity and the loss of cohesion.",
  "1013": "تَفَسَّحُوا and related words stem from the root ف-س-ح, with the root verb فَسَحَ meaning \"he made wide,\" \"he expanded,\" or \"he made room.\" تَفَسَّحُوا means \"you make room for yourselves\" or \"you widen yourselves.\" The connection lies in the act of creating space within gatherings or assemblies, reflecting the root's emphasis on expansion and accommodation. This term encourages mutual consideration, promoting harmony by physically and metaphorically making space for others.",
  "1014": "تَفَقَّدَ and related words stem from the root ف-ق-د, with the root verb فَقَدَ meaning \"he lost,\" \"he missed,\" or \"he failed to find.\" تَفَقَّدَ means \"he sought to find,\" \"he investigated,\" or \"he inspected.\" The connection lies in actively searching for what is lost or missing, turning the state of loss into an action of careful examination and oversight. This reflects the root's concept of absence, emphasizing diligence and attentiveness in ensuring that nothing is overlooked or unaccounted for.",
  "1015": "تَفَكَّهُونَ and related words stem from the root ف-ك-ه, with the root verb فَكِهَ meaning \"he was cheerful,\" \"he jested,\" or \"he was amused.\" تَفَكَّهُونَ means \"you jest,\" \"you ridicule,\" or \"you are amused.\" The term reflects a deeper sense of amusement often coupled with scorn or mockery, particularly in situations where lightheartedness or jest is misplaced. The root conveys themes of joy, humor, and playfulness, but تَفَكَّهُونَ emphasizes the act of turning something into an object of ridicule, highlighting behavior that can detract from seriousness or respect. This term highlights the impact of inappropriate amusement, especially when it dismisses or belittles important matters.",
  "1016": "تَفِيضُ and related words stem from the root ف-ي-ض, with the root verb فَاضَ meaning \"it overflowed\" or \"it gushed.\" تَفِيضُ means \"it overflows\" or \"it pours forth.\" The connection lies in the ongoing action of overflowing, capturing the root's essence of abundance. This term vividly describes tears or emotions that flow abundantly, reflecting a heart overwhelmed by faith or compassion, emphasizing sincerity and deep emotional response.",
  "1017": "تَفْتَأُ and related words stem from the root ف-ت-أ, with the root verb فَتَأَ meaning \"he ceased\" or \"he desisted.\" تَفْتَأُ means \"you cease\" or \"you stop,\" and when used with negation, it means \"you do not cease.\" The connection lies in the concept of cessation, reflecting the root's emphasis on ending an action. It highlights persistence and continuity, especially in contexts where one refuses to stop a particular behavior or pursuit, highlighting the determination to continue regardless of obstacles or discouragement.",
  "1018": "تَفْجِيرٌ and related words stem from the root ف-ج-ر, with the root verb فَجَرَ meaning \"it burst forth\" or \"it gushed out.\" تَفْجِيرٌ refers to the act of causing something to burst forth with force, typically liquids like water or oil. It signifies a sudden, powerful release, emphasizing magnitude and energy. This term reflects both literal outpourings, such as a spring or river, and metaphorical situations where something contained is abruptly revealed or set free. It conveys the idea of an overwhelming or intense eruption.",
  "1019": "تَفْرِيقٌ and related words stem from the root ف-ر-ق, with the root verb فَرَقَ meaning \"he separated\" or \"he divided.\" تَفْرِيقٌ means \"separation,\" \"division,\" or \"distinction.\" The intensified form underscores deliberate action in causing separation. The connection lies in actively creating divisions, reflecting the root's concept of parting. This term highlights the impact of intentional separation, emphasizing the effects of causing disunity.",
  "1020": "تَفْسِيرٌ and related words stem from the root ف-س-ر, with the root verb فَسَرَ meaning \"he explained,\" \"he made clear,\" or \"he disclosed.\" تَفْسِيرٌ means \"explanation\" or \"interpretation,\" particularly of sacred texts like the Qur'an. The connection lies in the act of uncovering or clarifying meanings, reflecting the root's emphasis on making things clear. This term highlights the importance of understanding and interpreting messages to gain deeper insights and wisdom.",
  "1021": "تَفْصِيلٌ and related words stem from the root ف-ص-ل, with the root verb فَصَلَ meaning \"he separated,\" \"he divided,\" or \"he set apart.\" تَفْصِيلٌ means \"detailed explanation,\" \"elaboration,\" or \"distinction.\" The connection lies in separating information into distinct parts for clarity, reflecting the root's emphasis on division and differentiation. This term highlights the importance of providing detailed understanding by breaking down complex concepts.",
  "1022": "تَفْضَحُونَ and related words stem from the root ف-ض-ح, with the root verb فَضَحَ meaning \"he exposed,\" \"he disgraced,\" or \"he revealed.\" تَفْضَحُونَ means \"you expose\" or \"you disgrace.\" The connection lies in the act of revealing something hidden, often leading to disgrace or embarrassment, reflecting the root's emphasis on exposure. This term highlights the consequences of uncovering secrets or faults, highlighting the importance of discretion.",
  "1023": "تَفْضِيلٌ and related words stem from the root ف-ض-ل, with the root verb فَضَلَ meaning \"he exceeded,\" \"he was superior,\" or \"he remained.\" تَفْضِيلٌ means \"preference,\" \"favoring,\" or \"distinction,\" referring to the act of granting superiority or favor to one over another. The root conveys themes of abundance, excellence, and surpassing, emphasizing the act of elevating or prioritizing. تَفْضِيلٌ highlights the deliberate act of distinguishing or favoring based on merit or purpose, reflecting both the giver's intentionality and the root's essence of surplus and superiority.",
  "1024": "تَفْقِدُونَ and related words stem from the root ف-ق-د, with the root verb فَقَدَ meaning \"he lost,\" \"he missed,\" or \"he lacked.\" تَفْقِدُونَ means \"you lose\" or \"you miss,\" describing the act of being deprived of or unable to find something. The root conveys themes of absence, loss, or deficiency, emphasizing a state of lacking or searching for what is no longer present. تَفْقِدُونَ reflects the experience of noticing or feeling the impact of loss, highlighting the importance of what is absent and the awareness it brings.",
  "1025": "تَقاسَمُوا and related words stem from the root ق-س-م, with the root verb قَسَمَ meaning \"he divided\" or \"he swore an oath.\" تَقاسَمَ means \"they mutually swore\" or \"they shared among themselves.\" The connection highlights collective action in dividing or making oaths together. This term reflects how groups may conspire or agree upon actions, emphasizing the shared responsibility and consequences of their intentions.",
  "1026": "تَقَبَّلَ and related words stem from the root ق-ب-ل, with the root verb قَبِلَ meaning \"he took, received, or admitted willingly,\" or \"he accepted.\" تَقَبَّلَ means \"he accepted graciously\" or \"he received willingly,\" reflecting a deeper and more personal act of acceptance. The connection lies in the root’s emphasis on willingness and receptivity, with تَقَبَّلَ highlighting a sincere, wholehearted acknowledgment. This word particularly emphasizes the importance of genuine approval or acceptance, often associated with spiritual contexts such as the acceptance of prayers or deeds. It reflects an internalized, profound form of reception that aligns with the root’s themes of intentional and gracious acknowledgment.",
  "1027": "تَقَدَّمَ and related words stem from the root ق-د-م, with the root verb قَدُمَ meaning \"he was ancient\" or \"he preceded.\" تَقَدَّمَ means \"he advanced,\" \"he came forward,\" or \"he proceeded.\" The connection lies in the action of moving forward or preceding others, directly relating to the root's concept of advancement and precedence. This term emphasizes progression, leadership, or taking initiative by moving ahead.",
  "1028": "تَقَرَّ and related words stem from the root ق-ر-ر, with the root verb قَرَّ meaning \"he settled,\" \"he remained,\" or \"he became cool.\" تَقَرَّ means \"it found comfort\" or \"it was delighted.\" The connection lies in the root's concept of coolness and settling, reflecting a state of inner peace and satisfaction. This term evokes the imagery of one's eyes becoming cool, symbolizing deep joy and contentment found in life's blessings.",
  "1029": "تَقَطَّعَ and related words stem from the root ق-ط-ع, with the root verb قَطَعَ meaning \"he cut,\" \"he severed,\" or \"he separated.\" تَقَطَّعَ means \"it was cut off,\" \"it was severed,\" or \"it was broken apart.\" The connection lies in the mutual or intensive form of cutting or severing, indicating complete disconnection. The root emphasizes separation and the ending of connections. In a spiritual sense, it can represent the severing of ties due to actions or choices, highlighting the consequences of division and disunity.",
  "1030": "تَقَلُّبٌ and related words stem from the root ق-ل-ب, with the root verb قَلَبَ meaning \"he turned over,\" \"he inverted,\" or \"he changed.\" تَقَلُّبٌ means \"turning,\" \"alternation,\" or \"change,\" emphasizing transformation and fluctuation. The root reflects the dynamic nature of transitions, whether in physical movement or shifts in human conditions.",
  "1031": "تَقِيٌّ and related words stem from the root و-ق-ي, with the root verb وَقَىٰ meaning \"he guarded\" or \"he preserved.\" تَقِيٌّ means \"God-conscious,\" describing someone who actively shields and protects themselves from sin through deep awareness of Allah (ﷻ). The term embodies the root's concept of guarding oneself, highlighting an internal state of vigilance and devotion where consciousness serves as a shield against spiritual and moral harm.",
  "1032": "تَقْتِيلٌ and related words stem from the root ق-ت-ل, with the root verb قَتَلَ meaning \"he killed.\" قَتَّلَ means \"he killed repeatedly\" or \"he massacred.\" تَقْتِيلٌ means \"massacring\" or \"slaughter.\" The connection lies in intensifying the root's concept of killing, emphasizing repeated or excessive killing. It highlights the severity and brutality of mass violence.",
  "1033": "تَقْدِيرٌ and related words stem from the root ق-د-ر, with the root verb قَدَرَ meaning \"he measured,\" \"he determined,\" or \"he decreed.\" تَقْدِيرٌ means \"measurement,\" \"determination,\" or \"decree.\" The connection lies in the act of precisely defining or assigning value and limits, embodying the root's concept of measuring and determining. This term reflects the idea of setting an exact measure or destiny, emphasizing the meticulousness and intentionality in determining outcomes or ordaining events.",
  "1034": "تَقْرِضُ and related words stem from the root ق-ر-ض, with the root verb قَرَضَ meaning \"he cut off,\" \"he severed,\" or \"he gnawed.\" It can also mean \"he lent\" or \"he gave a loan,\" signifying parting with something valuable temporarily. تَقْرِضُ means \"it passes by,\" \"it avoids,\" or \"it cuts through.\" The connection to the root lies in the concept of parting, separating, or leaving behind, whether through physical motion, as in bypassing or avoiding, or through giving, as in lending or offering something. The root emphasizes themes of severance and detachment, whether literal or metaphorical, highlighting movement, transition, or the deliberate act of relinquishing or bypassing.",
  "1035": "تَقْشَعِرُّ and related words stem from the root ق-ش-ع-ر, with the root verb اقْشَعَرَّ meaning \"it shuddered,\" \"it bristled,\" or \"it became rough.\" تَقْشَعِرُّ means \"it shudders\" or \"it trembles,\" emphasizing a physical reaction, such as hair standing on end, often triggered by awe or fear. The connection lies in the profound sensitivity of the body to something overwhelming. This term symbolizes reverence and humility, reflecting the deep connection between emotions and their physical manifestations, especially in response to profound truths or experiences.",
  "1036": "تَقْصُرُوا and related words stem from the root ق-ص-ر, with the root verb قَصَرَ meaning \"he shortened,\" \"he curtailed,\" or \"he confined.\" تَقْصُرُوا means \"you (all) shorten\" or \"you (all) curtail,\" emphasizing the deliberate act of reducing or limiting something. The connection lies in the idea of moderation, whether it pertains to physical dimensions, such as shortening a garment, abstract concepts like curtailing speech, or specific practices such as shortening prayers. This term reflects themes of restraint, intentionality, and practicality, highlighting the importance of adapting actions to circumstances while maintaining balance and purpose.",
  "1037": "تَقْفُ and related words stem from the root ق-ف-و, with the root verb قَفَا meaning \"he followed\" or \"he traced.\" تَقْفُ means \"you follow\" or \"you pursue.\" The connection lies in the act of following closely behind or tracing someone's footsteps. This root emphasizes the concept of pursuit and adherence, highlighting the importance of seeking knowledge and guidance by following established paths or examples. It highlights the significance of mindful pursuit, ensuring that one follows only that which is based on sound knowledge and understanding.",
  "1038": "تَقْهَرْ and related words stem from the root ق-ه-ر, with the root verb قَهَرَ meaning \"he subdued,\" \"he overpowered,\" or \"he compelled.\" تَقْهَرْ means \"you overpower\" or \"you oppress,\" reflecting an act of exerting dominance or control. The root conveys themes of subjugation, authority, and force, emphasizing the ability to bring something or someone under control. This highlights the dual nature of dominance—where it can be justly exercised for order or misused to oppress, highlighting the responsibility tied to the act of overpowering.",
  "1039": "تَقْوَىٰ and related words stem from the root و-ق-ي, with the root verb وَقَىٰ meaning \"he guarded\" or \"he preserved.\" تَقْوَىٰ means \"God-consciousness,\" signifying the state of being spiritually protected through awareness and reverence of Allah (ﷻ). It reflects the root's concept of self-guarding, emphasizing the practice of self-restraint and mindfulness to avoid moral and spiritual harm. تَقْوَىٰ highlights the protective barrier one builds through devotion and righteous actions, ensuring alignment with Allah's (ﷻ) guidance.",
  "1040": "تَقْوِيمٌ and related words stem from the root ق-و-م, with the verb قامَ meaning \"he stood\" or \"he rose.\" The root conveys concepts of uprightness, establishing, and correcting. تَقْوِيمٌ, derived from قَوَّمَ, means \"correction,\" \"straightening,\" or \"setting right.\" It signifies bringing something to its most perfect or balanced state, encompassing both physical and metaphorical refinement. In the context of أَحْسَنِ تَقْوِيمٍ, it refers to overall stature, emphasizing the excellence of human creation, including physical form, upright posture, and the harmonious integration of intellectual and moral qualities, embodying the root’s essence of perfection and alignment with truth.",
  "1041": "تَكَاثُرٌ and related words stem from the root ك-ث-ر, with the root verb كَثُرَ meaning \"it became numerous,\" \"it increased,\" or \"it multiplied.\" تَكَاثُرٌ means \"mutual rivalry in increase,\" \"competition in accumulating,\" or \"vying to surpass others.\" It highlights the act of striving collectively or competitively to outdo others in wealth, status, or possessions. The connection to the root lies in the focus on abundance and multiplication, with this form emphasizing reciprocal action and social dynamics. It also serves as a moral reminder of the human tendency to prioritize material gain over enduring values, cautioning against the fleeting nature of such pursuits.",
  "1042": "تَكْبِيرٌ and related words stem from the root ك-ب-ر, with the root verb كَبُرَ meaning \"he became great\" or \"he grew.\" Derived from كَبَّرَ, meaning \"he magnified\" or \"he declared greatness,\" تَكْبِيرٌ signifies \"magnification\" or the act of saying 'Allahu Akbar'. It reflects the act of proclaiming Allah’s (ﷻ) greatness, embodying the root's essence of magnitude and exaltation. The connection emphasizes acknowledging Allah’s (ﷻ) unparalleled majesty and vastness while directing all reverence toward Him. تَكْبِيرٌ is a central expression of worship, reinforcing the humility and devotion of believers as they recognize Allah’s (ﷻ) supreme greatness.",
  "1043": "تَكْذِيبٌ and related words stem from the root ك-ذ-ب, with the root verb كَذَبَ meaning \"he lied\" or \"he told a falsehood.\" تَكْذِيبٌ means \"denial,\" \"persistent rejection,\" or \"accusation of lying,\" referring to the act of rejecting or discrediting the truth. This form emphasizes the active nature of denying or invalidating truth, often with persistence or repetition. The root meaning encompasses both verbal and practical actions that oppose or deviate from truth. تَكْذِيبٌ highlights an intentional refusal to accept reality or fact, making it a term for sustained opposition to truth or a deliberate stance of falsehood.",
  "1044": "تَكْلِيمٌ and related words stem from the root ك-ل-م, with the root verbs كَلَمَ, meaning \"he wounded,\" and كَـلَّمَ, meaning \"he spoke.\" تَكْلِيمٌ refers to deliberate, impactful, and direct speech, emphasizing purposeful and explicit communication. The connection lies in the act of addressing someone in a manner that leaves no ambiguity, where the speech is clear, intentional, and leaves a lasting impression, much like a wound. This term highlights not just the act of speaking but the profound clarity and influence behind such communication, reflecting the root’s dual meanings of wounding and verbal expression.",
  "1045": "تَلَاقٍ and related words stem from the root ل-ق-ي, with the root verb لَقِيَ meaning \"he met,\" \"he encountered,\" or \"he found.\" تَلَاقٍ means \"meeting\" or \"encounter,\" describing the act of convergence or coming together. The root conveys themes of connection, interaction, and facing others or events, emphasizing the significance of such encounters. In the Qur'an, تَلَاقٍ is notably used in reference to the \"Day of Meeting\" (يَوْمُ التَّلَاقِ), symbolizing the ultimate gathering where all are brought together for accountability and judgment. This term reflects the root’s focus on impactful and purposeful interactions, highlighting the gravity and finality of this profound event.",
  "1046": "تَلَذُّ and related words stem from the root ل-ذ-ذ, with the root verb لَذَّ meaning \"it was pleasant,\" \"delightful,\" or \"enjoyable.\" تَلَذُّ means \"it delights.\" The connection lies in the act of experiencing delight or pleasure, reflecting the root's emphasis on enjoyment and sweetness. This term illustrates the personal experience of pleasure, emphasizing how one actively engages in finding delight, often in sensory experiences that uplift the spirit and bring joy.",
  "1047": "تَلَظَّىٰ and related words stem from the root ل-ظ-ي, with the root verb لَظِيَ meaning \"it burned fiercely,\" \"it blazed,\" or \"it glowed with intense heat.\" تَلَظَّىٰ is an intensified form meaning \"blazing fiercely,\" or \"flaring up violently.\" The root emphasizes the imagery of fire that is not just burning but consuming with extreme heat and brightness, often conveying a sense of destruction or unbearable intensity. Classical sources describe لَظِيَ as signifying flames that leap or are unrestrained in their ferocity. This term reflects the root’s emphasis on unrelenting and overwhelming heat, symbolizing a powerful and consuming force.",
  "1048": "تَلَقَّىٰ and related words stem from the root ل-ق-ي, with the root verb لَقِيَ meaning \"he met,\" \"he encountered,\" or \"he found.\" تَلَقَّىٰ means \"he received,\" \"he was given,\" or \"he came to meet.\" This form emphasizes the action of actively or deliberately receiving or encountering something, often with intention or preparedness. The root conveys themes of meeting, encountering, or being presented with something, whether physical, emotional, or metaphorical. تَلَقَّىٰ is often used to describe significant moments of reception, such as receiving divine messages, wisdom, or important events, highlighting the gravity and purpose of such encounters.",
  "1049": "تَلَهَّىٰ and related words stem from the root ل-ه-و, with the root verb لَهَا meaning \"he was diverted,\" \"he was distracted,\" or \"he engaged in idle amusement.\" تَلَهَّىٰ means \"he amused himself,\" \"he was distracted,\" or \"he engaged in diversion.\" This form highlights self-induced distraction, particularly in circumstances where attention is diverted away from something more pressing or significant. The connection lies in the root's emphasis on diversion and amusement, showing how one’s preoccupation with trivial matters can lead to neglect of important responsibilities or obligations. It serves as a reminder to prioritize attentiveness and avoid distractions that hinder focus on meaningful tasks or relationships.",
  "1050": "تَلَا and related words stem from the root ت-ل-و, and as the root verb, it means \"he recited\" or \"he followed.\" This verb combines reciting and following guidance, reflecting an active engagement where recitation involves understanding, internalizing, and acting on the conveyed message. In the context of the Qur'an, the root emphasizes that recitation is not merely verbal or passive but a deliberate and transformative process that strengthens and deepens one’s connection with Allah (ﷻ), His guidance, and wisdom.",
  "1051": "تَلَّ and related words stem from the root ت-ل-ل, and as the root verb, it means \"he threw down\" or \"he prostrated.\" تَلَّ signifies the act of laying someone down, whether by force or in submission. The root implies both a physical act of lowering and a sense of humbling or bringing low, capturing the idea of placing someone or something in a submissive or vulnerable position. This term can convey both reverence, as in prostration, or force, as in subduing someone.",
  "1052": "تَلْفَحُ and related words stem from the root ل-ف-ح, with the root verb لَفَحَ meaning \"it scorched,\" \"it burned,\" or \"it blasted with heat.\" تَلْفَحُ translates as \"it scorches,\" \"it sears,\" or \"it burns fiercely.\" The root conveys the idea of intense, direct heat or burning, emphasizing its harsh, damaging impact. The connection lies in the overwhelming and inescapable nature of the heat, whether it be from flames, scorching winds, or extreme temperatures. This term vividly illustrates the devastating and relentless effect of intense heat, highlighting the root's focus on the severity of the burning and its capacity to leave lasting marks or destruction.",
  "1053": "تَلْفِتَ and related words stem from the root ل-ف-ت, with the root verb لَفَتَ meaning \"he turned,\" \"he diverted,\" or \"he caused to turn away.\" تَلْفِتَ means \"you turn away\" or \"you divert.\" The root emphasizes the act of shifting direction or attention, whether physically or metaphorically. This term conveys the idea of being drawn away or distracted from a set path, reflecting a loss of focus or purpose. The connection lies in the action of turning from one direction to another, symbolizing a disruption of continuity or steadfastness. It highlights the challenge of maintaining focus and the dangers of being led astray, emphasizing perseverance and deliberate intent in staying on the right course.",
  "1054": "تَلْقَفُ and related words stem from the root ل-ق-ف, with the root verb لَقَفَ meaning \"he caught,\" \"he snatched,\" or \"he seized quickly.\" تَلْقَفُ means \"it seizes swiftly\" or \"it snatches up quickly.\" The connection lies in the rapid and decisive action of taking hold, reflecting the root's emphasis on swift and complete capture. This term vividly conveys the image of something that acts with precision and speed to nullify or overpower, such as the staff of Prophet Moses (ﷺ) swallowing the illusions of the sorcerers, symbolizing the triumph of truth over falsehood.",
  "1055": "تَمَاثِيلُ (plural of تِمْثَالٌ) stems from the root م-ث-ل, with the root verb مَثَلَ meaning \"he resembled,\" \"he was like,\" or \"he set forth an example.\" تَمَاثِيلُ refers to \"statues\" or \"images,\" representing physical likenesses or imitations of beings or objects. The connection lies in the root’s concept of resemblance and imitation, reflecting the act of creating tangible representations that mirror the form or essence of the original. Such representations often serve purposes like commemoration, honor, reverence, worship, superstition, ritualistic use, or protective symbolism. Believers must be extremely wary of any such practices and avoid them without exception, as they constitute shirk, the gravest sin in Islam.",
  "1056": "تَمَارَوْا and related words stem from the root م-ر-ي, with the root verb مَارَىٰ meaning \"he disputed,\" \"he doubted,\" or \"he argued.\" تَمَارَوْا means \"they disputed with one another,\" \"they mutually argued,\" or \"they doubted.\" The root encompasses the concepts of doubt, contention, and mutual questioning, often emphasizing the back-and-forth nature of a debate. تَمَارَوْا highlights an interactive engagement in disputes or doubt, reflecting how skepticism or uncertainty can lead to active argumentation, questioning, or contention.",
  "1057": "تَمَامًا and related words stem from the root ت-م-م, with the root verb تَمَّ meaning \"it became complete, entire, or full.\" تَمَامًا means \"completion\" or \"perfection,\" indicating a state of wholeness or entirety. Rooted in the concept of fullness, تَمَامًا suggests the arrival at a final, intended form with no deficiencies, achieving a harmonious state of balance or perfection.",
  "1058": "تَمَتَّعَ and related words stem from the root م-ت-ع, with the root verb مَتَعَ meaning \"he enjoyed,\" \"he benefited,\" or \"he made use of.\" تَمَتَّعَ means \"he enjoyed thoroughly\" or \"he delighted in.\" This form intensifies the basic meaning, reflecting a deep, prolonged enjoyment or benefit. The connection highlights a sustained and comprehensive experience of pleasure, aligning with the root's emphasis on enduring utility and satisfaction. It signifies a state of being fully engaged in and appreciative of the benefits one receives.",
  "1059": "تَمَثَّلَ and related words stem from the root م-ث-ل, with the root verb مَثَلَ meaning \"he resembled,\" \"he was like,\" or \"he set forth an example.\" تَمَثَّلَ means \"he assumed the likeness,\" \"he appeared in the form,\" or \"he represented.\" The connection lies in embodying or personifying a particular form or quality, reflecting the root's concept of resemblance and exemplification. It emphasizes the act of manifesting characteristics or attributes of something else, often to convey a message or embody an ideal.",
  "1060": "تَمَيَّزُ and related words stem from the root م-ي-ز, with the root verb مَازَ meaning \"he separated\" or \"he distinguished.\" تَمَيَّزُ means \"it bursts,\" \"it is separated,\" or \"it is distinguished.\" This describes an intense or forceful form of separation, often reflecting something breaking apart or being divided due to internal pressure. In certain contexts, such as describing Hell in the Qur'an, it illustrates rage or anger so intense that it causes separation or bursting, emphasizing the dramatic and vivid nature of the term.",
  "1061": "تَمُورُ and related words stem from the root م-و-ر, with the root verb مَارَ meaning \"it moved from side to side,\" \"it moved round about,\" or \"it was in a state of commotion\" or \"tumult.\" تَمُورُ means \"it sways,\" \"it moves side to side,\" or \"it moves round about,\" describing instability or trembling. This term is frequently used to depict natural phenomena such as earthquakes or the swaying of the heavens, emphasizing the fragility of creation and the overwhelming power of Allah (ﷻ). The connection lies in the profound instability reflected in such movements, serving as a reminder of humanity’s dependence on divine stability amidst the inherent uncertainty of the natural world.",
  "1062": "تَمِيدَ and related words stem from the root م-ي-د, with the root verb مَادَ meaning \"it swayed violently,\" \"it moved in a state of motion,\" or \"it became agitated.\" This root conveys instability, oscillation, or unsteady movement, often describing swaying objects or unstable ground. تَمِيدَ means \"it sways\" or \"it shakes,\" emphasizing instability or motion driven by external forces. The root’s broader meanings highlight dynamic or fluctuating states, symbolizing a lack of firmness or steadiness, which can extend metaphorically to physical or abstract contexts of imbalance or uncertainty.",
  "1063": "تَمَّ and related words stem from the root ت-م-م, and as the root verb, it means \"it became complete, entire, or full.\" تَمَّ signifies something reaching its intended end, fully executed and complete. It implies the natural progression toward an endpoint where the purpose is fully realized, capturing both the state of completion and the fulfillment of an intended purpose.",
  "1064": "تَمْرَحُونَ and related words stem from the root م-ر-ح, with the root verb مَرِحَ meaning \"he exulted,\" \"he was joyous,\" or \"he was insolently proud.\" تَمْرَحُونَ means \"you exult\" or \"you act arrogantly.\" The root conveys the idea of excessive joy that crosses into arrogance, highlighting the danger of overstepping bounds due to elation. This term serves as a caution against allowing happiness to lead to prideful or dismissive behavior, reflecting the root's emphasis on balancing joy with humility and avoiding actions that disregard or diminish others.",
  "1065": "تَمْهِيدٌ and related words stem from the root م-ه-د, with the root verb مَهَدَ meaning \"he spread out,\" \"he prepared,\" or \"he made smooth.\" تَمْهِيدٌ means \"preparation,\" \"making smooth,\" or \"arrangement,\" emphasizing the act of thoroughly readying something for ease or stability. The root conveys themes of smoothing a surface, laying a foundation, or facilitating progress. In a broader sense, تَمْهِيدٌ reflects the careful groundwork necessary to achieve harmony and success, whether in physical, social, or spiritual contexts. It highlights the value of deliberate effort and thoughtful planning in creating stability and ensuring favorable outcomes.",
  "1066": "تَنَابَزُوا and related words stem from the root ن-ب-ز, with the root verb نَبَزَ meaning \"he called by a nickname,\" often derogatory or insulting. تَنَابَزُوا means \"they called each other offensively,\" emphasizing the reciprocal act of exchanging offensive names. The root also carries connotations of reviling or insulting, reflecting behaviors that sow discord and emotional harm. This highlights the destructive impact of ridicule and the ethical importance of respectful communication in fostering harmony and preventing hurt in relationships.",
  "1067": "تَنَاجَوْا and related words stem from the root ن-ج-و, with the root verb نَجَا meaning \"he became safe\" or \"he escaped,\" and also \"he conversed secretly.\" تَنَاجَوْا means \"they conversed secretly\" or \"they conferred privately.\" The connection lies in secrecy as a form of \"escape\" or separation from the public eye, where private conversations safeguard intentions or plans. This reflects themes of confidentiality, intention, and the outcomes of such discussions—whether for good or ill. The act of secret conversation mirrors the root's sense of seeking refuge, emphasizing the balance between sincerity and accountability in private exchanges.",
  "1068": "تَنَادَوْا and related words stem from the root ن-د-ي, with the root verb نَدَا meaning \"he called,\" \"he proclaimed,\" or \"he invited.\" تَنَادَوْا means \"they called out to one another\" or \"they summoned each other.\" It reflects a reciprocal action, emphasizing mutual communication among a group. This root encompasses concepts of calling out, proclaiming, and gathering people through vocal means. The connection lies in the collective nature of calling embedded in the root. In the Qur'an, تَنَادَوْا is used to depict scenes of urgency or collective action.",
  "1069": "ٱلتَّنَادِ and related words stem from the root ن-د-ي, with the root verb نَدَا meaning \"he called,\" \"he proclaimed,\" or \"he invited.\" The root encompasses themes of vocal proclamation, summoning, and gathering people through a call. ٱلتَّنَادِ means \"the Calling,\" signifying a momentous event characterized by cries, calls, or proclamations. It refers to the Day of Judgment, when individuals will call out in distress, seek help, summon others, or be summoned themselves for accountability. This term embodies the root’s essence of vocal outreach and collective summoning, highlighting the urgent, communal, and decisive nature of the event.",
  "1070": "تَنَازَعُوا and related words stem from the root ن-ز-ع, with the root verb نَزَعَ meaning \"he pulled out\" or \"extracted.\" The root conveys pulling, extracting, or removing with effort or force. تَنَازَعُوا means \"they disputed with one another\" or \"they contended,\" reflecting a reciprocal struggle where parties pull in opposition to assert their position. The connection lies in the metaphorical extension of pulling to conflict, portraying disputes as mutual exertion. In harmonious exchanges, تَنَازَعُوا can also mean \"they exchanged,\" showing the root’s adaptability to signify contention or sharing. In the Qur'an, its use with intoxicants shows they cause discord, contrasting with harmony in Paradise.",
  "1071": "تَناصَرُوا and related words stem from the root ن-ص-ر, with the root verb نَصَرَ meaning \"he helped.\" تَناصَرُوا means \"they helped each other,\" emphasizing mutual assistance and solidarity. The connection lies in the cooperative effort to provide aid, reflecting the root’s emphasis on collective support and shared victory. تَناصَرُوا highlights the importance of unity and cooperation within a community, highlighting how mutual support strengthens relationships and ensures shared success in overcoming challenges.",
  "1072": "تَناوُشٌ and related words stem from the root ن-و-ش, with the root verb نَوَشَ meaning \"he reached for something\" or \"he grasped something distant.\" تَناوُشٌ refers to \"an attempt to reach or grasp,\" often in a context where the object or goal is beyond reach. In the Quran, it highlights the disbelievers' belated attempt to attain faith at a point where such efforts are futile, as the opportunity to act has passed. This term highlights the importance of seizing the proper time for action and avoiding procrastination in matters of faith and righteousness, emphasizing that delay leads to loss when the window for meaningful action closes.",
  "1073": "تَنْتَشِرُونَ and related words stem from the root ن-ش-ر, with the root verb نَشَرَ meaning \"he spread out,\" \"he unfolded,\" or \"he disseminated.\" تَنْتَشِرُونَ means \"you disperse,\" \"you spread out,\" or \"you scatter.\" The root conveys the action of expansion or distribution, emphasizing movement from a central point. This term describes beings dispersing across the earth, reflecting themes of motion, activity, and the natural spreading of life. It symbolizes the dynamic flow of human life, as individuals move and engage in their worldly endeavors.",
  "1074": "تَنْزِيلٌ and related words stem from the root ن-ز-ل, with the root verb نَزَلَ meaning \"he descended,\" \"he came down,\" or \"he alighted.\" تَنْزِيلٌ means \"revelation,\" \"gradual revelation,\" or \"gradual descent,\" referring to the deliberate process of divine guidance or scripture being sent down. The root encompasses meanings such as \"to bring down,\" \"to settle,\" and \"to guide downward.\" تَنْزِيلٌ reflects the sanctity and methodical nature of revelation, emphasizing its role as a purposeful and impactful act of guidance from Allah (ﷻ).",
  "1075": "تَنْفُذُونَ and related words stem from the root ن-ف-ذ, with the root verb نَفَذَ meaning \"he penetrated,\" \"he passed through,\" or \"he escaped.\" تَنْفُذُونَ means \"you penetrate\" or \"you pass through,\" reflecting the act of moving through barriers or boundaries. The root also conveys the idea of exhaustion or depletion, as in using up resources or options after passing through. In the Qur'anic context, it challenges humankind and jinn to attempt to penetrate the boundaries of the heavens and the earth, emphasizing their limitations and the supremacy of Allah (ﷻ). This captures the root's theme of passing through obstacles while highlighting the futility of escaping Allah's (ﷻ) dominion without His permission.",
  "1076": "تَنكِيلٌ and related words stem from the root ن-ك-ل, with the root verb نَكَلَ meaning \"he refrained\" or \"he punished severely.\" تَنكِيلٌ means \"severe punishment\" or \"exemplary punishment.\" The connection is that such punishment serves as a deterrent, causing others to refrain from similar actions, directly relating to the root's concept of refraining due to fear of consequences. It highlights the idea of making an example to prevent wrongdoing.",
  "1077": "تَنَزَّلَتْ and related words stem from the root ن-ز-ل, with the root verb نَزَلَ meaning \"he descended,\" or \"he came down.\" The root also encompasses meanings such as \"to move from a higher place to a lower one,\" \"to dismount,\" and \"to settle or lodge.\" تَنَزَّلَتْ means \"it descended\" or \"they descend repeatedly,\" emphasizing a gradual or systematic descent. This form reflects the idea of a deliberate and recurring action, aligning with the root's core themes of measured or purposeful coming down. The intensification inherent in this form highlights the sequential and intentional nature of the descent, whether referring to spiritual, physical, or symbolic realms.",
  "1078": "تَنَفَّسَ and related words stem from the root ن-ف-س, with the root verb نَفَسَ meaning \"he breathed\" or \"he exhaled.\" تَنَفَّسَ means \"he or it took a breath\" or \"he or it breathed deeply,\" often implying relief or rejuvenation. The connection lies in the act of breathing as a renewal of life and alleviation of stress, directly relating to the root's meaning. This term symbolizes the refreshing and vitalizing aspects of taking a deep breath, reflecting the essential role of breath in sustaining life.",
  "1079": "تَنُوءُ and related words stem from the root ن-و-أ, with the root verb نَاءَ meaning \"he was heavy,\" \"he leaned,\" or \"he weighed down.\" تَنُوءُ means \"it weighs down\" or \"it burdens.\" The connection lies in the sense of being burdened by weight, reflecting the root's emphasis on heaviness and strain. It highlights how excessive wealth or responsibilities can become a burden, as in the story of Korah whose wealth was so abundant that it weighed down even the strongest carriers.",
  "1080": "تَنِيَ and related words stem from the root ت-ن-ي, and as the root verb it means \"he slackened\" or \"he became negligent.\" The connection is direct, reflecting the root's concept of weakening or losing resolve. It emphasizes a decrease in effort or determination, highlighting the importance of perseverance and steadfastness.",
  "1081": "تَنُّورٌ is derived from the Aramaic tannūrā, meaning \"oven,\" and in Arabic, it refers to a ground-embedded baking oven. It also describes the highest ground or a place where water pours forth. In the story of Prophet Noah (ﷺ), the overflowing of the oven symbolizes the start of the flood. The image of an oven, traditionally associated with fire, overflowing with water, reflects the earth’s eruption and Allah’s (ﷻ) power to bring both destruction and purification.",
  "1082": "تَنْهَرْ and related words stem from the root ن-ه-ر, with the root verb نَهَرَ meaning \"he turned away\" or \"he averted.\" تَنْهَرْ means \"you rebuke,\" \"you scold,\" or \"you turn away,\" often implying a harsh or forceful action to deter or reject. The root conveys themes of restraint and separation, reflecting an active effort to set boundaries. تَنْهَرْ emphasizes the importance of addressing situations with care and avoiding undue harshness, particularly in contexts requiring compassion and understanding.",
  "1083": "تَنْبُتُ and related words stem from the root ن-ب-ت, with the root verb نَبَتَ meaning \"it grew\" or \"it sprouted.\" تَنْبُتُ means \"it grows\" or \"she grows,\" often referring to plants or vegetation. The connection lies in the natural process of growth and development, aligning with the root's emphasis on sprouting and flourishing. This reflects the continuous and life-giving processes in nature, symbolizing renewal and the nurturing aspects of creation.",
  "1084": "تَهَجَّدْ and related words stem from the root ه-ج-د, with the root verb هَجَدَ meaning \"he slept\" or \"he rested at night.\" The derived form تَهَجَّدَ means \"he forsook sleep to perform worship at night,\" emphasizing the act of rising from rest specifically for prayer. This term reflects the root’s dual themes of rest and the deliberate forsaking of it for a higher purpose. The root also conveys notions of discipline and devotion, as the act of تَهَجَّدْ requires overcoming the natural inclination for rest to engage in spiritual acts. It highlights the profound commitment involved in night worship, symbolizing the believer's dedication to connecting with Allah (ﷻ) during the stillness of the night.",
  "1085": "تَهْلُكَةٌ and related words stem from the root ه-ل-ك, with the root verb هَلَكَ meaning \"he perished,\" \"he died,\" or \"he was destroyed.\" تَهْلُكَةٌ means \"destruction,\" \"ruin,\" or \"perdition.\" This term embodies the root's concept by representing the state or means leading to destruction. It reflects themes of downfall and catastrophe inherent in the root, emphasizing severe consequences resulting in ultimate ruin.",
  "1086": "تَوَارَتْ and related words stem from the root و-ر-ي, with the root verb وَارَى meaning \"he concealed\" or \"he hid.\" تَوَارَتْ means \"it concealed herself\" or \"it hid.\" The connection lies in the action of withdrawing from sight, reflecting the root's concept of concealment. In the Qur'an, it can describe the sun setting: \"فَتَوَارَتْ بِالْحِجَابِ\" meaning \"so it concealed itself behind the veil.\"",
  "1087": "تَواصَى and related words stem from the root و-ص-ي, with the root verb وَصَّى meaning \"he enjoined\" or \"he advised earnestly.\" تَواصَى means \"they enjoined upon one another\" or \"they exhorted each other.\" The connection to the root highlights reciprocal action, where individuals collectively encourage or advise each other in matters of truth and patience. In the Qur'an, it emphasizes the importance of mutual exhortation in upholding righteous deeds and perseverance.",
  "1088": "تَواعَدَ and related words stem from the root و-ع-د, with the root verb وَعَدَ meaning \"he promised.\" تَواعَدَ is a reciprocal verb meaning \"they made a mutual promise\" or \"they agreed together.\" The connection lies in the mutual commitment between parties, emphasizing the root's concept of giving one's word and the trust involved in such agreements. This highlights the importance of reciprocal trust and the binding nature of mutual promises in fostering strong relationships.",
  "1089": "تَوَجَّهَ and related words stem from the root و-ج-ه, with the root verb وَجَّهَ meaning \"he directed\" or \"he oriented.\" تَوَجَّهَ means \"he turned towards,\" \"he faced,\" or \"he directed himself.\" The connection lies in the action of orienting oneself or turning towards a direction or goal, directly relating to the root's emphasis on facing or directing. This term emphasizes intentional movement or focus towards a particular objective.",
  "1090": "تَوَفَّىٰ and related words stem from the root و-ف-ى, with the root verb وَفَىٰ meaning \"he fulfilled\" or \"he completed.\" تَوَفَّىٰ means \"to take fully,\" \"to take completely,\" or \"to cause to die.\" The connection lies in the idea of completing or fulfilling something in its entirety, such as the taking of the soul at the appointed time. This reflects the root's emphasis on fulfillment and completeness, highlighting the inevitability of death and the realization of Allah's (ﷻ) decree in the cycle of life.",
  "1091": "تَوَكَّلْ and related words stem from the root و-كـ-ل, with the root verb وَكَـلَ meaning \"he entrusted\" or \"he relied upon.\" تَوَكَّلْ means \"put your trust.\" The root concepts include entrusting responsibilities, appointing someone as a guardian, and dependence. The connection lies in the act of entrusting oneself or one's affairs to another, embodying the root's concept of reliance and trust. It emphasizes the importance of placing confidence in a higher power or trustworthy entity, highlighting surrender and faith over personal control.",
  "1092": "تَوَلَّىٰ and related words stem from the root و-ل-ي, with the root verb وَلِيَ meaning \"he was near,\" \"he befriended,\" or \"he protected.\" The root conveys broader concepts of nearness, guardianship, authority, and relational dynamics. تَوَلَّىٰ means \"he turned\" or \"he took charge,\" reflecting a shift in position or responsibility. The connection lies in altering proximity or roles, whether by moving away or assuming authority, emphasizing the root’s focus on closeness, movement, and leadership.",
  "1093": "تَوَّابٌ and related words stem from the root ت-و-ب, with the root verb تَابَ meaning \"he repented\" or \"he returned [to God] from sin to obedience.\" التَّوَّابُ, one of Allah's (ﷻ) perfect names, means \"The Accepter of Repentance,\" emphasizing His continuous readiness to forgive and His boundless mercy. In the Qur'an, Allah (ﷻ) is described as التَّوَّابُ الرَّحِيمُ (The Accepter of Repentance, The Most Merciful), urging believers to seek forgiveness and reconnect with Him. This name reassures that Allah (ﷻ) consistently welcomes sincere repentance, forgiving without limits, underlining themes of return, renewal, and divine mercy in every act of repentance.",
  "1094": "تَوْبٌ and related words stem from the root ت-و-ب, with the root verb تَابَ meaning \"he repented\" or \"he returned [to God] from sin to obedience.\" تَوْبٌ means \"repentance,\" capturing the essence of a sincere return to Allah (ﷻ) after error. The root emphasizes a process of self-correction, where one acknowledges wrongdoing and seeks closeness to Allah (ﷻ) through sincere intention. تَوْبٌ signifies repentance as an act of purification and renewal, representing a heartfelt turn away from sin and toward obedience and spiritual growth.",
  "1095": "تَوْبَةٌ and related words stem from the root ت-و-ب, with the root verb تَابَ meaning \"he repented\" or \"he returned [to God] from sin to obedience.\" تَوْبَةٌ means \"repentance.\" It conveys the essence of returning to Allah (ﷻ) with a purified heart. تَوْبَةٌ emphasizes the humility and sincerity involved in repenting, often denoting a complete turning away from sin. The root reflects the idea of repentance as both a cleansing act and a reaffirmation of commitment to Allah's (ﷻ) guidance.",
  "1096": "تَوْرَاةُ is derived from the Hebrew Torah (תּוֹרָה), rooted in the verb Y.R.H (ירה), meaning \"to throw\" or \"to cast.\" This root also extends to mean \"to guide\" or \"to instruct,\" reflecting the idea of directing someone towards a goal or path. تَوْرَاةُ refers to the divine scripture revealed to Prophet Moses (ﷺ), serving as a source of law and guidance for the Children of Israel. It embodies both the act of casting guidance and providing direction through sacred law.",
  "1097": "تَوْصِيَةٌ and related words stem from the root و-ص-ي, with the root verb وَصَّى meaning \"he enjoined\" or \"he advised earnestly.\" تَوْصِيَةٌ means \"recommendation,\" \"instruction,\" or \"advice.\" It refers to the act of giving counsel or making a bequest. The connection to the root involves the conveying of important directives or guidance, often carrying a sense of duty or moral responsibility.",
  "1098": "تَوْفِيقٌ and related words stem from the root و-ف-ق, with the root verb وَفَقَ meaning \"he agreed\" or \"he succeeded.\" تَوْفِيقٌ means \"success\" or \"harmony.\" The connection lies in achieving alignment with what is right and suitable, reflecting the root's emphasis on agreement and proper guidance. It highlights the idea that true success comes from being in harmony with righteousness, attained through Allah's (ﷻ) guidance and support.",
  "1099": "تَوْكِيدٌ and related words stem from the root و-ك-د, with the root verb وَكَدَ meaning \"he confirmed\" or \"he asserted.\" تَوْكِيدٌ means \"emphasis\" or \"confirmation.\" The connection lies in reinforcing a statement or commitment, reflecting the root's emphasis on certainty and assurance. This highlights the importance of clarity and strength in communication, ensuring that messages are understood and taken seriously, which is essential for effective dialogue and trust.",
  "1100": "تَيَسَّرَ and related words stem from the root ي-س-ر, with the root verb يَسَرَ meaning \"it became easy.\" تَيَسَّرَ means \"it became easy\" or \"it was facilitated,\" emphasizing the transformation of a situation into ease. The root conveys broader concepts of ease, simplicity, facilitation, and accessibility. The connection lies in the root’s focus on removing obstacles and making things manageable, reflecting the transition from difficulty to simplicity.",
  "1101": "تَيَمَّمُوا and related words stem from the root ي-م-م, with the root verb يَمَّمَ meaning \"he aimed for\" or \"he directed himself towards.\" تَيَمَّمُوا means \"aim for\" or \"perform dry ablution,\" referring to the act of using clean earth for purification when water is unavailable. The root conveys broader concepts of intention, purpose, and direction. The connection lies in the act of intentionally aiming for purification and directing oneself toward spiritual readiness, reflecting the root’s focus on deliberate action and devotion, even in the face of adversity.",
  "1102": "تُبَذِّرْ and related words stem from the root ب-ذ-ر, with the root verb بَذَرَ meaning \"he scattered\" or \"he sowed seeds.\" تُبَذِّرْ means \"you waste\" or \"you squander,\" emphasizing the act of dispersing resources carelessly. The root conveys themes of scattering and distribution, which, when done irresponsibly, lead to wastefulness. تُبَذِّرْ highlights the importance of adhering to Allah’s (ﷻ) commands to avoid excess and irresponsibility in using resources, emphasizing moderation and accountability as central principles.",
  "1103": "تُبَّعٌ and related words stem from the root ت-ب-ع, with the root verb تَبِعَ meaning \"he followed.\" تُبَّعٌ refers to a title given to the ancient Himyarite kings who ruled in Yemen, meaning \"successor\" or \"follower.\" These kings were Arab descendants of Qahtan and were called تُبَّعٌ because they succeeded one another, following in the previous king's course of actions. The connection lies in succession and leadership, emphasizing the continuity of authority and the responsibilities of rulership. In a tradition, تُبَّعٌ also refers to a specific king who was a believer while his people were unbelievers.",
  "1104": "تُبْقِي and related words stem from the root ب-ق-ي, with the root verb بَقِيَ meaning \"he remained,\" \"he endured,\" or \"he stayed behind.\" تُبْقِي means \"she or it leaves remaining,\" \"she or it preserves,\" or \"she or it keeps alive,\" reflecting the act of causing something to endure or preventing its disappearance. The root conveys themes of endurance, preservation, and continuity, emphasizing the purposeful effort to sustain or safeguard something. تُبْقِي highlights the active role in maintaining what is valuable or significant, ensuring its resilience and persistence over time.",
  "1105": "تُحَدِّثُ and related words stem from the root ح-د-ث, with the root verb حَدَثَ meaning \"it was new or recent,\" or \"it came into existence,\" or \"it happened.\" تُحَدِّثُ means \"you tell\" or \"she or it reports,\" referring to the act of narrating or recounting events. The root broadly conveys meanings of occurrences, newness, and communication. The connection lies in transforming events or happenings into narratives, turning them into shared knowledge through speech. This emphasizes the role of storytelling in conveying new information, preserving history, and fostering understanding.",
  "1106": "تُحَرِّكْ and related words stem from the root ح-ر-ك, with the root verb حَرُكَ meaning \"he or it was in motion\" or \"he or it was moved.\" حَرَّكَ means \"he moved,\" and تُحَرِّكْ means \"you move\" or \"you stir,\" emphasizing the act of initiating movement or causing something to shift. The connection lies in the root's fundamental focus on motion, capturing the dynamic quality of stirring or prompting change. It symbolizes action, instigation, or the catalyst for transformation.",
  "1107": "تُخافِتْ and related words stem from the root خ-ف-ت, with the root verb خَفَتَ meaning \"he became silent, quiet, or still,\" or \"he became low in sound or voice.\" خَافَتَ means \"he spoke in a low voice.\" تُخافِتُ means \"you lower your voice (toward something or someone else).\" The root conveys silence, quietness, and reducing sound. It describes becoming silent or lowering one's voice, as well as inducing quietness. The connection emphasizes reducing volume in speech, symbolizing secrecy, humility, or attentiveness. In a spiritual context, it refers to the appropriate tone in prayer or discourse.",
  "1108": "تُخَالِطُونَ and related words stem from the root خ-ل-ط, with the root verb خَلَطَ meaning \"he mixed\" or \"he blended.\" تُخَالِطُونَ means \"you mix\" or \"you mingle\" (plural), emphasizing active association and interaction with others. The root conveys mixing, blending, and intermingling, whether harmoniously or chaotically. The connection highlights how companionship and interaction influence one’s character and conduct, emphasizing the transformative impact of one’s environment and relationships, whether in refining or distorting one's nature.",
  "1109": "تُدِيرُونَ and related words stem from the root د-و-ر, with the root verb دَارَ meaning \"he or it turned, revolved, or rotated.\" تُدِيرُونَ means \"you carry out\" or \"you manage,\" emphasizing active control or influence over movement. The root reflects themes of turning, revolving, and circular motion. Just as something that turns follows a controlled direction, this word conveys the idea of overseeing, directing, or regulating matters, highlighting an ongoing and intentional effort to keep things in motion or under control.",
  "1110": "تُذِلُّ and related words stem from the root ذ-ل-ل, with the root verb ذَلَّ meaning \"he was lowly, humbled, or became submissive.\" تُذِلُّ means \"you humiliate\" or \"you cause to be humbled,\" reflecting the act of bringing someone into a state of humility or submission. This directly connects to the root's emphasis on lowering or subduing, highlighting the ethical considerations in how one treats others and emphasizing the importance of compassion over humiliation.",
  "1111": "تُرَابٌ and related words stem from the root ت-ر-ب, with the root verb تَرِبَ meaning \"he became dusty\" or \"he was destitute.\" تُرَابٌ means \"dust\" or \"fine, dry particles of earth.\" The association with dust emphasizes humility, mortality, and human origin, as dust represents both the material from which humans were created and the state to which they will return. This term also reflects the fragility and transience of human life, grounding it in the natural world and the concept of returning to a humble origin.",
  "1112": "تُرَاثٌ and related words stem from the root و-ر-ث, with the root verb وَرِثَ meaning \"he inherited.\" تُرَاثٌ means \"inheritance,\" \"heritage,\" or \"legacy.\" The connection lies in the accumulated wealth, knowledge, traditions, or cultural values passed down through generations, reflecting the root's emphasis on inheritance. This term encompasses both tangible and intangible assets, highlighting the importance of preserving and honoring what predecessors have entrusted to us.",
  "1113": "تُرِيحُونَ and related words stem from the root ر-و-ح, with the root verb رَاحَ meaning \"he departed\" or \"he found rest.\" تُرِيحُونَ means \"you give rest,\" conveying the causative sense of providing relief or comfort. The connection lies in facilitating a departure from toil or distress, directly relating to the root's concept of moving toward relaxation and serenity.",
  "1114": "تُرْجِي and related words stem from the root ر-ج-و, with the root verb رَجَا meaning \"he hoped\" or \"he expected,\" and أَرْجَىٰ meaning \"he delayed\" or \"he postponed.\" تُرْجِي means \"you delay\" or \"you postpone.\" The connection lies in causing something to be awaited, reflecting the root's emphasis on expectation. This term signifies the act of deferring, emphasizing control over timing and the management of affairs.",
  "1115": "تُرْهِبُ and related words stem from the root ر-ه-ب, with the root verb رَهِبَ meaning \"he feared\" or \"he was in awe.\" أَرْهَبَ means \"he frightened\" or \"he intimidated.\" تُرْهِبُ means \"you frighten\" or \"you intimidate,\" addressing someone directly. The connection lies in the act of causing fear, directly relating to the root's meaning. This term can be used in contexts of deterrence or warning, emphasizing the impact of instilling fear to prevent undesirable actions.",
  "1116": "تُسَاقِطْ and related words stem from the root س-ق-ط, with the root verb سَقَطَ meaning \"he fell\" or \"it fell.\" تُسَاقِطْ means \"let fall\" or \"cause to fall repeatedly.\" The connection lies in the act of causing something to drop successively, directly relating to the root's emphasis on falling. In the Qur'anic context, it illustrates the request for fruits to fall from a palm tree, symbolizing the seeking of sustenance and divine provision in times of need.",
  "1117": "تُسَوَّىٰ and related words stem from the root س-و-ي, with the root verb سَوَّىٰ meaning \"he made equal,\" \"he leveled,\" or \"he fashioned.\" تُسَوَّىٰ is a passive form meaning \"it is leveled,\" \"it is made uniform,\" or \"it is adjusted.\" The root conveys the ideas of symmetry, uniformity, and correction, emphasizing the process of rectifying or balancing. تُسَوَّىٰ highlights the act of shaping or adjusting something into an even and harmonious state, often used in the context of leveling the earth or fashioning creation.",
  "1118": "تُسِيمُونَ and related words stem from the root س-و-م, with the root verb سَامَ meaning \"he pastured,\" \"he grazed,\" or \"he let (animals) graze freely.\" تُسِيمُونَ means \"you pasture,\" or \"you graze.\" The connection lies in the act of allowing livestock to move freely for grazing, reflecting the root's emphasis on roaming and feeding. This term highlights the natural process of seeking sustenance, symbolizing provision and the freedom to nourish oneself.",
  "1119": "تُسْقِطَ and related words stem from the root س-ق-ط, with the root verb سَقَطَ meaning \"he fell.\" أَسْقَطَ means \"he caused to fall.\" تُسْقِطَ means \"you cause to fall\" or \"that it causes to fall.\" The connection lies in the act of making something fall, directly relating to the root's emphasis on descent. This term highlights the ability or action of bringing something down, whether physically or metaphorically, reflecting the influence one may have over events or outcomes.",
  "1120": "تُشْطِطْ and related words stem from the root ش-ط-ط, with the root verb شَطَّ meaning \"he exceeded proper bounds\" or \"he acted unjustly.\" تُشْطِطْ means \"you act unjustly\" or \"you deviate.\" The connection lies in the root's emphasis on excessiveness and deviation from justice. It serves as a warning against overstepping moral or ethical limits, urging adherence to fairness and moderation.",
  "1121": "تُشْمِتْ and related words stem from the root ش-م-ت, with the root verb شَمِتَ meaning \"he rejoiced at another's misfortune.\" تُشْمِتْ means \"you rejoice over (another's) misfortune.\" The connection lies in the root's concept of deriving pleasure from others' difficulties, specifically the act of taking satisfaction in another's hardship. تُشْمِتْ serves as a caution against actions that would allow adversaries or enemies to rejoice in one’s misfortune, emphasizing the importance of maintaining one's dignity and seeking refuge from situations that invite negative attention. The term suggests a moral stance, highlighting the harm in rejoicing over the suffering of others and the value of humility in adversity.",
  "1122": "تُصَاحِبُ and related words stem from the root ص-ح-ب, with the root verb صَحِبَ meaning \"he accompanied\" or \"he befriended.\" تُصَاحِبُ means \"you befriend\" or \"you associate with.\" This form implies mutual companionship and interaction. The connection lies in encouraging active engagement in forming relationships, reflecting the root's emphasis on companionship. It highlights the importance of building positive associations and fostering mutual support within a community.",
  "1123": "تُصَعِّرْ and related words stem from the root ص-ع-ر, with the root verb صَعَّرَ meaning \"he turned away arrogantly\" or \"he twisted.\" تُصَعِّرْ means \"turn your cheek arrogantly.\" The connection lies in the physical act of turning one's face away in pride. In the Qur'an, it admonishes against arrogance and disdainful behavior, emphasizing humility and respectful interaction with others. This term conveys the idea of showing contempt or superiority through dismissive actions, highlighting the importance of modesty and the rejection of pride in one’s interactions.",
  "1124": "تُصْعِدُونَ and related words stem from the root ص-ع-د, with the root verb صَعِدَ meaning \"he ascended\" or \"he climbed.\" تُصْعِدُونَ means \"you ascend\" or \"you climb uphill.\" The connection lies in moving upward, often with effort, emphasizing the action of rising or progressing, usually through a difficult or strenuous path. This term reflects both physical and metaphorical upward movement, symbolizing advancement or striving toward a higher state.",
  "1125": "تُضَيِّقُوا and related words stem from the root ض-ي-ق, with the root verb ضَاقَ meaning \"it became narrow\" or \"it was straitened.\" تُضَيِّقُوا means \"you restrict\" or \"you make narrow.\" The connection lies in actively causing someone or something to become confined or limited, directly reflecting the root's emphasis on constriction. This term highlights the act of imposing limitations or creating a sense of pressure, often in physical, social, or emotional contexts.",
  "1126": "تُعِزُّ and related words stem from the root ع-ز-ز, with the root verb عَزَّ meaning \"he was mighty,\" \"he was strong,\" or \"he was powerful.\" تُعِزُّ means \"You honor,\" \"You make mighty,\" often addressing Allah (ﷻ). The nuance here is causative, indicating the act of bestowing honor or might upon someone. This connects to the root's concept of strength and honor, emphasizing that true honor and might are granted by Allah (ﷻ) alone, highlighting His supreme authority in elevating whom He wills.",
  "1127": "تُغْمِضُوا and related words stem from the root غ-م-ض, with the root verb غَمَضَ meaning \"he closed his eyes,\" \"slept,\" or \"it was obscure.\" تُغْمِضُوا means \"you close (your eyes)\" or \"you overlook.\" The connection lies in the act of closing one's eyes, symbolizing overlooking or ignoring something undesirable. In the Qur'anic context, it refers to accepting something one would normally refuse, except by overlooking its faults. It emphasizes sincerity and quality in actions, particularly in charity, highlighting the need to avoid hypocrisy and uphold integrity.",
  "1128": "تُفَادُونَ and related words stem from the root ف-د-ي, with the root verb فَدَىٰ meaning \"he ransomed\" or \"he redeemed.\" تُفَادُونَ means \"you all ransom\" or \"you all redeem,\" referring to the act of offering something valuable, such as money or effort, to free or save someone. The term emphasizes themes of substitution and sacrifice, highlighting the willingness to endure a loss in order to protect or restore someone else, reflecting both literal and metaphorical applications of redemption and liberation.",
  "1129": "تُفَتَّحُ and related words stem from the root ف-ت-ح, with the root verb فَتَحَ meaning \"he opened.\" تُفَتَّحُ means \"they are opened,\" often referring to gates or doors. The connection lies in the act of opening being intensified and made accessible, reflecting the root's concept of opening wide. It emphasizes the readiness and welcoming nature of opportunities or blessings, such as the gates of Paradise being opened for the believers.",
  "1130": "تُفَنِّدُونِ and related words stem from the root ف-ن-د, with the root verb فَنِدَ meaning \"he became foolish\" or \"he became weak in mind.\" تُفَنِّدُونِ means \"you reproach\" or \"you accuse of folly,\" reflecting the act of attributing foolishness or error to someone. The root conveys themes of weakness in judgment or intellect, and تُفَنِّدُونِ emphasizes the act of criticizing, reproaching, or refuting someone by highlighting perceived flaws, errors, or lack of wisdom in their argument or behavior. This term emphasizes the active process of discrediting or challenging someone's reasoning.",
  "1131": "تُقَاةٌ and related words stem from the root و-ق-ي, with the root verb وَقَىٰ meaning \"he guarded,\" or \"he preserved.\" تُقَاةٌ means \"protection,\" or \"a means of guarding oneself.\" The root conveys themes of shielding, preserving, and taking preventative measures. تُقَاةٌ emphasizes the act of consciously avoiding harm or danger, particularly in moments of vulnerability or fear. This concept extends beyond physical safety to include moral and spiritual safeguarding, highlighting prudence, foresight, and the responsibility to ensure well-being through precautionary measures.",
  "1132": "تُقْسِطُوا and related words stem from the root ق-س-ط, with the root verb قَسَطَ meaning \"he was unjust.\" تُقْسِطُوا means \"you act justly\" or \"you establish justice,\" focusing on proactive efforts to maintain fairness and equity. This term emphasizes the responsibility to uphold justice consistently, reflecting deliberate and intentional actions to ensure balanced and equitable dealings. It highlights the importance of righteousness in human interactions, urging vigilance in promoting fairness and the active establishment of justice in all areas of life.",
  "1133": "تُقْلَبُونَ and related words stem from the root ق-ل-ب, with the root verb قَلَبَ meaning \"he turned over,\" \"he inverted,\" or \"he changed.\" تُقْلَبُونَ is a passive form meaning \"you are turned\" or \"you are returned.\" It emphasizes the inevitability of being brought back or directed to a final destination. The root’s focus on reversal and transformation reflects the certainty of returning to a point of reckoning or accountability, highlighting the transient nature of life and the inevitability of facing the consequences of one’s actions.",
  "1134": "تُكْوَىٰ and related words stem from the root ك-و-ي, with the root verb كَوَىٰ meaning \"he branded with fire,\" \"he scorched,\" or \"he seared.\" تُكْوَىٰ is the passive form, meaning \"it is branded\" or \"it is scorched,\" reflecting an externally inflicted action with lasting consequences. The root conveys the act of applying intense heat to leave a permanent mark, often associated with punishment, ownership, or identification. It also implies deliberate confrontation or the imposition of an action with enduring effects, emphasizing the severity and permanence of the result. This term highlights branding or burning as a method of delivering justice or consequence, highlighting its symbolic and physical irreversibility.",
  "1135": "تُمَارِ and related words stem from the root م-ر-ي, with the root verb مَارَىٰ meaning \"he disputed\" or \"he doubted.\" تُمَارِ means \"you dispute\" or \"you argue.\" The word emphasizes engaging in a challenge or debate with someone, reflecting the root's connection to doubt and contention. It highlights the dynamic and interpersonal nature of questioning or confronting ideas, illustrating the root’s focus on testing or examining beliefs through argument.",
  "1136": "تُمْسُونَ and related words stem from the root م-س-ى, with the root verb أَمْسَىٰ meaning \"he entered the evening.\" تُمْسُونَ means \"you enter the evening\" or \"you reach evening.\" The connection lies in the transition from day to night, reflecting the root's concept of moving into the evening period. This emphasizes the passage of time and the cyclical nature of daily life.",
  "1137": "تُنْكِحُوا and related words stem from the root ن-ك-ح, with the root verb نَكَحَ meaning \"he married\" or \"he entered into a marriage contract.\" تُنْكِحُوا means \"you give in marriage\" or \"you arrange for marriage,\" referring to the act of facilitating or granting permission for someone to marry. The root conveys themes of union, bond, and the establishment of formal relationships. This term emphasizes the responsibility of guardians or others in authority to ensure marriage is conducted lawfully and ethically, reflecting the root’s focus on fostering legitimate relationships and social harmony.",
  "1138": "تُورُونَ and related words stem from the root و-ر-ي, with the root verb أَوْرَى meaning \"he kindled,\" \"he ignited,\" or \"he caused to burn.\" تُورُونَ means \"you kindle\" or \"you produce fire,\" referring to the act of generating flames or heat. The root conveys the idea of bringing forth something hidden, as kindling fire involves drawing it out from a concealed source, such as sparks from flint. This term emphasizes the transformative process of creating energy or illumination, connecting to the broader theme of uncovering or producing something latent.",
  "1139": "تُوعِدُ and related words stem from the root و-ع-د, with the root verb وَعَدَ meaning \"he promised.\" أَوْعَدَ means \"he threatened.\" تُوعِدُ means \"you threaten\" or \"she threatens.\" The connection is that a threat is a form of promise with negative implications, emphasizing the seriousness and certainty of consequences. This reflects the root's focus on the power of words and the responsibility that comes with making declarations, whether positive or negative.",
  "1140": "تُوَقِّرُوا and related words stem from the root و-ق-ر, with the root verb وَقَرَ meaning \"he was dignified, steady, and reliable.\" وَقَّرَ means \"he treated him with honor, reverence, veneration, or respect,\" and تُوَقِّرُوا translates as \"you all respect.\" The connection lies in demonstrating profound respect and reverence, embodying the root's emphasis on dignity and weightiness. This term highlights the importance of showing honor to those deserving of respect, such as elders, scholars, and the Prophet (ﷺ), fostering humility and a culture of esteem.",
  "1141": "تِبْيَانٌ and related words stem from the root ب-ي-ن, with the root verb بَانَ meaning \"it became separated, severed, disunited, or cut off,\" or \"it became apparent, manifest, evident, or clear\" or \"it became distinct,\" implying separation from others. تِبْيَانٌ means \"clarification,\" referring to the act of making something thoroughly clear or providing a detailed explanation. The root conveys a sense of separating truth from falsehood or illuminating something hidden, emphasizing clarity and precision in understanding. تِبْيَانٌ captures the idea of an explanation that removes all ambiguity, making things unmistakably clear.",
  "1142": "تِجارَةٌ and related words stem from the root ت-ج-ر, with the root verb تَجَرَ meaning \"he traded\" or \"he engaged in commerce.\" تِجارَةٌ means \"trade\" or \"commerce,\" encompassing the activity of exchanging goods and services. The root also carries broader connotations of movement and flow, as trade involves the continuous flow of goods and wealth. This term reflects the root’s emphasis on interaction, mutual benefit, and the balance between gain and loss.",
  "1143": "تِسْعٌ and related words stem from the root ت-س-ع, with the root verb تَسَعَ meaning \"it became nine.\" تِسْعٌ represents the number nine.",
  "1144": "تِسْعَةٌ and related words stem from the root ت-س-ع, with the root verb تَسَعَ meaning \"it became nine.\" تِسْعَةٌ is the feminine form meaning \"nine.\"",
  "1145": "تِلَاوَةٌ and related words stem from the root ت-ل-و, with the root verb تَلَا meaning \"he recited\" or \"he followed.\" تِلَاوَةٌ specifically means \"recitation\" and refers to the act of reciting the Qur'an. This term connects directly to the root, where تَلَا implies vocalizing words while following and adhering to the guidance within them. The root also conveys continuity, making تِلَاوَةٌ an ongoing engagement with the Qur'an, embodying both recitation and a continuous effort to live by its teachings.",
  "1146": "تِلْقاءَ and related words stem from the root ل-ق-ي, with the root verb لَقِيَ meaning \"he met,\" \"he encountered,\" or \"he found.\" This root reflects the concept of meeting or coming face to face. تِلْقاءَ translates as \"towards\" or \"in the direction of,\" emphasizing movement or orientation toward something, aligning with the root's focus on the act of coming into contact or proximity. It can also refer to one's own \"accord,\" stemming from the intentionality inherent in the root—meeting or encountering often involves deliberate effort or initiative. Both meanings connect to the root's emphasis on purposeful engagement, whether through spatial direction or self-motivated action.",
  "1147": "تِينٌ stems from the root ت-ي-ن, referring to \"figs,\" a fruit renowned for its nourishment and natural sweetness. In the Qur'an, Allah (ﷻ) swears by the fig and the olive, emphasizing their importance as symbols of blessings and abundance. Figs are valued not only for their nutritional benefits and health-promoting qualities but also as a representation of divine provision and the richness of creation. This connection highlights their role as a reminder of Allah's (ﷻ) care and the sustenance provided for His creation, emphasizing their purity and inherent goodness.",
  "1148": "ثَابِتٌ and related words stem from the root ث-ب-ت, with the root verb ثَبَتَ meaning \"he remained firm,\" \"endured,\" or \"continued.\" ثَابِتٌ means \"firm\" or \"steadfast,\" describing a person or thing that is stable, unshakable, and grounded. The root conveys a sense of unwavering strength and resilience, suggesting that true firmness and stability arise from a foundation of endurance and persistence.",
  "1149": "ثَاقِبٌ and related words stem from the root ث-ق-ب, with the root verb ثَقَبَ meaning \"he pierced\" or \"he penetrated.\" ثَاقِبٌ refers to a star, lamp, fire, flame, or shooting star \"shining brightly, or glistening, as though piercing through the darkness, and dispelling it.\" It embodies the quality of piercing or shining brightly, directly tied to the root's meaning. Often describing a shining star or penetrating intellect, it symbolizes clarity, insight, or brilliance cutting through darkness or ignorance.",
  "1150": "ثَالِثٌ and related words stem from the root ث-ل-ث, meaning \"third.\" It signifies the position of being third in order, directly connected to the root's numerical meaning. This term is used to denote sequence or ranking in various contexts.",
  "1151": "ثَالِثَةٌ and related words stem from the root ث-ل-ث, meaning \"third\". It is the feminine form used to refer to feminine nouns or entities in the third position.",
  "1152": "ثَامِنٌ and related words stem from the root ث-م-ن, meaning \"eighth.\" It refers to the position of being eighth in a sequence and is used to indicate order or rank in numerical arrangements.",
  "1153": "ثَانِيَ and related words stem from the root ث-ن-ي, with the root verb ثَنَىٰ meaning \"he doubled,\" \"he folded,\" or \"he bent.\" ثَانِيَ means \"second,\" signifying the position of being second in order, directly tied to the root's sense of doubling or following. The word can also describe an act of bending or folding, as in \"bending the neck\" or \"folding the side,\" which is expressed as turning. This usage metaphorically conveys an attitude of arrogance or rejection, where turning the neck or side symbolizes disdain or disregard through a deliberate, dismissive gesture.",
  "1154": "ثَاوِيٌ and related words stem from the root ث-و-ي, with the root verb ثَوَى meaning \"he remained,\" \"he dwelled,\" or \"he stayed in place.\" ثَاوِيٌ means \"one who dwells\" or \"resident,\" emphasizing a sense of permanence or settled presence. The root conveys the concept of remaining in a state or location, often implying attachment or belonging. This term reflects the idea of being firmly rooted or established in a particular place, connecting physical residence to stability and continuity.",
  "1155": "ثَبَّتْنَا and related words stem from the root ث-ب-ت, with the root verb ثَبَتَ meaning \"he remained firm,\" \"endured,\" or \"continued.\" ثَبَّتْنَا means \"we made firm\" or \"we strengthened,\" emphasizing the act of reinforcing or solidifying something to ensure stability. The root suggests that strengthening involves establishing a firm foundation, often in the face of challenges, to maintain resilience and unwavering resolve.",
  "1156": "ثَبَّطَ and related words stem from the root ث-ب-ط, with the root verb ثَبِطَ meaning \"he was or became heavy, sluggish, slow, or weak.\" ثَبَّطَ means \"he hindered, withheld, or prevented,\" involving an active effort to cause someone to hesitate or hold back. This word builds on the root's sense of sluggishness and weakness, implying that hindering someone is akin to weighing them down, often by inducing fear, doubt, or reluctance, making them resistant to progress or action.",
  "1157": "ثَجَّاجٌ and related words stem from the root ث-ج-ج, with the root verb ثَجَّ meaning \"it flowed\" or \"it poured forth abundantly.\" ثَجَّاجٌ is an intensive form meaning \"pouring abundantly\" or \"gushing profusely.\" This word vividly conveys the image of something flowing in copious, powerful streams, often symbolizing overwhelming generosity or blessings. The root encompasses the concept of boundless flow and continuity, frequently describing heavy rainfall, streams, or the outpouring of divine favors.",
  "1158": "ثَرًى and related words stem from the root ث-ر-ى, with the root verb ثَرِيَ meaning \"it became moist and soft, after drought and dryness.\" ثَرًى means \"moist earth\" or \"rich soil.\" The word captures the idea of fertile ground, stemming from the root's association with moisture and abundance. It symbolizes growth, sustenance, and the nurturing aspects of the earth that support life.",
  "1159": "أَثْقَالٌ and related words stem from the root ث-ق-ل, with the root verb ثَقُلَ meaning \"it was heavy, weighty, burdensome.\" أَثْقَالٌ means \"burdens\" or \"loads,\" representing something heavy that is carried, directly tied to the root's meaning of weight and gravity. This term applies to both physical loads, such as material objects, and metaphorical burdens, including responsibilities, obligations, or moral weights. The word highlights the effort required to bear these burdens, symbolizing the impact of heaviness in tangible and intangible forms, often reflecting the trials or duties of life.",
  "1160": "ثَقُلَتْ and related words stem from the root ث-ق-ل, with the root verb ثَقُلَ meaning \"it was heavy, weighty, burdensome.\" ثَقُلَتْ is the feminine form, and it denotes a state of becoming weighty or burdensome, directly tied to the root's sense of heaviness and gravity. This term can apply to physical weight, the heaviness of deeds, or the gravity of situations, symbolizing the profound impact, significance, or consequence of what is described. Rooted in the idea of substantiality, ثَقُلَتْ reflects the weightiness of matters that demand attention or bear serious implications.",
  "1161": "ثَقِيلٌ and related words stem from the root ث-ق-ل, with the root verb ثَقُلَ meaning \"it was heavy, weighty, or burdensome.\" ثَقِيلٌ means \"heavy\" or \"weighty,\" describing something with substantial physical weight or metaphorical importance. The root conveys the idea of density, gravity, or seriousness, often symbolizing something that requires effort to bear. ثَقِيلٌ can refer to physical objects, significant responsibilities, profound words, or even burdensome situations, all emphasizing the substantial impact or seriousness tied to the root's essence.",
  "1162": "ثَلَاثٌ and related words stem from the root ث-ل-ث, and represents the number three in Arabic.",
  "1163": "ثَلَاثٌ and related words stem from the root ث-ل-ث, and represents the number three in Arabic.",
  "1164": "ثَمَانِيَ and related words stem from the root ث-م-ن, representing the number eight in Arabic.",
  "1165": "ثَمَانِينَ and related words stem from the root ث-م-ن, meaning \"eighty.\" It is used to represent the number eighty, whether counting objects or indicating something in a sequence, like a position or rank.",
  "1166": "ثَمَانِيَةٌ and related words stem from the root ث-م-ن, representing the number eight in Arabic.",
  "1167": "ثَمَرٌ and related words stem from the root ث-م-ر, with the root verb ثَمَرَ meaning \"it became ripe\" or \"it became abundant,\" and أَثْمَرَ meaning \"it bore fruit\" or \"it began to yield its produce,\" signifying the act of generating results or benefits. ثَمَرٌ means \"fruit\" or \"produce,\" referring to the yield of trees or plants, directly tied to the root's agricultural meaning. Beyond its literal sense, ثَمَرٌ also metaphorically represents the outcomes, benefits, or results of one’s efforts. The term reflects the idea of growth, nourishment, and productivity, symbolizing the rewards or tangible results of dedication and cultivation, whether in agriculture or in life’s endeavors.",
  "1168": "ثَمَرَةٌ and related words stem from the root ث-م-ر, with the root verb ثَمَرَ meaning \"it became ripe\" or \"it became abundant,\" and أَثْمَرَ meaning \"it bore fruit\" or \"it began to yield its produce,\" signifying the act of generating results or benefits.\" ثَمَرَةٌ is the singular form of ثَمَرٌ, meaning \"fruit.\" It refers to an individual unit of produce, directly tied to the root’s agricultural origins. Beyond its literal meaning, ثَمَرَةٌ can symbolize a singular result, reward, or benefit stemming from effort or cultivation.",
  "1169": "ثَمَنٌ and related words stem from the root ث-م-ن, with the root verb ثَمُنَ meaning \"it was costly\" or \"it was precious.\" ثَمَنٌ means \"price\" or \"cost,\" representing the value or worth of something, directly tied to the root's focus on importance and exchange. Beyond its commercial use in denoting the monetary worth of goods or services, ثَمَنٌ can metaphorically signify the sacrifices or efforts required to achieve something valuable. The term highlights the broader concept of worth—whether material, moral, or symbolic—emphasizing the relationship between value and effort.",
  "1170": "ثَمُودُ and related words stem from the root ث-م-د, with the root verb ثَمَدَ meaning \"he pierced\" or \"he dug for water.\" ثَمُودُ refers to the ancient Arab tribe Thamud, known for residing in Al-Hijr and carving homes out of mountains. The connection lies in their ingenuity in extracting resources from hard stone, reflecting their ability to pierce through and shape rock, embodying the root's themes of piercing and resourcefulness.",
  "1171": "The particle ثَمَّ means \"there\" and is used to point to a place that is far or distant from the speaker. Both هُنَالِكَ and ثَمَّ are used to show distance, but هُنَالِكَ usually suggests a greater sense of being far away or separated, often referring to a specific place. On the other hand, ثَمَّ is often used in a more poetic or elegant way, especially in the Qur'an. It can hint at not just physical distance, but also a deeper, sometimes symbolic meaning, adding richness to the verse.",
  "1172": "ثَوَابٌ and related words stem from the root ث-و-ب, with the root verb ثَابَ meaning \"he returned,\" \"he went back,\" or \"he came back to a place or state.\" ثَوَابٌ means \"reward,\" signifying recompense or return for good deeds, directly tied to the root's core idea of returning. Unlike مَثُوبَةٌ, which emphasizes a deserved or specific recompense, ثَوَابٌ often conveys the sense of an enduring or ultimate reward, reflecting Allah's (ﷻ) generosity and the perpetual nature of recompense for righteous actions. This highlights the balance of justice and grace in the concept of rewards, particularly, emphasizing the return of goodness as a lasting acknowledgment of one's efforts.",
  "1173": "ثَيِّبَاتٌ and related words stem from the root ث-ي-ب, with the root verb ثَابَ meaning \"he returned.\" ثَيِّبَاتٌ means \"women who have become separated from their husbands\" or \"divorced women,\" describing a woman who has returned to her family or original state after marriage. The connection to the root highlights the concept of returning, emphasizing the transition from marriage back to a prior state, whether familial or societal. This term reflects both a literal and social return, capturing the root's essence of restoration or coming back to a former condition.",
  "1174": "ثُبَاتٌ and related words stem from the root ث-ب-ى, with the root verb ثبّى meaning \"putting something in a good, sound state,\" \"completing or augmenting something,\" or \"preserving, guarding, or taking care of.\" ثُبَاتٌ means \"groups of men.\" The connection to the root meanings lies in the idea of a group being held together, organized, and safeguarded, reflecting how the root verb denotes putting something in a sound or preserved state.",
  "1175": "ثُبُوتٌ and related words stem from the root ث-ب-ت, with the root verb ثَبَتَ meaning \"he remained firm,\" \"endured,\" or \"continued.\" ثُبُوتٌ means \"firmness\" or \"stability,\" describing an active state of being established, proven, and unyielding. The root conveys resilience and unwavering strength, particularly through challenges, where ثُبُوتٌ represents a foundational certainty that withstands external pressures. This word emphasizes that true stability and inner strength come from conviction, illustrating how deeply rooted beliefs remain steadfast and immovable.",
  "1176": "ثُبُورٌ and related words stem from the root ث-ب-ر, with the root verb ثَبَرَ meaning \"he confined, restrained, withheld, hindered, or prevented,\" or \"he expelled,\" or \"he destroyed.\" This root conveys overarching themes of severance, prevention, and harm. In its usage, ثُبُورٌ refers to \"destruction\" or \"perdition,\" conveying devastating ruin. The connection to the root lies in hindering existence or severing continuity, where destruction is the ultimate act of breaking. This term vividly portrays profound despair and the invocation of destruction upon oneself, often out of overwhelming regret or suffering, emphasizing the finality of ruin in physical and emotional realms.",
  "1177": "ثُعْبَانٌ and related words stem from the root ث-ع-ب, with the root verb ثَعَبَ meaning \"it gushed forth\" or \"it flowed.\" ثُعْبَانٌ means \"a serpent.\" The connection lies in the serpent's sinuous, flowing movement resembling a stream's flow, directly relating to the root's meaning. This term may also symbolize stealth or danger, drawing on the imagery of a snake's fluid motion and elusive nature.",
  "1178": "ثُقِفُوا and related words stem from the root ث-ق-ف, with the root verb ثَقِفَ meaning \"he became skilled, quick, or sharp; intelligent,\" or \"he skillfully found, overtook, or gained victory.\" ثُقِفُوا is a passive form meaning \"they were overtaken\" or \"they were overcome,\" reflecting the idea of being subdued or dominated with precision and inevitability. This connects to the root's emphasis on proficiency and dexterity, particularly in overcoming or overpowering.",
  "1179": "ثُلَاثٌ and related words stem from the root ث-ل-ث, meaning \"threefold\" or \"in groups of three.\" It is used to describe something occurring in threes, referring to patterns, structures, or repetitions involving the number three.",
  "1180": "ثُلُثٌ and related words stem from the root ث-ل-ث, meaning \"one-third.\" It denotes a fraction representing one part of three equal parts, and is used in mathematical, legal, or inheritance contexts to specify portions.",
  "1181": "ثُلَّةٌ and related words stem from the root ث-ل-ل, with the root verb ثَلَّ meaning \"he broke, demolished, or destroyed,\" signifying actions involving separation or fragmentation. ثُلَّةٌ refers to a \"group\" or \"company\" of people, particularly a distinguished or selected group. The connection to the root lies in the idea of separating individuals from the larger whole to form a distinct group, emphasizing their unique selection or unity within the collective. This term conveys the notion of an organized assembly, highlighting the interconnectedness and shared purpose of those within the group.",
  "1182": "ثُمُنٌ and related words stem from the root ث-م-ن, meaning \"one-eighth.\" ثُمُنٌ refers to a fractional part, specifically one of eight equal divisions of a whole. This term emphasizes the idea of equitable distribution and precise measurement, often used in contexts like inheritance or portions in Islamic law.",
  "1183": "ثُوِّبَ and related words stem from the root ث-و-ب, with the root verb ثَابَ meaning \"he returned,\" \"he went back,\" or \"he came back to a place or state.\" ثُوِّبَ, as a passive form, means \"he was rewarded\" or \"he was recompensed,\" signifying the act of receiving something in return for deeds or actions. The connection to the root lies in the idea of a return or restoration, where the reward or recompense is seen as something cycling back to the individual as a direct consequence of their efforts. This reflects the root's overarching theme of reciprocation and the inherent balance in the concept of returning or restoring what is due.",
  "1184": "ثِيَابٌ and related words stem from the root ث-و-ب, with the root verb ثَابَ meaning \"he returned,\" \"he went back,\" or \"he came back to a place or state.\" ثِيَابٌ means \"garments\" or \"clothes,\" directly tied to the root's sense of returning, as garments are items one continually returns to for covering, protection, or adornment. This connection emphasizes the root’s idea of renewal and restoration, as clothing restores a person's dignity, identity, and sense of propriety. The term also highlights preparation, as garments prepare and equip an individual to face various circumstances, symbolizing a return to a state of completeness or readiness.",
  "1185": "جَاءَ and related words stem from the root ج-ي-أ, with the root verb جَاءَ meaning \"he came\" or \"he arrived.\" The root broadly conveys meanings of coming, arrival, bringing, and movement toward a destination or purpose. The connection is direct, emphasizing motion, fulfillment, or the realization of an event. This term reflects purposeful arrival, often symbolizing the completion of a journey or the unfolding of significant outcomes.",
  "1186": "جَائِرٌ and related words stem from the root ج-و-ر, with the root verb جَارَ meaning \"he declined or deviated from the right course\" or \"he acted unjustly.\" The root broadly encompasses meanings of deviation, straying from the correct path, and acting unfairly. جَائِرٌ means \"deviating,\" \"unjust,\" or \"oppressive,\" referring to someone or something that departs from the correct path or from justice and fairness.",
  "1187": "جَابُوا and related words stem from the root ج-و-ب, with the root verb جَابَ meaning \"he cut through\" or \"he hollowed out.\" جَابُوا means \"they carved out,\" referring to the act of hollowing or piercing through something, such as stone, often with precision and effort. The root conveys themes of cutting, hollowing, and shaping physical objects. This connection highlights the deliberate effort and skill involved in transforming and shaping materials.",
  "1188": "جَاثِمِينَ and related words stem from the root ج-ث-م, with the root verb جَثَمَ meaning \"he clave to the ground\" or \"he fell upon his chest.\" جَاثِمِينَ describes people \"lying face down\" or \"cleaving to the ground,\" emphasizing a state of immobility, helplessness, or submission. The broader root concepts reflect an image of stillness and being pinned or pressed to the earth, often connoting fear, despair, or finality. This connection highlights the overwhelming nature of situations that render one powerless, symbolizing complete surrender or stagnation.",
  "1189": "جَاثِيَةٌ and related words stem from the root ج-ث-و, with the root verb جَثَا meaning \"he knelt down.\" جَاثِيَةٌ means \"kneeling\" or \"a kneeling group,\" depicting individuals or groups in a posture of kneeling. The root reflects a position of stillness and submission, often associated with reverence, anticipation, or helplessness. This connection emphasizes the act of kneeling as a state of waiting or subjugation, capturing both physical posture and emotional undertones tied to humility or apprehension.",
  "1190": "جَادَلُوا and related words stem from the root ج-د-ل, with the root verb جَدَلَ meaning \"it was hard and strong,\" and جَدِلَ meaning \"he disputed, or litigated, vehemently, or violently.\" جَادَلُوا means \"they argued\" or \"they disputed,\" emphasizing active engagement in debate or contention. The root carries the sense of structured, often intense discussion or reasoning, which can aim to convince, refute, or challenge. It reflects the idea of mental or verbal effort to assert a position, tying جَادَلُوا to the broader concept of argumentation as an interaction requiring skill and determination.",
  "1191": "جَارٌ and related words stem from the root ج-و-ر, with the verb جَارَ meaning \"he deviated\" or \"he inclined from the right course,\" and جاوَرَ meaning \"he became a neighbor.\" The root broadly conveys meanings of deviation, proximity, relationship, and granting protection. جَارٌ means \"neighbor,\" emphasizing closeness and shared rights and responsibilities. This term highlights the importance of fostering good relations, mutual support, and a strong sense of community among neighbors. The root also serves as a reminder that neighbors, while being close in proximity, have a duty to protect and guide one another, reflecting the moral and social bonds that uphold communal harmony.",
  "1192": "جارِيَةٌ and related words stem from the root ج-ر-ي, with the root verb جَرَىٰ meaning \"it flowed,\" \"it ran,\" or \"it passed along qickly.\" جارِيَةٌ means \"ship,\" highlighting its movement or running upon the sea. The root conveys themes of motion, continuity, and activity, with the ship symbolizing something that glides or flows smoothly over water. This connection emphasizes the dynamism and grace of movement inherent in the root, tying the ship's function to the broader concept of flowing or running.",
  "1193": "جَازٍ and related words stem from the root ج-ز-ي, with the root verb جَزَى meaning \"he recompensed\" or \"he rewarded.\" جَازٍ means \"one who can compensate\" or \"one who can requite,\" emphasizing the ability to repay or make amends. The root reflects themes of balance and justice, where actions are met with their due recompense. جَازٍ highlights the idea of accountability, emphasizing that no one can recompense or intervene for another in the ultimate reckoning.",
  "1194": "جَاسُوا and related words stem from the root ج-و-س, with the root verb جَاسَ meaning \"he sought after.\" The root broadly conveys meanings of searching, exploring, or intruding, often with intensity or suddenness. جَاسُوا means \"they prowled\" or \"they ransacked,\" describing the act of moving through the midst of houses, searching or attacking in a sudden and forceful manner. This term reflects deliberate movement through an area with the intent to uncover or seize, often with a destructive or invasive connotation. It conveys physical intrusion and the idea of purposefully seeking and disrupting, highlighting themes of exploration with aggression or urgency.",
  "1195": "جَاعِلٌ and related words stem from the root ج-ع-ل, with the root verb جَعَلَ meaning \"he made,\" encompassing contexts of creating, preparing, appointing, altering a state or condition, pronouncing a judgment, or transforming something. جَاعِلٌ means \"maker\" or \"one who assigns,\" emphasizing the act of creating, designating, or causing something to take a particular state. The root conveys themes of purposeful transformation, causation, and assignment, reflecting deliberate actions that bring about order, function, or change. جَاعِلٌ embodies the active role of shaping or defining roles and outcomes.",
  "1196": "جَالُوتُ is the Arabic name for Goliath, the giant warrior defeated by Prophet David (ﷺ). The name is of Hebrew origin but does not have a clear, established root or meaning. Goliath represents formidable opposition, arrogance, and brute strength. His defeat by Prophet David (ﷺ) symbolizes the triumph of faith, righteousness, and divine support over seemingly insurmountable odds. This story serves as a reminder that true strength lies in faith, and that victory belongs to the righteous, even in the face of overwhelming adversity.",
  "1197": "جَامِدَةٌ and related words stem from the root ج-م-د, with the root verb جَمَدَ meaning \"it froze,\" \"it became solid,\" or \"it stiffened.\" The root broadly conveys meanings of hardness, rigidity, and lack of motion, extending to concepts of being unyielding or stagnant. جَامِدَةٌ refers to \"solid,\" \"motionless,\" or \"stagnant,\" describing a state characterized by immobility, inflexibility, or the absence of vitality. The connection lies in the transition from fluidity or motion to a fixed, hardened state, reflecting themes of stillness, rigidity, and an inability to adapt or flow.",
  "1198": "جَامِعٌ and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered.\" The root conveys broad meanings of collecting, uniting, assembling, and bringing together disparate elements into a cohesive whole. جَامِعٌ means \"gathering\" or \"meeting,\" signifying a source that unites various elements. In the Qur'an, it reflects Allah’s (ﷻ) gathering of creation on the Day of Judgment, highlighting the ultimate assembly. ٱلْجَامِعُ, one of Allah’s (ﷻ) perfect names, means \"The Gatherer,\" emphasizing His power to unite all things—people, events, or outcomes—according to His will. This name reflects the root’s theme of unity and coherence, demonstrating Allah’s (ﷻ) majesty over creation.",
  "1199": "جانِبٌ and related words stem from the root ج-ن-ب, with the root verb جَنَبَ meaning \"he placed at a distance, sent away, or turned aside.\" جانب means \"he was by his side,\" and جانِبٌ means \"side\" or \"aspect,\" referring to a position or perspective relative to something else. The connection lies in the concept of separation or positioning, as جانِبٌ represents the periphery or flank, reflecting the act of being apart or situated differently. This emphasizes the importance of understanding perspectives, boundaries, and considering different dimensions or facets of a situation.",
  "1200": "جَانٌّ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he covered,\" \"he concealed\" or \"he hid.\" جَانٌّ refers to an individual jinn, highlighting their nature as beings hidden from human perception and their creation from smokeless fire. The term also denotes a \"serpent,\" symbolizing their swift, elusive, and sometimes fear-inducing characteristics. The root embodies concepts of hiddenness, veiling, and invisibility, aligning with the jinn’s nature as unseen entities possessing unique abilities and strength, while remaining concealed within the unseen realm.",
  "1201": "جَاهَدَ and related words stem from the root ج-ه-د, with the root verb جَهَدَ meaning \"he exerted effort.\" جَاهَدَ means \"he strove\" or \"he exerted his utmost effort.\" The connection lies in the act of engaging in a deliberate and effortful struggle to achieve a noble goal, reflecting themes of dedication, perseverance, and steadfastness in overcoming challenges in the pursuit of righteousness.",
  "1202": "جَاهِلٌ and related words stem from the root ج-ه-ل, with the root verb جَهِلَ meaning \"he was ignorant.\" The root broadly conveys meanings of ignorance, lack of knowledge, foolishness, and acting without understanding. جَاهِلٌ means \"ignorant person,\" directly referring to someone lacking knowledge or awareness. This term emphasizes the importance of seeking knowledge, understanding, and wisdom while warning of the pitfalls and harm of acting without proper understanding.",
  "1203": "جَاهِلِيَّةٌ and related words stem from the root ج-ه-ل, with the root verb جَهِلَ meaning \"he was ignorant.\" The root encompasses broader meanings of ignorance, foolishness, and a lack of guidance. جَاهِلِيَّةٌ means \"age of ignorance,\" specifically referring to the period before the mission of the Prophet Muhammad (ﷺ). The connection lies in the widespread ignorance of Allah’s (ﷻ) guidance during that era. This term highlights the transformative power of knowledge and revelation in replacing ignorance with enlightenment and moral clarity.",
  "1204": "جَاوَزَ and related words stem from the root ج-و-ز, with the root verb جَازَ meaning \"he passed over\" or \"he crossed.\" The root broadly conveys meanings of crossing, transitioning, surpassing, and moving beyond boundaries. جَاوَزَ means \"he exceeded,\" or \"he transgressed,\" emphasizing the act of moving beyond limits or boundaries, whether physical, moral, or metaphorical. This term reflects the idea of actively going further than what is typical, expected, or allowed, connecting to themes of growth, ambition, and, in some cases, transgression.",
  "1205": "جَبَلٌ and related words stem from the root ج-ب-ل, with the root verb جَبَلَ meaning \"He (Allah (ﷻ)) created,\" specifically \"He created with an adaptation or disposition,\" emphasizing the act of molding or shaping for a purpose. جَبَلٌ means \"mountain,\" reflecting this root idea of being formed by Allah (ﷻ), symbolizing grandeur, stability, and permanence. The root also conveys meanings of generations and multitudes, highlighting that mountains exist in great numbers and endure through successive generations, standing as timeless witnesses and profound evidence of Allah’s (ﷻ) majestic power.",
  "1206": "جَبِينٌ and related words stem from the root ج-ب-ن, with the root verb جَبُنَ meaning \"he was cowardly\" or \"he was weak-hearted.\" جَبِينٌ means \"forehead.\" Remarkably, the prefrontal cortex, located behind the forehead, plays a role in managing fear responses linked to cowardice by interacting with other brain regions. Even more profound is that the forehead, used in prostration during prayer, symbolizes submission to Allah (ﷻ), through which believers are strengthened, becoming more steadfast in their faith and worldly affairs.",
  "1207": "جَبَّارٌ and related words stem from the root ج-ب-ر, with the root verb جَبَرَ meaning \"he compelled or constrained,\" or \"he restored to a sound, right, or good, state.\" جَبَّارٌ, is an intensive form meaning \"tyrant\" in the human context, describing someone who forcefully compels others and oversteps bounds. الْجَبَّارُ, is one of Allah's (ﷻ) perfect names, meaning \"The Compeller and Restorer,\" reflecting His authority to enforce His will and mend what is broken with justice and mercy. The root highlights both compulsion and restoration, reminding us that human arrogance contrasts with Allah’s (ﷻ) supreme and just control over all creation.",
  "1208": "جَحَدُوا and related words stem from the root ج-ح-د, with the root verb جَحَدَ meaning \"he denied\" or \"he rejected.\" جَحَدُوا means \"they denied\" or \"they disacknowledged,\" emphasizing a willful refusal to acknowledge or accept something known to be true. The root reflects deliberate negation or rejection, often in defiance of evidence or clear understanding. This connection highlights the act of disavowal as a conscious and intentional repudiation.",
  "1209": "جَحِيمٌ and related words stem from the root ج-ح-م, with the root verb جَحَمَ meaning \"it blazed intensely\" or \"it burned fiercely.\" The root carries the sense of extreme heat, ferocity, and unrelenting intensity, often associated with overwhelming or consuming fire. جَحِيمٌ refers to \"a blazing fire\" and الْجَحِيمُ specifically refers to \"Hellfire,\" emphasizing the terrifying and all-encompassing nature of such flames. The connection to the root highlights the severity and enduring nature of this fire, symbolizing punishment or destruction that is both intense and inescapable.",
  "1210": "جَدَلٌ and related words stem from the root ج-د-ل, with the root verb جَدَلَ meaning \"it was hard and strong,\" and جَدِلَ meaning \"he disputed, or litigated, vehemently, or violently.\" جَدَلٌ means \"argument\" or \"dispute,\" emphasizing the process of reasoning or contending over a matter. The root conveys structured contention, often involving skill or persistence in asserting a position. جَدَلٌ reflects this by highlighting the verbal or intellectual effort inherent in debate or dispute.",
  "1211": "جَدِيدٌ and related words stem from the root ج-د-د, with the root verb جَدَّ meaning \"he cut\" or \"he cut off,\" \"he was fortunate,\" or \"it was new\" or \"renewed.\" جَدِيدٌ means \"new\" or \"fresh,\" emphasizing renewal and the emergence of something novel. The root conveys the idea that creating something new often involves cutting away the old, symbolizing a fresh start or transformation. This can be likened to pruning a tree to encourage new growth, connecting the root’s meanings to regeneration, vitality, and the continuous cycle of renewal.",
  "1212": "جَدٌّ and related words stem from the root ج-د-د, with the root verb جَدَّ meaning \"he became possessed of good fortune, wealth, or sufficiency,\" or \"he was of great dignity in the eyes of men.\" جَدٌّ signifies worldly fortune or dignity for humans but, when referring to Allah (ﷻ), it exclusively denotes \"Majesty.\" This root highlights the connection between human attainment of fortune and dignity and the ultimate source—Allah’s (ﷻ) unparalleled greatness and majesty. It emphasizes His supreme authority, reminding that all worldly honor and fortune are entirely dependent on His will and decree.",
  "1213": "جَذْوَةٌ and related words stem from the root ج-ذ-و, with the root verb جَذَا meaning \"it stood firmly\" or \"it was erect or straight.\" جَذْوَةٌ refers to \"an ember\" or \"a live coal,\" specifically a glowing piece capable of igniting fire. It also refers to a thick piece of wood with fire at one end. The root’s meaning of standing firmly connects to the ember’s function as a steadfast and concentrated source of heat, retaining the potential to ignite flames. This connection highlights the ember’s role as both a fragment of fire and a tool for generating new flames, symbolizing enduring energy, stability, and transformative power inherent in its glowing core.",
  "1214": "جَرَادٌ and related words stem from the root ج-ر-د, with the root verb جَرَدَ meaning \"it stripped\" or \"it made bare,\" specifically referring to locusts stripping the land of its herbage or produce. جَرَادٌ means \"locusts,\" highlighting their behavior of stripping vegetation and leaving the land bare. The root reflects themes of removal and exposure, directly connecting to the destructive nature of locusts as they consume crops and vegetation, leaving behind barren landscapes.",
  "1215": "جَرَحْتُمْ and related words stem from the root ج-ر-ح, with the root verb جَرَحَ meaning \"he wounded\" or \"he acquired or earned.\" جَرَحْتُمْ means \"you all wounded\" or \"you all commit,\" depending on the context. The root conveys the dual concept of physical harm and acquisition, connecting the act of wounding to the process of earning or gathering, whether tangible or intangible. This highlights how both injuries and deeds leave lasting effects, tying the physical and moral aspects of the root.",
  "1216": "جَرَمَ and related words stem from the root ج-ر-م, and as the root verb, it means \"he cut off,\" \"he committed a crime,\" or \"he severed.\" These meanings highlight themes of separation and transgression. In the phrase لَا جَرَمَ, it forms an idiomatic expression often translated as \"no doubt.\" The root’s concept of cutting off is metaphorically applied here to signify the removal of doubt or ambiguity, leaving only certainty. The negating particle لَا, instead of its usual function, emphasizes the inevitability or decisiveness of a matter. This connection shows the root’s versatility in expressing physical and moral separation as well as definitive clarity, reflecting its theme of severance.",
  "1217": "جَرَيْنَ and related words stem from the root ج-ر-ي, with the root verb جَرَىٰ meaning \"it flowed,\" \"it ran,\" or \"it passed along quickly.\" جَرَيْنَ refers to \"they flowed\" or \"they ran,\" emphasizing the act of continuous movement. The root reflects the idea of perpetual motion, whether describing rivers flowing, events taking place, or time passing. This verb encapsulates the root’s core concept of progression and fluidity, highlighting movement as a fundamental aspect of existence.",
  "1218": "جَزَاءٌ and related words stem from the root ج-ز-ي, with the root verb جَزَى meaning \"he recompensed\" or \"he rewarded.\" جَزَاءٌ means \"recompense\" or \"reward,\" emphasizing the act of giving in return for deeds, whether good or bad. The root highlights the balance and fairness of returning actions with their due consequences. جَزَاءٌ reflects the inherent justice in cause and effect, where every action results in an appropriate and measured response.",
  "1219": "جَزَى and related words stem from the root ج-ز-ي, and as the root verb, it means \"he recompensed\" or \"he rewarded.\" It involves repaying an action with its due consequence, whether reward for good or punishment for wrongdoing. The verb emphasizes the fairness and balance of divine and human justice, where deeds are met with their appropriate outcomes. جَزَى ties directly to the concept of accountability and the inevitability of receiving what one has earned.",
  "1220": "جَزُوعٌ and related words stem from the root ج-ز-ع, with the root verb جَزِعَ meaning \"he was impatient\" or \"he was overcome by grief and agitation.\" جَزُوعٌ refers to someone who is \"impatient,\" highlighting a lack of endurance in the face of hardship. The root reflects themes of emotional fragility and vulnerability, emphasizing a state of being overwhelmed by difficulty or adversity. جَزُوعٌ connects to the root's broader concept by portraying the struggle to maintain composure and resilience under pressure.",
  "1221": "جَزِعٌ and related words stem from the root ج-ز-ع, with the root verb جَزِعَ meaning \"he was impatient\" or \"he was overcome by grief and agitation.\" جَزِعٌ means \"much impatience,\" describing a heightened state of emotional turmoil when faced with hardship or distress. The root conveys themes of vulnerability and a lack of endurance, emphasizing the human tendency to lose composure and be overwhelmed by challenges. جَزِعٌ connects to the root’s broader concept by illustrating the struggle to maintain patience and resilience under pressure.",
  "1222": "جَسَدٌ and related words stem from the root ج-س-د, with the root verb جَسَدَ meaning \"it stuck or adhered.\" جَسَدٌ refers to the \"body\" or \"corporeal form,\" emphasizing the physical aspect of a being as distinct from the soul or spirit. The root conveys themes of cohesion, solidity, and adherence, reflecting the body’s unified structure where components work together seamlessly. جَسَدٌ highlights the material existence of the body, symbolizing its temporal nature in contrast to the soul’s permanence. It ties to the root verb by illustrating the body's cohesive design, where adherence ensures integrity and functionality.",
  "1223": "جَعَلَ and related words stem from the root ج-ع-ل, with the root verb meaning \"he made,\" encompassing contexts of creating, preparing, appointing, altering a state or condition, pronouncing a judgment, or transforming something. It emphasizes the deliberate act of causing something to take a specific form, position, or purpose. The root conveys themes of intentional creation, designation, and transformation, often involving purposeful effort to bring about change or establish order. جَعَلَ captures the process of turning potential into reality and assigning roles within a structured framework.",
  "1224": "جَلَاءٌ and related words stem from the root ج-ل-و, with the root verb جَلَا meaning \"he removed, uncovered, or made clear,\" \"it became manifest or clear,\" and \"he expelled or caused to emigrate.\" جَلَاءٌ refers to \"removal,\" encompassing meanings such as \"expulsion,\" \"departure,\" or \"clearness,\" depending on the context. The root conveys notions of uncovering, clearing away, and revealing, whether through physical displacement, polishing to bring forth brilliance, or eliminating barriers to achieve clarity. The connection lies in the transformative act of removal—be it physical, intellectual, or spiritual—highlighting the processes of unveiling, refinement, and making apparent.",
  "1225": "جَلَابِيبُ and related words stem from the root ج-ل-ب, with the root verb جَلَبَ meaning \"it assembled or became collected together.\" جَلَابِيبُ is the plural of جِلْبَابٌ, referring to \"outer garments\" or \"cloaks.\" The connection to the root lies in its function as a garment that helps assemble oneself into a modest and dignified form. It embodies the concept of being \"collected together,\" ensuring that everything is properly arranged and covered, leaving nothing out of place or exposed, thus symbolizing both physical modesty and personal composure.",
  "1226": "جَلَالٌ and related words stem from the root ج-ل-ل, with the root verb جَلَّ meaning \"he was great,\" describing a human being in terms of estimation, rank, or dignity. جَلَالٌ, meaning \"supreme greatness\" or \"majesty,\" is a term exclusively attributed to Allah (ﷻ). The phrase ذُو الْجَلَالِ وَالْإِكْرَامِ, one of Allah’s (ﷻ) beautiful names, translates as \"The Possessor of Majesty and Honour,\" emphasizing His unmatched greatness and absolute perfection. Similarly, the name ٱلْجَلِيلُ, meaning \"The Majestic\" or \"The Sublime,\" reflects Allah’s (ﷻ) unparalleled grandeur, evoking awe, reverence, and deep veneration.",
  "1227": "جَلْدَةٌ and related words stem from the root ج-ل-د, with the root verb جَلَدَ meaning \"he whipped,\" in response to a crime, as well as \"he compelled.\" جَلْدَةٌ refers to \"lash,\" specifically a single strike administered during flogging. The root conveys themes of strength, endurance, and compulsion, reflecting the physical and symbolic weight of each lash in its role as a prescribed punishment. In the Qur'an and Sunnah, جَلْدَةٌ highlights the precision and measured nature of such punishments, carried out under strict evidentiary conditions as part of divine justice to uphold moral and social order.",
  "1228": "جَمَالٌ and related words stem from the root ج-م-ل, with the root verb جَمُلَ meaning \"he was beautiful.\" The root broadly conveys meanings of beauty, perfection, elegance, and completeness, encompassing both physical and abstract forms of attractiveness and excellence. جَمَالٌ means \"beauty\" and refers directly to aesthetic appeal and attractiveness. This term reflects the harmony and balance in creation, highlighting Allah’s (ﷻ) perfect design as ٱلْمُصَوِّرُ (\"The Fashioner\"), who shapes all things in the most beautiful and precise forms.",
  "1229": "جَمَعَ and related words stem from the root ج-م-ع, and as the root verb, it means \"he gathered\" or \"he collected.\" It signifies the act of assembling, combining, or uniting disparate parts into a whole, emphasizing intentionality and purpose. The root also conveys broader concepts of accumulation, consolidation, and bringing things into order, whether physically, intellectually, or spiritually. The connection lies in the deliberate action of uniting or organizing, reflecting themes of harmony, coherence, and purposeful integration across various contexts.",
  "1230": "جَمَلٌ and related words stem from the root ج-م-ل, with the root verb جَمَلَ meaning \"he collected\" and جَمُلَ meaning \"he was beautiful.\" The root encompasses meanings of gathering, assembling, and beauty. جَمَلٌ means \"camel,\" with the connection lying in the camel's ability to carry and gather loads for transport, symbolizing endurance, provision, and the uniting of resources. The camel is also regarded as a beautiful and majestic creature, elegant in motion, embodying strength and grace.",
  "1231": "جَمِيعٌ and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered\" or \"he collected.\" جَمِيعٌ means \"all\" or \"entirety,\" reflecting the state of inclusiveness and completeness that results from gathering all parts into a single entity. The root conveys the act of bringing together separate parts into a unified whole, emphasizing organization, intentionality, and unity. The connection to the root highlights the unification of disparate elements into one comprehensive whole, symbolizing completeness and totality.",
  "1232": "جَمِيلٌ and related words stem from the root ج-م-ل, with the root verb جَمُلَ meaning \"he was beautiful.\" The root broadly conveys meanings of beauty, elegance, perfection, and completeness, encompassing both external and internal qualities. جَمِيلٌ means \"beautiful,\" \"pleasing,\" or \"goodly,\" directly describing qualities that are admirable and delightful. This term emphasizes that true beauty is not limited to physical appearance but is also reflected in morals, character, and virtuous actions.",
  "1233": "جَمٌّ and related words stem from the root ج-م-م, with the root verb جَمَّ meaning \"it was abundant\" or \"it overflowed.\" The root conveys the idea of excess, great quantity, and plentifulness, often referring to things in large or overwhelming amounts. جَمٌّ means \"numerous\" or \"abundant,\" emphasizing the vastness or multitude of something. The connection lies in the root’s depiction of things existing in great numbers or quantities, reflecting themes of profusion and plentitude. This term captures the overwhelming nature of abundance, whether in material or abstract forms.",
  "1234": "جَمْعٌ and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered.\" جَمْعٌ refers to \"gathering\" or \"assembly,\" emphasizing the act or instance of bringing people or elements together. It also refers to the Day of Assembly (Resurrection), where all beings will be united before Allah (ﷻ). The connection lies in the themes of unity, accountability, and the culmination of events into a single significant moment.",
  "1235": "جَنَاحٌ and related words stem from the root ج-ن-ح, with the root verb جَنَحَ meaning \"he inclined\" or \"he leaned on one side.\" جَنَاحٌ means \"wing,\" referring to the part of a bird that extends outward, enabling flight, and for humans, it can signify the arm or upper arm area. The root conveys the idea of inclination or extension, highlighting the symbolic role of the wing or arm as a means of protection, support, or reaching outward. The connection emphasizes themes of leaning, extending, and providing coverage or movement.",
  "1236": "جَنْبٌ and related words stem from the root ج-ن-ب, with the root verb جَنَبَ meaning \"he placed at a distance, sent away, or turned aside.\" جَنْبٌ means \"side\" or \"flank,\" directly referring to the physical side of a person or object. The connection lies in the spatial concept of being beside or alongside, reflecting themes of proximity and closeness. It also symbolizes personal space or an intimate aspect of oneself, highlighting the balance between nearness and separation in human interactions and physical positioning.",
  "1237": "جَنَحُوا and related words stem from the root ج-ن-ح, with the root verb جَنَحَ meaning \"he inclined\" or \"he leaned to one side,\" often suggesting a deliberate or natural tendency to turn or deviate. The root encompasses broader meanings, such as bending, inclining, or deviating toward a particular direction or purpose, whether physically or metaphorically. جَنَحُوا reflects this action, highlighting an intentional or instinctive movement toward a specific position, often associated with a shift or alignment that emphasizes the root's overarching focus on movement, tendency, and inclination.",
  "1238": "جَنَفٌ and related words stem from the root ج-ن-ف, with the root verb جَنَفَ meaning \"he deviated\" or \"he inclined unfairly.\" جَنَفٌ means \"injustice\" or \"bias,\" specifically referring to an inclination toward unfairness or partiality. The root conveys the idea of leaning or inclining in a way that diverges from balance or fairness, often implying moral or ethical deviation. The connection lies in the act of turning away from justice and equity, emphasizing themes of partiality and unfairness.",
  "1239": "جَنَىٰ and related words stem from the root ج-ن-ي, and as the root verb, it means \"he gathered\" or \"he harvested,\" specifically referring to fruit or produce. The connection is in the action of collecting fruits or outcomes from one's efforts. This verb emphasizes the principle of reaping what one sows, highlighting accountability and the tangible results of work and actions.",
  "1240": "جَنِيٌّ and related words stem from the root ج-ن-ي, with the root verb جَنَىٰ meaning \"he harvested\" or \"he plucked.\" جَنِيٌّ means \"freshly picked,\" often referring to ripe dates, fresh fruit, and by extension, activities like cotton harvesting, gold mining, and fishing. The connection lies in the state of readiness at the time of harvest—when something is ripe, suitable, and rewarding to gather. This term reflects maturity, readiness, and the fulfillment of effort and patience.",
  "1241": "جَنَّ and related words stem from the root ج-ن-ن, and as the root verb, it means \"he covered\" or \"he concealed.\" It conveys the action of hiding or veiling something from sight. The root emphasizes themes of protection, secrecy, and the unseen aspects of existence. This root forms the basis of words like جَنَّةٌ (paradise, a hidden garden), جَنِينٌ (embryo, concealed in the womb), and جَانٌّ (jinn, beings hidden from human senses), reflecting the interconnected concept of hiddenness and safeguarding.",
  "1242": "جَنَّةٌ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he concealed\" or \"he covered.\" جَنَّةٌ means \"garden\" or \"Paradise,\" referring to a lush, enclosed space often hidden from view. The root conveys concealment, protection, and enclosure, emphasizing the hidden and safeguarded nature of a garden or Paradise. It symbolizes a secluded and richly adorned area, shielded from the outside world, representing reward, beauty, and safety.",
  "1243": "جَهَازٌ and related words stem from the root ج-ه-ز, with the root verb جَهَّزَ meaning \"he prepared\" or \"he equipped.\" The root broadly conveys meanings of preparation, readiness, equipping, and providing what is necessary for a purpose or task. جَهَازٌ means \"equipment\" or \"provision,\" reflecting the act of preparing and supplying essential items. This term emphasizes the importance of being well-equipped and ready, whether for a journey, a task, or life’s challenges, highlighting foresight and diligence.",
  "1244": "جَهَالَةٌ and related words stem from the root ج-ه-ل, with the root verb جَهِلَ meaning \"he was ignorant.\" The root broadly signifies ignorance, foolishness, and the absence of knowledge or wisdom. جَهَالَةٌ means \"ignorance\" or \"foolishness,\" referring to the state of lacking knowledge or acting without understanding. This term highlights the consequences of ignorance and the immense value of education, wisdom, and thoughtful action in achieving success and avoiding harm.",
  "1245": "جَهَرَ and related words stem from the root ج-ه-ر, and as the root verb, it means \"he spoke aloud\" or \"he proclaimed openly.\" The connection is in making something visible or audible that was previously concealed. This verb emphasizes openness and clarity in communication, highlighting the importance of declaring truth and sharing knowledge openly.",
  "1246": "جَهَنَّمُ and related words stem from the root ج-ه-ن-م, though its exact Arabic derivation is debated. It means \"Hell,\" a place of severe punishment in the afterlife. Some scholars suggest it is borrowed from the Hebrew word Gehenna, referring to the Valley of Hinnom near Jerusalem, where some of the Children of Israel sacrificed their children to the idol Moloch. In the Qur'an, جَهَنَّمُ serves as a stark warning for disbelievers and wrongdoers, while also highlighting Allah's (ﷻ) mercy in warning humanity about its existence and establishing ultimate justice for wrongs not rectified on earth.",
  "1247": "جَهُولٌ and related words stem from the root ج-ه-ل, with the root verb جَهِلَ meaning \"he was ignorant.\" The root broadly conveys meanings of ignorance, lack of knowledge, foolishness, and acting without understanding. جَهُولٌ is an intensive form meaning \"extremely ignorant\" or \"very unknowing,\" emphasizing a profound or excessive state of ignorance. This term highlights the critical need for learning and awareness to prevent serious errors and misjudgments and underscores the severity of remaining in such a state.",
  "1248": "جَهَّزَ and related words stem from the root ج-ه-ز, and as the root verb, it means \"he equipped\" or \"he prepared.\" The root encompasses broader meanings of readiness, preparation, and supplying what is needed for completion or success. جَهَّزَ specifically focuses on the act of equipping or making ready, often in the context of preparing for a journey or task. This highlights the critical importance of preparation and foresight, ensuring one is adequately equipped to meet upcoming challenges or objectives.",
  "1249": "جَهْدٌ and related words stem from the root ج-ه-د, with the root verb جَهَدَ meaning \"he exerted effort\" or \"he strove.\" جَهْدٌ refers to the exertion of effort, strength, or capacity, often emphasizing striving with one's utmost or greatest ability. The root conveys themes of intense effort and perseverance. The connection lies in the idea of employing all available strength and resources to achieve a goal, highlighting the concept of maximum exertion and intensity in effort.",
  "1250": "جَهْرٌ and related words stem from the root ج-ه-ر, with the root verb جَهَرَ meaning \"it was apparent or public,\" or \"he spoke aloud.\" The root broadly conveys meanings of loudness, openness, clarity, and making something apparent. جَهْرٌ means \"aloud\" or \"openness,\" referring to the state of being overt or publicly expressed. This term highlights the value of transparency and the contrast between hidden intentions and openly declared actions, emphasizing honesty and clarity in expression.",
  "1251": "جَهْرَةً and related words stem from the root ج-ه-ر, with the root verb جَهَرَ meaning \"it was apparent or public,\" or \"he spoke aloud.\" The root broadly encompasses meanings of making something clear, manifest, or visible, often in a loud or overt way. جَهْرَةً means \"openly\" or \"visibly,\" emphasizing the act of making something perceptible to the senses. This term highlights clarity and openness, often referring to something that is physically visible or manifest in a clear and undeniable manner.",
  "1252": "جَوَابٌ and related words stem from the root ج-و-ب, with the root verb جَابَ meaning \"he cut through\" or \"he pierced.\" The root broadly conveys meanings of cutting, piercing, breaking through, or addressing something directly. جَوَابٌ means \"answer\" or \"response,\" reflecting the idea of cutting through ambiguity or uncertainty to provide clarity and resolution. This emphasizes the importance of effective communication in resolving doubts and the satisfaction that comes from receiving a definitive and clear response.",
  "1253": "جَوَارٍ and related words stem from the root ج-ر-ي, with the root verb جَرَىٰ meaning \"it flowed,\" \"it ran,\" or \"it passed along qickly.\" جَوَارٍ is the plural of جارِيَةٌ and refers to \"ships\" or \"things that run.\" This term captures the collective motion of ships gliding across the sea, embodying the root’s concept of flowing or running. The plural form emphasizes the dynamic and harmonious movement of multiple entities, reflecting the coordinated flow inherent in the root.",
  "1254": "جَوَارِحُ and related words stem from the root ج-ر-ح, with the root verb جَرَحَ meaning \"he wounded\" or \"he acquired or earned.\" جَوَارِحُ primarily refers to \"hunting animals\" but also means \"limbs.\" The connection lies in the role of limbs as tools for earning or acting, paralleling the hunting animal’s role in acquiring prey. Both meanings reflect the root’s broader themes of acquiring, wounding, and leaving a mark—whether through physical action or purposeful effort. This duality ties the physical function of limbs and the trained instincts of hunting animals to the root’s concept of deliberate acquisition.",
  "1255": "جَوٌّ and related words stem from the root ج-و-و, which broadly conveys meanings of openness, vastness, air, and space. جَوٌّ means \"atmosphere\" or \"sky,\" emphasizing the expansive environment surrounding us.",
  "1256": "جَوْفٌ and related words stem from the root ج-و-ف, which conveys meanings of hollowness, emptiness, interior space, or cavity. جَوْفٌ means \"inside\" or \"inner part,\" referring to the hollow or interior aspect of something. The word highlights introspection, inner depth, or the unseen spaces within. This term emphasizes the importance of what lies within, whether physically or metaphorically, as a core or essence.",
  "1257": "جَيْبٌ and related words stem from the root ج-ي-ب, which refers to the \"chest\" or \"opening of a garment at the neck and chest,\" specifically the cut or slit at the uppermost part of a shirt. The term highlights the functional purpose of an opening designed for ease of wear and accessibility. In Arab culture, items were often carried within the chest area of the garment, giving rise to the word’s use for \"a pocket,\" further emphasizing its connection to the concept of a purposeful and practical opening.",
  "1258": "جُبٌّ and related words stem from the root ج-ب-ب, with the root verb جَبَّ meaning \"he cut off,\" \"he severed,\" or \"he removed.\" جُبٌّ means \"well\" or \"pit,\" referring to a hollow created by cutting or excavating into the ground. The connection to the root lies in the act of severing or removing earth to create a space for accessing water or other resources. Symbolically, it represents the effort to draw sustenance or knowledge from deep and often hidden sources. This reflects the root’s broader theme of separation or extraction, emphasizing the labor and intention involved in seeking life-sustaining necessities from beneath the surface.",
  "1259": "جُدَدٌ and related words stem from the root ج-د-د, with the root verb جَدَّ meaning \"he cut\" or \"he severed,\" or \"it was new\" or \"renewed.\" جُدَدٌ (plural of جُدَّةٌ) refers to \"streaks or paths in something, such as a mountain, differing in color from the rest, like white, black, or red.\" This term connects to the root’s themes of cutting and renewal, as the streaks and paths appear as if the surface was cut into distinct forms and renewed into something striking and beautiful. The differing colors and patterns reflect the transformation of the natural landscape into something uniquely defined, emphasizing the root’s connotation of creating newness and distinction with awe-inspiring results.",
  "1260": "جُدُرٌ and related words stem from the root ج-د-ر, with the root verb جَدُرَ meaning \"he was suitable, fit, competent, or worthy.\" Another form, جَدَرَ, means \"he built a wall.\" جُدُرٌ means \"walls.\" The connection lies in the idea of a wall being something fit or suitable for a specific purpose, serving as a protective boundary. Just as the root conveys appropriateness, a wall is an element that is properly suited to providing security, separation, or support in a given environment. This reflects the root’s broader theme of something being designed and constructed with the right purpose.",
  "1261": "جُذَاذٌ and related words stem from the root ج-ذ-ذ, with the root verb جَذَّ meaning \"he cut off\" or \"he broke into pieces.\" جُذَاذٌ means \"fragments\" or \"pieces,\" emphasizing the result of cutting or breaking something apart. The root conveys themes of severing, dividing, or disintegrating, often implying forceful separation. This connection highlights how something whole can be reduced to scattered parts due to disruption or destruction.",
  "1262": "جُرُزٌ and related words stem from the root ج-ر-ز, with the root verb جَرَزَ meaning \"he cut it off,\" \"he devoured,\" or \"he consumed entirely.\" جُرُزٌ refers to \"barren\" or \"infertile land,\" describing land stripped of fertility and productivity. The root reflects themes of depletion, consumption, and desolation, connecting the barren state of the land to the idea of being consumed or left empty, similar to devoured food. This term vividly captures the starkness and emptiness of unproductive landscapes, emphasizing the complete removal of growth and sustenance.",
  "1263": "جُرُفٌ and related words stem from the root ج-ر-ف, with the root verb جَرَفَ meaning \"he carried away the whole of it or much of it,\" or \"he swept away from the surface of the earth.\" جُرُفٌ refers to an \"eroded bank,\" emphasizing instability and vulnerability to collapse. The root conveys themes of forceful removal or displacement, illustrating how external forces strip or sweep something away, leaving it exposed and fragile. جُرُفٌ encapsulates the precarious nature of such structures, symbolizing the transformative and often destructive power of erosion, which alters the landscape and reflects the fragility of what lacks firm foundation.",
  "1264": "جُرُوحٌ and related words stem from the root ج-ر-ح, with the root verb جَرَحَ meaning \"he wounded\" or \"he acquired or earned.\" جُرُوحٌ (plural of جُرْحٌ) means \"wounds,\" emphasizing the physical injuries inflicted on the body. The root extends to metaphorical injuries, reflecting the deeper idea of harm or impact that leaves a lasting impression. Whether physical or moral, the concept of wounding connects to the root’s broader theme of actions or events that result in enduring marks or scars.",
  "1265": "جُزْءٌ and related words stem from the root ج-ز-أ, with the root verb جَزَأَ meaning \"he divided,\" \"he took a part,\" or \"he was satisfied or content.\" جُزْءٌ means \"part\" or \"portion,\" referring to a segment derived from dividing a whole. The root embodies themes of division, separation, and allocation, emphasizing the act of breaking something into distinct, meaningful components. جُزْءٌ reflects the root's broader dimensions by highlighting how individual parts contribute to a larger entity, balancing the notion of separation with the interdependence and purpose of each segment.",
  "1266": "جُفَاءٌ and related words stem from the root ج-ف-أ, with the root verb جَفَأَ meaning \"he or it cast off froth, foam, or particles of rubbish.\" جُفَاءٌ refers to \"foam\" or \"froth\" discarded by a torrent or valley, symbolizing something rejected or without value. The root conveys themes of separation and estrangement, emphasizing the act of casting away or distancing. جُفَاءٌ ties to the root’s concept of rejection, illustrating the transient and insignificant nature of what is discarded.",
  "1267": "جُلُودٌ and related words stem from the root ج-ل-د, with the root verb جَلَدَ meaning \"he was hardy, strong, sturdy,\" or \"he was enduring or patient.\" جُلُودٌ, the plural of جِلْدٌ, refers to \"skins\" or \"hides,\" highlighting the skin as a protective and resilient covering of the body. The connection to the root lies in the skin’s role as a symbol of strength and endurance, serving as the body’s first layer of defense against external harm. This association reflects the broader themes of durability and protection conveyed by the root, emphasizing the vital function of the skin in maintaining the body’s integrity.",
  "1268": "جُمُعَةٌ and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered\" or \"he collected.\" جُمُعَةٌ refers to \"Friday,\" the day of congregation for Muslims. The root conveys the act of bringing together separate parts into a unified whole, emphasizing organization and unity. The connection lies in the weekly gathering for communal prayer, reflecting physical and spiritual unity. This term highlights the significance of coming together in worship, fostering community bonds, and reinforcing shared purpose and devotion.",
  "1269": "جُمْلَةٌ and related words stem from the root ج-م-ل, with the root verb جَمَلَ meaning \"he collected.\" جُمْلَةٌ means \"sum,\" \"whole,\" or \"total,\" referring to something that is considered in its entirety or as a collective unit. The root conveys the idea of gathering or uniting separate parts into a complete and cohesive whole, emphasizing order and completeness. The connection reflects the act of assembling distinct elements into a single unified entity, highlighting themes of comprehensiveness and inclusion.",
  "1270": "جُناحٌ and related words stem from the root ج-ن-ح, with the root verb جَنَحَ meaning \"he inclined\" or \"he leaned to one side.\" جُناحٌ means \"sin\" or \"act of disobedience,\" reflecting a metaphorical extension of the root’s concept of inclining or deviating. The broader root meanings encompass themes of bending, turning, or shifting from a stable or upright position. The connection lies in the idea that inclining away from the straight path or moral uprightness results in wrongdoing, symbolizing deviation from truth, justice, or balance, and emphasizing the moral consequences of straying from righteousness.",
  "1271": "جُنْدٌ and related words stem from the root ج-ن-د, with the root verb جَنَّدَ meaning \"he collected or assembled,\" particularly in reference to armies or military forces. The root conveys broader concepts of gathering, strengthening, or preparing for action, often emphasizing a structured or organized effort. جُنْدٌ means \"army\" or \"troops,\" symbolizing a group brought together for a unified purpose. This connection highlights not only the physical assembly of individuals but also the notions of order, discipline, and collective strength that emerge from coordination and shared objectives, highlighting the power of unity and preparedness in achieving a common goal.",
  "1272": "جُنَّةٌ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he concealed,\" or \"he covered.\" جُنَّةٌ means \"a thing by which a person is veiled, concealed, hidden, covered, or protected\" or \"armor.\" The connection lies in the armor’s role as a protective covering, concealing the bearer from harm. This term emphasizes defense and safeguarding, symbolizing protection from external threats, whether physical or spiritual.",
  "1273": "جُهْدٌ and related words stem from the root ج-ه-د, with the root verb جَهَدَ meaning \"he strove\" or \"he exerted effort.\" جُهْدٌ means \"utmost effort\" or \"struggle.\" The connection lies in the exertion of energy towards a goal, reflecting the root's emphasis on striving. This term highlights the importance of diligence and perseverance in overcoming challenges and achieving success, both in worldly affairs and spiritual endeavors.",
  "1274": "جُودِيٌّ and related words stem from the root ج-و-د, with the root verb جَادَ meaning \"it was good or excellent\" or \"he was excellent.\" The root broadly conveys meanings of excellence, generosity, abundance, and bountifulness. جُودِيٌّ refers to \"Mount Judi,\" the mountain where Prophet Noah’s (ﷺ) ship came to rest. The connection to the root is clear in the mountain being a manifestation of divine generosity and excellence, as it served as a place of salvation and mercy. This symbolizes Allah’s (ﷻ) abundant grace and kindness in granting safety and a new beginning for humanity after the Flood.",
  "1275": "جُوعٌ and related words stem from the root ج-و-ع, with the root verb جَاعَ meaning \"he became hungry.\" جُوعٌ means \"hunger,\" referring to a state of need or deprivation of sustenance. The root conveys themes of insufficiency, reliance, and vulnerability, emphasizing the human condition of dependence on external provision. The connection lies in hunger as a profound expression of need, reflecting the broader root concepts of striving for fulfillment and the relief brought by sustenance.",
  "1276": "جِبَاهٌ and related words stem from the root ج-ب-ه, with the root verb جَبَهَ meaning \"to confront with rough speech,\" \"to face openly,\" or \"to rebuke harshly.\" جِبَاهٌ (plural of جَبْهَةٌ) means \"foreheads,\" and the root reflects the idea of direct confrontation and exposure. Interestingly, in the Qur'an, this term is used instead of جَبِينٌ (another word for forehead) to emphasize the confrontational nature of punishment for those who hoard wealth. The use of this word highlights how such individuals are rebuked and held accountable for their greed and failure to give in the path of Allah (ﷻ), reinforcing the theme of direct exposure and reproach.",
  "1277": "جِبِلَّةٌ and related words stem from the root ج-ب-ل, with the root verb جَبَلَ meaning \"He (Allah (ﷻ)) created,\" specifically \"He created with an adaptation or disposition,\" emphasizing the act of molding or shaping for a purpose. جِبِلَّةٌ means \"generations\" or \"multitudes,\" referring to large groups of people or beings. It connects to the root by reflecting the act of forming or creating entire populations, emphasizing their shared origin and the diversity within creation. This term highlights humanity and other creatures as collectively molded by Allah (ﷻ), highlighting both their unity and variety in creation.",
  "1278": "جِبْتٌ is a non-Arabic word with unknown roots. It means \"idolatry,\" \"sorcery,\" \"superstition,\" or \"falsehood,\" encompassing anything that diverts people from truth and monotheistic worship. The term emphasizes negating truth and spreading falsehood through misguided practices, symbolizing corruption and spiritual misguidance. Engaging in superstition, magic, astrology, horoscopes, tarot cards, or seeking knowledge of the unseen future is a serious transgression. Such actions undermine trust in Allah’s (ﷻ) decree, foster reliance on falsehood, and invite spiritual harm, opposing belief in Allah's (ﷻ) ultimate knowledge and authority.",
  "1279": "جِبْرِيلُ and related words stem from Hebrew and Syriac origins, combining جَبَرَ (\"strength\" or \"restoring to a sound state\") and إِيل (\"God\"), meaning \"Strength of God\" or \"Mighty Servant of God.\" The Angel Gabriel (ﷺ) was tasked with delivering divine revelations to the prophets. As a powerful and trustworthy messenger, he restores humanity to a sound state by delivering divine communication. Allah (ﷻ) calls him the \"Holy and Trustworthy Spirit,\" emphasizing his strength and purity, highlighting the importance of divine guidance and the role of messengers in conveying Allah's (ﷻ) words.",
  "1280": "جِثِيٌّ and related words stem from the root ج-ث-و, with the root verb جَثَا meaning \"he knelt.\" جِثِيٌّ refers to \"kneeling positions\" or \"groups kneeling,\" emphasizing the collective act of being in a kneeling posture. The root highlights a state of submission or stillness, and in its plural form, جِثِيٌّ conveys the imagery of multiple individuals or groups united in humility or subservience. This connection highlights the shared acknowledgment of a greater power or authority, reflected in the uniformity of the posture.",
  "1281": "جِدَارٌ and related words stem from the root ج-د-ر, with the root verb جَدُرَ meaning \"he was suitable, fit, competent, or worthy.\" Another form, جَدَرَ, means \"he built a wall.\" جِدَارٌ means \"wall.\" The connection lies in the idea of a wall being something fit or suitable for a specific purpose—serving as a protective structure or boundary. Just as the root conveys appropriateness, a wall is properly suited to providing security, separation, or support in a given environment. This reflects the root’s broader theme of something being designed and constructed with purpose.",
  "1282": "جِدَالٌ and related words stem from the root ج-د-ل, with the root verb جَدَلَ meaning \"it was hard and strong,\" and جَدِلَ meaning \"he disputed, or litigated, vehemently, or violently.\" جِدَالٌ means \"contentious debate\" or \"disputation,\" emphasizing prolonged or intense argumentation. The root conveys structured contention and persistence, often requiring skill and determination in asserting a position or refuting another’s. جِدَالٌ reflects these broader root themes by focusing on argumentation that is not only deliberate but also marked by effort and intensity, highlighting the verbal struggle involved in contentious discussions.",
  "1283": "جِذْعٌ and related words stem from the root ج-ذ-ع, with the root verb جَذَعَ meaning \"he cut off,\" \"he severed,\" or \"he truncated.\" جِذْعٌ refers to \"the trunk\" or \"stem\" of a tree, viewed as the part that could be metaphorically severed or separated from its branches. The root’s theme of cutting or severance connects to the idea of the trunk being distinct as the main structural component of the tree, supporting and nourishing its extensions. This connection emphasizes the trunk’s role as a vital yet separable part of the tree, embodying the balance between centrality and the potential for separation inherent in the root meanings.",
  "1284": "جِزْيَةٌ and related words stem from the root ج-ز-ي, with the root verb جَزَى meaning \"he recompensed\" or \"he rewarded.\" جِزْيَةٌ means \"tribute\" or \"tax,\" referring to the payment made by non-Muslim subjects within an Islamic state in exchange for protection. The root connects to the idea of recompense, where the payment represents an obligation fulfilled in return for security and societal inclusion. جِزْيَةٌ reflects the mutual responsibilities within agreements, emphasizing balance and fairness in societal contracts.",
  "1285": "جِسْمٌ and related words stem from the root ج-س-م, with the root verb جَسُمَ meaning \"he was bulky\" or \"he was well-built.\" جِسْمٌ means \"body\" or \"substance,\" focusing on the material mass or structure of a being or object. Unlike جَسَدٌ, which is tied to human or symbolic form, جِسْمٌ applies broadly to any physical form, emphasizing size, shape, or composition. The root conveys themes of materiality and tangibility, highlighting the physical dimension of existence without necessarily contrasting it with spiritual qualities.",
  "1286": "جِفَانٌ and related words stem from the root ج-ف-ن, which relates to containers or receptacles. جِفَانٌ is the plural of جَفْنَةٌ, referring to \"bowls\" or \"basins,\" specifically large vessels used for serving food. The root conveys the idea of holding, containing, or enclosing, as these vessels are designed to gather and present their contents. This connection reflects the functional purpose of جِفَانٌ as objects that serve communal needs, often in the context of hospitality, abundance, or generosity, and particularly for feeding many people at once, emphasizing their role in fostering community and provision.",
  "1287": "جِمَالَةٌ and related words stem from the root ج-م-ل, with the root verb جَمَلَ meaning \"he gathered\" or \"he collected.\" جِمَالَةٌ means \"caravan\" or \"company of camels,\" referring to a grouping of camels traveling together for trade or transport. The root emphasizes bringing together distinct parts into a unified whole, highlighting organization and collaboration. The connection lies in the unity and shared purpose of a caravan, symbolizing collective effort and journeying.",
  "1288": "جِنٌّ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he concealed,\" or \"he covered.\" جِنٌّ refers to the jinn, beings created from smokeless fire and hidden from human sight. The root conveys themes of hiddenness, veiling, and invisibility, perfectly reflecting their existence in the unseen realm beyond human perception.",
  "1289": "جِنَّةٌ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he concealed\" or \"he covered.\" جِنَّةٌ carries dual meanings: it refers to madness or insanity, and to the jinn when written as \"الْجِنَّةُ.\" The root emphasizes hiddenness and concealment, unifying these meanings. In the context of madness, it signifies the veiling or obscuring of rational faculties, as if the mind is covered. Regarding the jinn, it connects to their hidden and unseen nature. This term conveys themes of invisibility and veiling, whether related to mental clarity or unseen beings.",
  "1290": "جِهَادٌ and related words stem from the root ج-ه-د, with the root verb جَهَدَ meaning \"he exerted effort.\" جِهَادٌ means \"struggle\" or \"striving,\" referring to exerting effort in various forms, including the internal struggle against desires, resisting temptations, striving with wealth, spreading knowledge, and physical struggle under specific conditions. The root conveys themes of exertion, perseverance, and overcoming challenges. The connection lies in the continuous effort to strive against internal weaknesses and external injustices, reflecting the comprehensive nature of striving in the way of Allah (ﷻ).",
  "1291": "جِهَارًا and related words stem from the root ج-ه-ر, with the root verb جَهَرَ \"it was apparent or public,\" or \"he spoke aloud.\" The root conveys ideas of loudness, openness, and making something apparent. جِهَارًا means \"openly\" or \"aloud,\" signifying the act of declaring something in a clear and audible manner. This term highlights the courage and integrity required to be open about one's beliefs and deeds, reflecting a commitment to truth and transparency.",
  "1292": "جِيَادٌ and related words stem from the root ج-و-د, with the root verb جَادَ meaning \"it was good or excellent\" or \"he was excellent.\" The root broadly conveys meanings of excellence, generosity, abundance, and noble qualities. جِيَادٌ (plural of جَوَادٌ) means \"swift horses\" or \"noble steeds,\" with the connection lying in the excellence, nobility, and superior qualities associated with these horses. Their speed, strength, and spirited nature embody the root's themes of distinction and generosity in both physical and moral attributes.",
  "1293": "جِيدٌ and related words stem from the root ج-ي-د, with the root verb جَادَ meaning \"he had a long or slender neck.\" جِيدٌ means \"neck,\" specifically referring to the upper part of the body that supports the head. In classical Arabic, جِيدٌ often conveys a sense of elegance and prominence, as the neck is frequently associated with beauty and adornment, such as necklaces. The connection to the root lies in the description of the neck’s graceful appearance, emphasizing its slender and distinguished nature.",
  "1294": "حَاجَةٌ and related words stem from the root ح-و-ج, with the root verb اِحْتَاجَ meaning \"he needed\" or \"he required.\" حَاجَةٌ means \"need,\" \"necessity,\" or \"want.\" The root conveys themes of deficiency or dependence, reflecting a state where something essential is missing and must be fulfilled. This word emphasizes human vulnerability and the reliance on external factors for sustenance and well-being, highlighting the universal nature of need and interdependence.",
  "1295": "حَاجِزٌ and related words stem from the root ح-ج-ز, with the root verb حَجَزَ meaning \"he prevented,\" \"he withheld,\" or \"he separated.\" حَاجِزٌ means \"barrier\" or \"separator.\" The root dimensions revolve around creating divisions, withholding access, and forming protective boundaries. The connection lies in the barrier’s role as an active agent of separation or obstruction, directly reflecting the root’s concept of prevention and limitation. Just as the verb signifies the act of withholding, حَاجِزٌ serves as a tangible divider, symbolizing the importance of boundaries in safeguarding or regulating movement and interaction.",
  "1296": "حَاجٌّ and related words stem from the root ح-ج-ج, with the root verb حَجَّ meaning \"he went to or visited an object of reverence, veneration, respect, or honor\" or \"he performed pilgrimage.\" حَاجٌّ means \"pilgrim,\" referring to one who undertakes the sacred journey to the Kaaba. The root conveys meanings of intending, seeking, and embarking on a purposeful journey. Just as حَجَّ denotes setting out toward something esteemed, the pilgrimage is a deliberate act of devotion, undertaken with deep purpose and reverence. The pilgrim embodies this meaning by striving toward nearness to Allah (ﷻ), fulfilling a journey that is not only physical but one of spiritual repair, purification, and submission.",
  "1297": "حَاجَّ and related words stem from the root ح-ج-ج, with the root verb حَجَّ meaning \"he performed pilgrimage,\" or \"he overcame another in an argument, plea, proof, or testimony.\" حَاجَّ means \"he argued\" or \"he debated,\" referring to engaging in disputation. The root conveys intentional seeking, assertion, and prevailing. Just as pilgrimage requires deliberate seeking and perseverance in striving toward nearness to Allah (ﷻ), debate requires reasoning and effort in establishing truth. Both signify a purposeful struggle—one in devotion, the other in intellectual engagement—highlighting the root’s broader theme of striving for clarity and resolution.",
  "1298": "حَادَّ and related words stem from the root ح-د-د, with the root verb حَدَّ meaning \"he sharpened\" or \"he prevented, impeded, withheld, or restrained.\" حَادَّ means \"he opposed\" or \"he was hostile towards.\" The root conveys sharpness, restriction, and division, where opposition becomes a force of resistance. Just as something sharp defines a boundary, hostility prevents agreement and creates separation. Opposition is not just a stance but an active barrier that hinders reconciliation, much like a limit that restrains movement. This reflects how enmity leads to division, preventing harmony and reinforcing consequences between opposing sides.",
  "1299": "حَاذِرُونَ and related words stem from the root ح-ذ-ر, with the root verb حَذِرَ meaning \"he was cautious\" or \"he was vigilant.\" حَاذِرُونَ means \"those who are on guard,\" referring to individuals in a state of awareness and preparation. The connection lies in the root’s emphasis on alertness, as caution requires continuous observation and readiness to avoid harm. Just as vigilance prevents danger, this word reflects an active state of awareness, where one is mindful of potential threats and acts accordingly to protect themselves.",
  "1300": "حَارَبَ and related words stem from the root ح-ر-ب, with the root verb حَرَبَ meaning \"he plundered\" and حَرِبَ meaning \"he was angry or violently angry.\" حَارَبَ means \"he waged war\" or \"he fought.\" The connection lies in the root’s themes of aggression, conflict, and loss. Plundering signifies the forceful seizure of possessions, while anger reflects an intense state of hostility, both of which are central to war. Just as war involves violent confrontation and destruction, the root conveys the disruption and devastation caused by enmity, reflecting the extreme consequences of opposition and conflict.",
  "1301": "حَاسَبَ and related words stem from the root ح-س-ب, with the root verb حَسِبَ meaning \"he reckoned\" or \"he calculated.\" حَاسَبَ means \"he held accountable\" or \"he called to account.\" The connection lies in the act of reckoning or evaluating actions, directly relating to the root's emphasis on calculation and consideration. This term highlights the importance of accountability in moral and social contexts.",
  "1302": "حاسِبٌ and related words stem from the root ح-س-ب, with the root verb حَسِبَ meaning \"he reckoned\" or \"he calculated.\" حاسِبٌ means \"reckoner\" or \"accountant,\" referring to one who calculates or keeps accounts. The connection emphasizes the role of calculation, directly relating to the root's essence of reckoning. This term highlights the importance of careful assessment in various aspects of life.",
  "1303": "حاسِدٌ and related words stem from the root ح-س-د, with the root verb حَسَدَ meaning \"he envied\" or \"he wished for the deprivation of (something from someone).\" حاسِدٌ means \"envier\" or \"one who envies.\" The connection lies in harboring envy towards others, directly relating to the root's focus on jealousy. This root conveys themes encompassing negative emotions such as resentment, covetousness, and ill will, emphasizing the harm of unchecked envy and its impact on relationships and morality.",
  "1304": "حاشَ stems from the root ح-و-ش, with the root verb حَاشَ meaning \"he drove or scattered away,\" or \"he withdrew or distanced himself.\" It is primarily used as an emphatic interjection meaning “God forbid” or “far be it,” expressing strong denial or rejection. This is similar to declaring something absolutely untrue or impossible. It appears in phrases that emphatically disassociate from a statement or action, reinforcing a sense of exclusion. In classical Arabic, حاشَ is often used to reject any association with imperfection or wrongdoing, emphasizing values of honor and moral integrity.",
  "1305": "حَاشِرِينَ and related words stem from the root ح-ش-ر, with the root verb حَشَرَ meaning \"he congregated or collected together\" or \"he made [them] go forth, collected together, from one place to another.\" حَاشِرِينَ means \"those who gather or assemble others.\" The connection lies in bringing people or beings together by command or force, emphasizing organization, movement, and control over a collective. This term conveys the role of an entity or group responsible for assembling others, whether for judgment, migration, or strategic purposes.",
  "1306": "حاصِبٌ and related words stem from the root ح-ص-ب, with the root verb حَصَبَ meaning \"he pelted\" or \"he threw stones.\" حاصِبٌ means \"storm of stones\" or \"violent storm,\" referring to a force that hurls objects with intensity. The connection lies in pelting and forceful projection, directly relating to the root’s emphasis on striking. This term evokes imagery of a destructive force, whether as a natural calamity or a form of divine punishment, emphasizing power, severity, and overwhelming impact.",
  "1307": "حاضِرٌ and related words stem from the root ح-ض-ر, with the root verb حَضَرَ meaning \"he was present,\" \"he attended,\" or \"he came.\" حاضِرٌ means \"present,\" \"attending,\" or \"resident.\" This reflects the state of being in attendance or existing in a particular place and time, directly relating to the root's emphasis on presence. The term can refer to someone who is currently in a location or situation, highlighting the immediacy and involvement in ongoing events.",
  "1308": "حاضِرَةٌ and related words stem from the root ح-ض-ر, with the root verb حَضَرَ meaning \"he was present,\" \"he attended,\" or \"he came.\" حاضِرَةٌ means \"present\" or \"attending.\" Additionally, it can refer to a \"city\" or \"metropolis,\" symbolizing a settled area as opposed to the desert. This reflects the concept of presence and habitation, directly connecting to the root's emphasis on being present or attending. The term captures the idea of a place where people are gathered and life is active.",
  "1309": "حَاضِرِي and related words stem from the root ح-ض-ر, with the root verb حَضَرَ meaning \"he was present,\" \"he attended,\" or \"he came forward.\" The root conveys themes of presence, readiness, and immediacy, often referring to physically being at a place or mentally engaging in a situation. حَاضِرِي means \"those who are present\" or \"attendees,\" emphasizing active participation and readiness. The connection lies in the state of being physically or mentally present, reflecting the root's focus on immediacy and presence.",
  "1310": "حَافِرَةٌ and related words stem from the root ح-ف-ر, with the root verb حَفَرَ meaning \"he dug,\" or \"he excavated.\" حَافِرَةٌ can mean \"hoof,\" but in idiomatic expressions, it refers to \"the original state\" or \"the beginning.\" The connection lies in the idea of returning to an initial condition, as digging uncovers what is beneath the surface, directly relating to the root's emphasis on excavation. The term captures the concept of reverting or returning to one's origins, highlighting themes of resurrection or restoration.",
  "1311": "حافِظٌ and related words stem from the root ح-ف-ظ, with the root verb حَفِظَ meaning \"he guarded,\" \"he protected,\" or \"he preserved.\" حافِظٌ means \"guardian,\" \"protector,\" or \"men who guard.\" This reflects the role of actively safeguarding or maintaining something, directly connecting to the root's emphasis on protection and preservation. The term can also refer to someone who has memorized the Qur'an, highlighting the dedication to preserving sacred knowledge.",
  "1312": "حَافِظَاتٌ and related words stem from the root ح-ف-ظ, with the root verb حَفِظَ meaning \"he guarded,\" \"he protected,\" or \"he preserved.\" حَافِظَاتٌ means \"women who guard\" or \"guarding.\" This reflects the role of a woman who safeguards or maintains something, directly connecting to the root's emphasis on protection and preservation. The term can also refer to a woman who has memorized significant texts, emphasizing dedication and responsibility in preserving knowledge or values.",
  "1313": "حَافِّينَ and related words stem from the root ح-ف-ف, with the root verb حَفَّ meaning \"he surrounded,\" \"he encircled,\" or \"he encompassed.\" حَافِّينَ means \"surrounding\" or \"encircling,\" reflecting the action of forming a circle around something. The root conveys themes of encompassing, bordering, or gathering closely, often with a sense of attentiveness or reverence. حَافِّينَ can describe groups or entities that encircle a central point, symbolizing unity, closeness, or focused attention, directly connecting to the root's emphasis on surrounding with purpose or care.",
  "1314": "حَاقَ and related words stem from the root ح-ي-ق, and as the root verb, it means \"it surrounded, encompassed, or encircled,\" or \"it befell.\" It is often used to describe punishment or consequences encompassing someone. The root conveys the idea of something surrounding completely, afflicting someone, or becoming unavoidable, emphasizing the overwhelming nature of events or outcomes that envelop their subjects. The connection lies in the inevitability of divine retribution or natural consequences that completely surround wrongdoers, leaving no room for escape.",
  "1315": "الْحَاقَّةُ stems from the root ح-ق-ق, with the root verb حَقَّ meaning \"it was true,\" \"it became established,\" or \"it was necessitated.\" الْحَاقَّةُ refers to \"The Inevitable Reality\" or \"The Impending Truth,\" specifically associated with the Day of Judgment. The connection lies in the absolute certainty and necessity of its occurrence, directly reflecting the root’s emphasis on truth, justice, and fulfillment of what is due. This term underscores the inescapable nature of ultimate reckoning, highlighting the definitive realization of truth and the consequences that follow.",
  "1316": "حَاكِمٌ and related words stem from the root ح-ك-م, with the root verb حَكَمَ meaning \"he judged\" or \"he governed.\" حَاكِمٌ means \"judge\" or \"ruler,\" referring to a person who exercises judgment, governance, or authority with fairness and deliberation. The root also encompasses meanings of restraining, controlling, making firm, and ensuring precision in decision-making or governance. The connection lies in the one who implements justice, maintains order, and establishes stability, directly reflecting the root's emphasis on control, wisdom, and balanced decision-making. This term highlights the critical role of justice, authority, and sound leadership in societal harmony.",
  "1317": "حَامٍ and related words stem from the root ح-م-ي, with the root verb حَمَى meaning \"he protected from harm,\" or \"he made forbidden,\" and حَمِيَ meaning \"it was hot,\" or \"it was forbidden.\" حَامٍ refers to a stallion-camel left at liberty, safeguarded from burdens, reflecting the root's themes of shielding and guarding. The term emphasizes the idea of being protected or set apart, referring to practices of idol-worship where such camels were left untouched. The connection to the root lies in the dual notions of protection and intensity, symbolizing care or reverence for what is guarded.",
  "1318": "حَامِدُونَ and related words stem from the root ح-م-د, with the root verb حَمِدَ meaning \"he praised\" or \"he thanked.\" حَامِدُونَ means \"those who praise\" or \"those who are grateful.\" The connection is direct, referring to those who actively engage in praise and gratitude, especially toward Allah (ﷻ). This term highlights the virtue of thankfulness and the importance of recognizing blessings, fostering a spirit of appreciation and humility in one’s relationship with Allah (ﷻ).",
  "1319": "حَامِلِينَ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" حَامِلِينَ means \"carriers\" or \"bearers,\" specifically referring to individuals who carry or bear something significant. The connection is direct, as it describes those actively engaged in the act of carrying or bearing. The root also relates to terms like حِمَالَةٌ (responsibility or liability) and حَمَّالٌ (a porter or load-bearer), emphasizing the theme of carrying important or heavy matters, whether physical or metaphorical.",
  "1320": "حَامِلَاتِ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" حَامِلَاتِ means \"carriers\" or \"bearers.\" The connection is direct, describing those who carry or bear something significant. The root also relates to terms like حِمَالَةٌ (responsibility or liability) and حَمَّالٌ (a porter or load-bearer), extending the theme of carrying important or heavy matters, whether physical or metaphorical.",
  "1321": "حَامِيَةٌ and related words stem from the root ح-م-ي, with the root verb حَمَى meaning \"he protected from harm,\" or \"he made forbidden,\" and حَمِيَ meaning \"it was hot,\" or \"he was enraged,\" or \"it was forbidden.\" حَامِيَةٌ means \"blazing fire\" or \"intense heat,\" particularly referring to the searing heat of Hellfire. The root conveys themes of heat, intensity, and protection, often signifying barriers that shield or separate. The connection to حَامِيَةٌ lies in its dual nature: it not only consumes and overwhelms with its extreme heat but also acts as a barrier, confining what is inside and protecting or isolating the outside from its destructive force. This duality emphasizes the fierce, punishing nature of Hellfire while illustrating its role as an isolating force in divine justice.",
  "1322": "حَبِطَ and related words stem from the root ح-ب-ط, and as the root verb, حَبِطَ means \"it became void,\" or \"it became worthless,\" highlighting the loss of reward due to actions such as insincerity, hypocrisy, or moral failure. The root encompasses meanings of becoming void, worthless, or ineffective. The connection emphasizes the idea of wasted efforts and the importance of sincerity and righteousness.",
  "1323": "حَبٌّ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved.\" حَبٌّ means \"grain\" or \"seed,\" referring to something small yet foundational and essential for growth and sustenance. The connection between love and grain lies in the idea that both nurture, sustain, and develop over time. Just as a seed, though small, carries the potential for abundant growth, love—when rooted deeply—flourishes and gives life to relationships, communities, and faith. This reflects how essential and life-giving both love and sustenance are, emphasizing their profound role in human existence.",
  "1324": "حَبَّبَ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved.\" حَبَّبَ means \"he made beloved,\" referring to the act of instilling love or affection for someone or something. Unlike أَحَبَّ, which expresses direct love or attachment, حَبَّبَ conveys the idea of causing another to love or find endearment in something. This distinction highlights the role of influence in shaping emotions—while love itself can be natural and intrinsic, making something beloved requires an external action that nurtures attachment, admiration, or devotion.",
  "1325": "حَبَّةٌ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved.\" حَبَّةٌ means \"seed\" or \"grain,\" referring specifically to a small yet essential unit of growth and life. The connection between love and a seed lies in the idea of potential—just as a tiny seed contains within it the ability to grow, flourish, and sustain life, love, when nurtured, develops into something profound and enduring. This highlights the root’s dual association with both emotional and physical sustenance, emphasizing how the smallest elements—whether in nature or relationships—hold the greatest transformative power.",
  "1326": "حَبْلٌ and related words stem from the root ح-ب-ل, with the root verb حَبَلَ meaning \"he tied\" or \"he bound.\" حَبْلٌ means \"rope\" or \"cord,\" emphasizing its use in binding or providing a connection. The root conveys meanings of binding, connecting, and securing. The connection lies in the symbolic role of a rope as a means of support, reliance, or connection, whether physically or metaphorically, highlighting trust and stability.",
  "1327": "حَتْمٌ and related words stem from the root ح-ت-م, with the root verb حَتَمَ meaning \"he decreed.\" حَتْمٌ means \"decree\" or \"inevitable,\" referring to something that is firmly decided or unavoidable. The root conveys meanings of finality, certainty, and the inevitability of outcomes. The connection emphasizes the certainty and unavoidable nature of decrees or events, reflecting the idea of predestination or resolute decisions.",
  "1328": "حَثِيثٌ and related words stem from the root ح-ث-ث, with the root verb حَثَّ meaning \"he hastened.\" حَثِيثٌ means \"swift\" or \"urgent,\" describing rapid or immediate movement or action. The root conveys meanings of urging, hastening, and acting quickly. The connection lies in the emphasis on promptness and rapid progress, highlighting urgency and determination in action.",
  "1329": "حَجَرٌ and related words stem from the root ح-ج-ر, with the root verb حَجَرَ meaning \"he prevented\" or \"he restrained.\" حَجَرٌ means \"stone,\" and the connection lies in the nature of stones as objects that impose boundaries or serve as barriers, symbolizing restraint and immovability. The root’s concept of restriction is reflected in the solidity and permanence of a stone, which prevents movement or access or also creates obstacles or difficulty, much like the act of limiting or prohibiting something.",
  "1330": "الْحَجُّ and related words stem from the root ح-ج-ج, with the root verb حَجَّ meaning \"he went to or visited an object of reverence, veneration, respect, or honor\" or \"he performed pilgrimage.\" الْحَجُّ refers to the sacred pilgrimage to Mecca, a pillar of Islam and a profound act of devotion. The root conveys intent, seeking, and embarking on a purposeful journey. The connection lies in the essence of pilgrimage as more than a physical journey—it is a passage of the soul, a renewal of faith, and a striving toward nearness to Allah (ﷻ). It embodies dedication, humility, and spiritual elevation, symbolizing the believer’s ultimate return to their Creator with sincerity and submission.",
  "1331": "حَجَّ and related words stem from the root ح-ج-ج, and as the root verb, it means \"he went to or visited an object of reverence, veneration, respect, or honor\" or \"he performed pilgrimage.\" It signifies the sacred journey to the Kaaba, an act of profound devotion. The root conveys purpose, intent, and sacred commitment, reflecting the deliberate pursuit of spiritual fulfillment. The connection highlights pilgrimage as more than an obligation—it is a journey of the heart, a renewal of faith, and a submission to Allah (ﷻ). It embodies humility, perseverance, and the longing to draw nearer to the Creator, fulfilling one of the central pillars of Islam.",
  "1332": "حَدَائِقُ and related words stem from the root ح-د-ق, with the root verb حَدَقَ meaning \"he looked at it,\" and أَحْدَقَ meaning \"it surrounded, encompassed, or encircled.\" حَدَائِقُ (plural of حَدِيقَةٌ) means \"gardens.\" The connection lies in the idea of enclosure and definition, as gardens are often enclosed spaces with distinct boundaries, reflecting the root’s meaning of surrounding or encircling. حَدَقَ also relates to the focused gaze, just as gardens captivate attention with their beauty. This highlights themes of protection, order, and careful cultivation, where natural beauty is enclosed and preserved.",
  "1333": "حَدَبٌ and related words stem from the root ح-د-ب, with the root verb حَدِبَ meaning \"it rose\" or \"it grew high.\" حَدَبٌ means \"elevation,\" \"hill,\" or \"high ground.\" The root dimensions emphasize upward motion, prominence, and distinction, with حَدَبٌ reflecting the physical manifestation of these ideas in raised terrain. The connection lies in the concept of standing out through elevation, symbolizing prominence and visibility. Whether describing a natural rise in the land or a metaphorical sense of elevation, it encapsulates the root’s core idea of rising or becoming distinct through height or prominence.",
  "1334": "حَدِيثٌ and related words stem from the root ح-د-ث, with the root verb حَدَثَ meaning \"it was new or recent,\" or \"it came into existence,\" or \"it happened.\" حَدِيثٌ means \"speech,\" \"narration,\" or \"something new.\" The connection lies in the discussion of events or new matters, transforming occurrences into spoken words. It embodies the root's concept of happening by focusing on the communication of recent events, emphasizing the sharing of fresh insights or teachings.",
  "1335": "حَدِيدٌ and related words stem from the root ح-د-د, with the root verb حَدَّ meaning \"he sharpened\" or \"he prevented, impeded, withheld, or restrained.\" حَدِيدٌ means \"iron.\" The connection lies in iron’s hardness, strength, and ability to be sharpened into tools or weapons, embodying the root’s concept of sharpness and limits. Iron is used to create precise edges, reinforcing themes of definition and separation. Just as sharpness marks boundaries and refines function, iron establishes strength and control, reflecting both resilience and restriction. The word also conveys sharpness in perception, as حَدِيدُ البَصَرِ refers to keen sight, highlighting the root’s broader meaning of precision and intensity.",
  "1336": "حَذَرٌ and related words stem from the root ح-ذ-ر, with the root verb حَذِرَ meaning \"he was cautious\" or \"he was vigilant.\" حَذَرٌ means \"caution,\" \"wariness,\" or \"a state of preparation\" and even \"fear.\" The connection lies in being alert to avoid what one perceives as harm, embodying the root's emphasis on vigilance. This state of caution often arises from fear, as one becomes wary in order to avoid danger or negative consequences, heightening their sense of readiness and self-protection.",
  "1337": "حَرامٌ and related words stem from the root ح-ر-م, with the root verb حَرُمَ meaning \"it was forbidden or prohibited,\" and حَرَّمَ meaning \"he forbade, prohibited, or made unlawful.\" حَرامٌ translates as \"forbidden\" or \"sacred,\" referring to something that is either prohibited or holds a sense of sanctity. The connection lies in the concept of sanctity—something that must not be violated due to its sacredness or prohibition. This term highlights the importance of boundaries and respect in moral and religious contexts, emphasizing the protection of what is deemed sacred or off-limits.",
  "1338": "حَرَجٌ and related words stem from the root ح-ر-ج, with the root verb حَرِجَ meaning \"it became narrow\" or \"it became constricted.\" حَرَجٌ means \"difficulty,\" \"distress,\" or \"embarrassment.\" The connection lies in the feeling of constriction or tightness when one faces hardship, reflecting the root's sense of narrowness. It highlights situations where options are limited, causing discomfort or constraint.",
  "1339": "حَرَسًا and related words stem from the root ح-ر-س, with the root verb حَرَسَ meaning \"he guarded\" or \"he preserved.\" حَرَسًا refers to \"guards.\" The connection lies in the root’s emphasis on protection, vigilance, and preservation. Just as guarding involves constant watchfulness to prevent harm, the word حَرَسًا signifies those assigned to ensure safety and security. This reflects the broader concept of preserving something from danger or interference, whether through physical defense or careful monitoring.",
  "1340": "حَرَصَ and related words stem from the root ح-ر-ص, and as the root verb, it means \"he desired vehemently, eagerly, or greedily\" or \"he strove with great effort to attain something.\" The connection lies in the intensity of pursuit, whether driven by longing, necessity, or ambition. Just as one strips away obstacles to obtain what they seek, the root conveys relentless effort and attachment to a goal. It can reflect both persistence in striving for good and an excessive, even harmful, attachment to worldly gains. This dual aspect highlights the contrast between determined effort and unrestrained covetousness, both of which are central to the word’s meaning.",
  "1341": "حَرَضٌ and related words stem from the root ح-ر-ض, with the root verb حَرَضَ meaning \"he became in a corrupt or disordered state,\" \"he was heavily oppressed by disease,\" or \"he became emaciated by grief or excessive love.\" حَرَضٌ means \"corruptness in the body and intellect\" or \"sickness and disease.\" The connection lies in progressive deterioration, whether physical, emotional, or moral. Just as disease weakens the body and grief wears down the soul, حَرَضٌ signifies a state of extreme frailty and depletion, where one is left without vitality or strength. The root also conveys neglect and forsakenness, reflecting how such a condition isolates a person, leaving them vulnerable and in a state of decline.",
  "1342": "حَرُورٌ and related words stem from the root ح-ر-ر, with the root verb حَرَّ meaning \"it became hot.\" حَرُورٌ means \"intense heat\" or \"hot wind.\" The connection lies in the root’s theme of intensity and transformation. Just as heat alters and refines substances, حَرُورٌ represents an extreme force that shapes its surroundings. The hot wind scorches and dries, stripping away moisture, much like how heat removes impurities. This reflects both the physical impact of intense heat and the broader idea of exposure, purification, or endurance under extreme conditions.",
  "1343": "حَرِيرٌ and related words stem from the root ح-ر-ر, with the root verb حَرَّ meaning \"it became hot.\" حَرِيرٌ means \"silk.\" The connection lies in the root’s theme of heat and transformation. Just as heat plays a role in softening and processing materials, silk is produced through an intricate process that transforms raw fibers into a fine, smooth fabric. The word also conveys a sense of delicacy and refinement, as silk is known for its softness and luxurious nature. This reflects the root’s broader association with intensity and change, where heat alters, enhances, and elevates materials to a perfected state.",
  "1344": "حَرِيصٌ and related words stem from the root ح-ر-ص, with the root verb حَرَصَ meaning \"he desired vehemently, eagerly, or greedily\" or \"he strove with great effort to attain something.\" حَرِيصٌ means \"eager,\" \"greedy,\" or \"keen,\" describing someone intensely desirous or overly concerned about something. The connection lies in persistent attachment and strong longing, whether for wealth, status, or any object of pursuit. Just as the root conveys stripping away obstacles to reach a goal, حَرِيصٌ reflects an unyielding focus on acquiring what is sought. This intensity can be positive, as in determination, or negative, as in excessive greed or unhealthy attachment.",
  "1345": "الْحَرِيقُ and related words stem from the root ح-ر-ق, with the root verb حَرَقَ meaning \"he burned\" or \"he scorched.\" الْحَرِيقُ means \"the Blazing Fire,\" specifically referring to the Hellfire. The connection lies in the state or result of burning, embodying the root's sense of combustion. It denotes a destructive fire, emphasizing the intensity and potential devastation caused by flames.",
  "1346": "حَرِيرٌ and related words stem from the root ح-ر-ر, with the root verb حَرَّ meaning \"it became hot.\" حَرِيرٌ means \"silk.\" The connection lies in the root’s theme of heat and transformation. Just as heat softens and alters materials, silk undergoes a process where cocoons are boiled or steamed to soften the fibers, allowing them to be unraveled and refined into smooth fabric. This reflects the root’s broader association with change, refinement, and elevation, where heat plays a key role in turning raw fibers into a delicate, luxurious textile.",
  "1347": "حَرَّمَ and related words stem from the root ح-ر-م, with the root verb حَرُمَ meaning \"it was forbidden or prohibited.\" حَرَّمَ translates as \"he forbade, prohibited, or made unlawful.\" The connection lies in the act of declaring something sacred, embodying the root's essence of prohibition and sanctity. This term reflects the authority to establish boundaries and define what is considered sacred or protected.",
  "1348": "حَرَضٌ and related words stem from the root ح-ر-ض, with the root verb حَرَضَ meaning \"he became in a corrupt or disordered state,\" \"he was heavily oppressed by disease,\" or \"he became emaciated by grief or excessive love.\" حَرَضٌ means \"corruptness in the body and intellect\" or \"sickness and disease.\" The connection lies in progressive deterioration, whether physical, emotional, or moral. Just as disease weakens the body and grief wears down the soul, حَرَضٌ signifies extreme frailty and depletion, where one loses vitality and strength. The root also conveys neglect and forsakenness, reflecting how such a condition isolates a person, leaving them vulnerable and in decline.",
  "1349": "حَرِّقُوا and related words stem from the root ح-ر-ق, with the root verb حَرَقَ meaning \"he burned.\" حَرِّقُوا means \"burn\" or \"set on fire,\" serving as a command to ignite or destroy through fire. The connection is direct, reflecting the root’s core sense of combustion and the transformative, often destructive, nature of fire. It highlights the power and intensity of burning as an act of complete consumption or obliteration.",
  "1350": "حَرْبٌ and related words stem from the root ح-ر-ب, with the root verb حَرَبَ meaning \"he plundered\" and حَرِبَ meaning \"he was angry or violently angry.\" حَرْبٌ means \"war\" or \"battle.\" The connection lies in the root’s association with aggression, destruction, and loss. Plundering involves forcibly taking what belongs to others, while intense anger fuels hostility, both of which are central to war. Just as war results in devastation and upheaval, the root conveys the idea of conflict stripping away stability, leaving disorder and hardship in its wake.",
  "1351": "حَرْثٌ and related words stem from the root ح-ر-ث, with the root verb حَرَثَ meaning \"he plowed,\" \"he tilled the soil,\" or \"he sought to gain sustenance.\" حَرْثٌ means \"cultivation,\" \"tillage,\" or \"agricultural produce.\" The root highlights preparation, effort, and nurturing to achieve growth. Just as tilling the land allows for a future harvest, seeking sustenance involves effort that leads to provision. The concept also extends metaphorically to actions and deeds, where effort determines the outcome, much like planting seeds results in a harvest shaped by care and intention.",
  "1352": "حَرْدٌ and related words stem from the root ح-ر-د, with the root verb حَرَدَ meaning \"he became angry,\" \"he resolved firmly,\" or \"he separated himself.\" حَرْدٌ means \"determination\" or \"a state of anger.\" The connection lies in the strong resolve or emotional intensity that propels one to action, reflecting the root’s themes of firm intention, emotional force, and separation. Just as anger can push someone to act decisively, determination requires an unwavering commitment, often involving a form of mental or emotional isolation to achieve a goal. This highlights how powerful emotions or firm resolve influence decisions and behaviors.",
  "1353": "حَرْفٌ and related words stem from the root ح-ر-ف, with the root verb حَرَفَ meaning \"he altered\" or \"he distorted.\" حَرْفٌ means \"edge\" or \"border.\" An edge marks a boundary where stability ends and change begins, making it a point of alteration or transition. Metaphorically, standing on an edge signifies instability and lack of firmness, causing one to incline, deviate, distort, or alter direction. Just as a person on the edge is vulnerable to falling, a person lacking stability in thought or faith becomes prone to misalignment and uncertainty.",
  "1354": "حَزَنٌ and related words stem from the root ح-ز-ن, with the root verb حَزِنَ meaning \"he was sad\" or \"he grieved.\" حَزَنٌ means \"grief\" or \"sadness,\" referring to an emotional state of distress. The root broadly conveys themes of heaviness, hardship, emotional burden, and the challenges of life. The connection lies in the heaviness of sorrow, directly relating to the root's emphasis on difficulty and struggle. This term reflects the weight of sadness one carries, symbolizing life's trials and the resilience needed to endure them.",
  "1355": "حَسَدٌ and related words stem from the root ح-س-د, with the root verb حَسَدَ meaning \"he envied\" or \"he wished for the deprivation of (something from someone).\" حَسَدٌ means \"envy\" or \"jealousy,\" referring to resentment towards someone else's advantages. The connection lies in coveting what others possess, directly relating to the root's emphasis on envy. Broadly, this root theme reflects the destructive nature of jealousy, highlighting its moral implications and the need for self-restraint to prevent harm to oneself and others.",
  "1356": "حَسَدَ and related words stem from the root ح-س-د, and as the root verb, it means \"he envied\" or \"he wished for the deprivation of (something from someone).\" This verb conveys both envy and the desire for another person to lose what they possess. The connection lies in the harmful nature of envy, which stems from discontentment and leads to resentment. This root theme signifies destructive emotions that disrupt harmony, highlighting the importance of contentment and gratitude as counterbalances to envy and its consequences.",
  "1357": "حَسَنٌ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he was beautiful.\" حَسَنٌ means \"good\" or \"beautiful.\" The root conveys themes of goodness, beauty, and excellence, encompassing both physical and moral qualities. The connection lies in qualities of beauty and goodness, directly relating to the root's emphasis on excellence. This term highlights aesthetic and moral virtues, describing what is pleasing and admirable.",
  "1358": "حَسَنَةٌ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he was beautiful.\" It means \"good deed\" or \"virtue,\" referring to an action that embodies righteousness, moral excellence, or benefit. The connection lies in the link between goodness and beauty, as virtue is both pleasing and praiseworthy. Just as external beauty is recognized for its harmony and refinement, a good deed reflects inner beauty by bringing benefit and righteousness. This root emphasizes striving toward excellence, highlighting that true virtue is cultivated through sincerity, effort, and righteous action, making it a representation of both inherent goodness and its outward expression.",
  "1359": "حَسُنَ and related words stem from the root ح-س-ن, and as the root verb, it means \"he was good\" or \"he was beautiful.\" The root encompasses themes of inherent goodness, beauty, and moral excellence, reflecting high standards in character and appearance. The connection lies in the inherent quality of being commendable, directly relating to the root's focus on excellence. This term emphasizes the pursuit of superior qualities in both inner character and outer appearance.",
  "1360": "حَسِبَ and related words stem from the root ح-س-ب, and as the root verb, it means \"he reckoned,\" or \"he calculated.\" This verb conveys the act of considering or estimating, reflecting a mental calculation. The connection lies in the cognitive process of assessment, directly relating to the root's focus on computation. This term highlights the human capacity for reasoning and evaluation.",
  "1361": "حَسِيبٌ and related words stem from the root ح-س-ب, with the root verb حَسِبَ meaning \"he reckoned\" or \"he calculated.\" حَسِيبٌ means \"reckoner\" or \"noble,\" highlighting the connection between accurate accounting and honor. ٱلْحَسِيبُ, one of Allah’s (ﷻ) perfect names, means \"The Reckoner\" or \"The Sufficient,\" signifying His role in accounting for every action and providing for every need. The root conveys themes of calculation, judgment, honor, and sufficiency. The connection emphasizes Allah’s (ﷻ) complete awareness of our deeds, His perfect judgment, and His sufficiency as a provider and protector, reminding us to rely on His justice and care in all matters.",
  "1362": "حَسِيرٌ and related words stem from the root ح-س-ر, with the root verb حَسَرَ meaning \"he was tired or fatigued,\" and حَسِرَ meaning \"he felt grief, sorrow, or regret.\" حَسِيرٌ means \"weary\" or \"exhausted,\" describing a state of depletion, whether physical, emotional, or mental. The connection lies in progressive weariness that results from continuous effort, hardship, or sorrow, directly reflecting the root’s emphasis on fatigue and loss of strength. This term conveys the burden of exhaustion, whether from labor, adversity, or deep emotional strain.",
  "1363": "حَسِيسٌ and related words stem from the root ح-س-س, with the root verb حَسَّ meaning \"he was tender or compassionate,\" and أَحَسَّ meaning \"he perceived\" or \"he sensed,\" reflecting heightened awareness or deliberate perception. حَسِيسٌ translates as \"whisper\" or \"faint sound,\" referring to a subtle auditory perception. The connection lies in the root’s emphasis on sensitivity and attentiveness, as it captures the ability to detect even the faintest stimuli through sound. This term highlights the nuanced aspect of perception, aligning with the root’s themes of tenderness, subtlety, and impact, where even the slightest sound evokes a sense of awareness and focus.",
  "1364": "حَسْبٌ and related words stem from the root ح-س-ب, with the root verb حَسِبَ meaning \"he reckoned\" or \"he calculated.\" حَسْبٌ means \"enough\" or \"sufficiency,\" indicating that which satisfies. The connection lies in calculating what is adequate, directly relating to the root's focus on reckoning. This root conveys themes encompassing notions of calculation, sufficiency, and trust in adequacy. This term emphasizes contentment and reliance, often used in expressions like \"Allah (ﷻ) is sufficient for us.\"",
  "1365": "حَسْرَةٌ and related words stem from the root ح-س-ر, with the root verb حَسَرَ meaning \"he was tired or fatigued,\" and حَسِرَ meaning \"he felt grief, sorrow, or regret.\"  حَسْرَةٌ translates as \"regret\" or \"sorrow,\" describing deep remorse over something lost or unattained. The connection lies in emotional and mental exhaustion caused by regret, reflecting the weariness conveyed by the root. Just as حَسَرَ involves uncovering or exposing, حَسْرَةٌ symbolizes the pain of realizing missed opportunities and the despair of irreversible loss.",
  "1366": "حَسْرَتَنَا and related words stem from the root ح-س-ر, with the root verb حَسَرَ meaning \"he was tired or fatigued,\" and حَسِرَ meaning \"he felt grief, sorrow, or regret.\" حَسْرَتَنَا translates as \"our regret,\" as in يَا حَسْرَتَنَا, meaning \"Oh! our regret.\" The connection lies in deep sorrow and emotional exhaustion, reflecting the root’s themes of weariness and lamentation. Just as fatigue weakens the body, regret weighs heavily on the heart and mind, emphasizing the lasting burden of missed opportunities, loss, or past mistakes.",
  "1367": "حَسْرَتَا and related words stem from the root ح-س-ر, with the root verb حَسَرَ meaning \"he was tired or fatigued,\" and حَسِرَ meaning \"he felt grief, sorrow, or regret.\" حَسْرَتَا translates as \"my regret,\" as in يَا حَسْرَتَا, meaning \"Oh! my regret.\" The connection lies in deep sorrow and emotional depletion, reflecting the root’s themes of weariness and lamentation. Just as exhaustion drains physical strength, regret burdens the heart and mind, highlighting the weight of lost opportunities and the lasting impact of past actions.",
  "1368": "حَشَرَ and related words stem from the root ح-ش-ر, and as the root verb, it means \"he congregated or collected together\" or \"he made [them] go forth, collected together, from one place to another.\" This verb conveys bringing people or things together for a purpose. The connection lies in physical or metaphorical gathering, directly relating to the root’s focus on assembly and movement. The term is especially significant in discussions about resurrection and the afterlife, referring to the gathering of souls for judgment or accountability.",
  "1369": "حَشْرٌ and related words stem from the root ح-ش-ر, with the root verb حَشَرَ meaning \"he congregated or collected together\" or \"he made [them] go forth, collected together, from one place to another.\" حَشْرٌ means \"gathering\" or \"assembly,\" referring to the act of collecting together. The root also encompasses the idea of expelling or driving out and is even used to describe creatures like insects, which gather or move collectively in multitudes. This connection highlights the root's broader theme of gathering in both structured and instinctual ways. This terms is also used to describe the ultimate gathering on the Day of Judgment, emphasizing the purposeful and inevitable assembly of all beings by Allah (ﷻ). ",
  "1370": "حَصَادٌ and related words stem from the root ح-ص-د, with the root verb حَصَدَ meaning \"he harvested\" or \"he reaped.\" حَصَادٌ means \"harvest\" or \"reaping,\" referring specifically to what remains on the ground among the lower parts of the stalks. The connection lies in the culmination of effort, leading to the gathering of crops, directly relating to the root's emphasis on cutting down or collecting. In the Qur'an, it is mentioned in the context of generosity, emphasizing giving portions of the harvest to the poor, including both handfuls of grains and allowing them to collect what is left on the ground.",
  "1371": "حَصَبٌ and related words stem from the root ح-ص-ب, with the root verb حَصَبَ meaning \"he pelted\" or \"he threw stones.\" حَصَبٌ means \"stones,\" or \"fuel,\" or \"firewood,\" often referring to materials thrown into a fire and symbolizing the fuel of Hellfire. The root also encompasses the idea of aggressive actions, such as pelting or hurling, which ties to the violent and relentless nature of casting materials into flames. This connection highlights the imagery of Hellfire as a place of punishment, where fuel is continuously added, emphasizing the intense and perpetual nature of the torment.",
  "1372": "حَصَدَ and related words stem from the root ح-ص-د, with the root verb حَصَدَ meaning \"he harvested,\" \"he reaped,\" or \"he cut down.\" While it primarily refers to cutting and gathering crops, the root also conveys themes of destruction, such as cutting down enemies, and moral accountability, symbolizing reaping the consequences of one’s actions. Additionally, it relates to what remains after a harvest, highlighting generosity and provision for others. These meanings connect the act of harvesting to broader themes of effort, judgment, and redistribution.",
  "1373": "حَصُورٌ and related words stem from the root ح-ص-ر, with the root verb حَصَرَ meaning \"he confined,\" \"he restricted,\" or \"he besieged.\" حَصُورٌ means \"chaste,\" \"self-restrained,\" or \"abstinent.\" The connection lies in the individual's ability to confine or restrain themselves from indulgent desires, directly relating to the root's emphasis on limitation and control. This term embodies the virtue of self-discipline and the moral strength to resist temptations by imposing personal boundaries.",
  "1374": "حَصِرَتْ and related words stem from the root ح-ص-ر, with the root verb حَصَرَ meaning \"he confined,\" \"he restricted,\" or \"he besieged,\" and حَصِرَ meaning \"he was distressed\" or \"he felt constricted.\" حَصِرَتْ means \"she or it became distressed\" or \"she or it became confined,\" reflecting a state of emotional or physical limitation. The root conveys themes of restriction, enclosure, and tightness, whether externally imposed or internally felt. This term highlights both physical confinement and emotional distress, symbolizing situations where options are narrowed or obstacles cause overwhelming pressure, directly connecting to the root's essence of being restricted or hemmed in.",
  "1375": "حَصِيدٌ and related words stem from the root ح-ص-د, with the root verb حَصَدَ meaning \"he harvested,\" \"he reaped,\" or \"he cut down.\" حَصِيدٌ means \"that which is harvested\" or \"mown down,\" representing the outcome of harvesting or reaping. The root also conveys themes of finality and destruction, as حَصِيدٌ can metaphorically refer to something annihilated or obliterated, such as fields or lives cut down. This connection ties the physical act of harvesting to broader concepts of completion, accountability, and the end of life or growth.",
  "1376": "حَصِيرٌ and related words stem from the root ح-ص-ر, with the root verb حَصَرَ meaning \"he confined,\" \"he restricted,\" or \"he besieged.\" حَصِيرٌ means \"mat\" or \"woven mat,\" often used for sitting or sleeping. The connection lies in the mat's confined and bounded nature, as it defines a limited space for rest or prayer, directly relating to the root's emphasis on restriction and enclosure. Additionally, حَصِيرٌ can also refer to a \"prison,\" further highlighting the theme of confinement.",
  "1377": "حَصْحَصَ and related words stem from the root ح-ص-ص, with the root verb حَصَّ meaning \"he cut off from it.\" حَصْحَصَ is an emphatic form meaning \"it became distinct, apparent, or manifest\" after having been concealed. The connection lies in the idea that what is separated or cut off eventually emerges clearly, as the portion of truth becomes undeniable. This term highlights the revealing of hidden realities, emphasizing the transition from ambiguity or concealment to clarity and absolute certainty, directly reflecting the root's essence of division and distinction.",
  "1378": "حَضَرَ and related words stem from the root ح-ض-ر, with the root verb حَضَرَ meaning \"he was present,\" \"he attended,\" or \"he came.\" This verb conveys the action of arriving or being in a place, emphasizing the state of presence. It reflects the concept of participation or involvement in events or gatherings, directly connecting to the root's essence of attendance and immediacy. The term captures the importance of being present both physically and attentively.",
  "1379": "حَطَبٌ and related words stem from the root ح-ط-ب, with the root verb حَطَبَ meaning \"he gathered firewood\" or \"he collected wood.\" حَطَبٌ means \"firewood\" or \"wood collected for fuel.\" This reflects the physical material gathered for kindling fires, directly connecting to the root's emphasis on collecting wood. The term symbolizes the preparation for warmth or cooking but can also metaphorically represent fuel for destructive purposes, as in the context of fueling conflicts or spreading harm.",
  "1380": "حَظٌّ and related words stem from the root ح-ظ-ظ, with the root verb حَظَّ meaning \"he was fortunate,\" or \"he was possessed of good fortune.\" حَظٌّ means \"fortune,\" \"share,\" or \"portion.\" This reflects the concept of receiving a part of something or experiencing favorable circumstances, directly connecting to the root's emphasis on allotted shares. The term encompasses both material and intangible blessings.",
  "1381": "حَفَدَةٌ and related words stem from the root ح-ف-د, with the root verb حَفَدَ meaning \"he hastened in service,\" \"he served eagerly,\" or \"he was devoted.\" حَفَدَةٌ means \"servants,\" \"helpers,\" or \"grandchildren.\" This reflects those who serve or assist with zeal and dedication, directly connecting to the root's emphasis on quick and willing service. The term can refer to offspring who support their parents, highlighting themes of familial devotion and dutiful assistance.",
  "1382": "حَفَفْنَا and related words stem from the root ح-ف-ف, with the root verb حَفَّ meaning \"he went round about,\" \"he compassed,\" or \"he surrounded.\" حَفَفْنَا means \"We surrounded\" or \"We encompassed,\" reflecting the act of encompassing or enclosing something entirely. The root conveys themes of encircling, encompassing, or bordering, often with a sense of close attention or protection. This term highlights the idea of creating boundaries or protective enclosures, emphasizing completeness and the deliberate nature of the act. The connection to the root highlights Allah's (ﷻ) ability to surround and safeguard, as well as the sense of order and harmony in creation.",
  "1383": "حَفِظَ and related words stem from the root ح-ف-ظ, with the root verb حَفِظَ meaning \"he guarded,\" \"he protected,\" \"he preserved,\" or \"he memorized.\" This verb conveys the action of safeguarding or keeping something intact, directly connecting to the root's emphasis on protection. It also encompasses the act of memorization, highlighting the internalization and preservation of knowledge.",
  "1384": "حَفِيظٌ and related words stem from the root ح-ف-ظ, with the root verb حَفِظَ meaning \"he guarded,\" \"he protected,\" or \"he preserved.\" The root conveys themes of vigilant care, meticulous safeguarding, and maintaining something valuable. حَفِيظٌ means \"guardian\" or \"protector,\" emphasizing active and continuous protection. ٱلْحَفِيظُ, is one of Allah’s (ﷻ) perfect names, meaning \"The Guardian\" or \"The Preserver,\" reflecting His role in protecting and maintaining His creation. The connection to حَفِظَ highlights Allah’s (ﷻ) comprehensive care and protection, reminding us of the trust we place in His safeguarding and the responsibility to preserve the blessings He has entrusted to us.",
  "1385": "حَفِيٌّ and related words stem from the root ح-ف-ي, with the root verb حَفِيَ meaning \"he inquired earnestly,\" \"he showed much honor,\" or \"he was deeply attentive and concerned.\" حَفِيٌّ refers to someone \"gracious,\" \"kind,\" or \"attentive,\" emphasizing genuine care and thoughtfulness. The root conveys attentiveness, solicitude, and careful inquiry, highlighting an active interest in someone's well-being. This reflects a sense of deep concern and honor in interactions, fostering meaningful relationships based on earnest care and sincerity.",
  "1386": "حَقِيقٌ and related words stem from the root ح-ق-ق, with the root verb حَقَّ meaning \"it was true,\" \"it became established,\" or \"it was necessitated.\" حَقِيقٌ means \"worthy,\" \"deserving,\" or \"appropriate,\" indicating a quality that is firmly tied to truth and legitimacy. The connection lies in the inherent alignment with certainty and justice, reflecting the root’s emphasis on rightful acknowledgment. This term conveys the idea of something being intrinsically suitable or justified, highlighting what is truly deserving of recognition or obligation.",
  "1387": "حَقٌّ and related words stem from the root ح-ق-ق, with the root verb حَقَّ meaning \"it was true,\" \"it became established,\" or \"it was necessitated.\" حَقٌّ means \"truth,\" \"right,\" or \"justice,\" embodying certainty, rightful entitlement, and the fulfillment of obligations. ٱلْحَقُّ, one of Allah’s (ﷻ) perfect names, means \"The Absolute Truth\" or \"The Reality,\" signifying that Allah (ﷻ) is the ultimate source of truth and justice. This name signifies that everything Allah (ﷻ) decrees is absolute, guiding creation with perfect wisdom and establishing all matters with complete justice and precision.",
  "1388": "حَقَّ and related words stem from the root ح-ق-ق, and as the root verb, it means \"it was true,\" \"it became established,\" or \"it was necessitated.\" This verb conveys the realization of truth and the fulfillment of rightful claims. The connection lies in how truth and justice are not merely abstract concepts but become firmly established in reality. This highlights the certainty of rightful matters and the fulfillment of obligations, reinforcing sincerity and just outcomes.",
  "1389": "حَكَمٌ and related words stem from the root ح-ك-م, with the root verb حَكَمَ meaning \"he judged,\" \"he decreed,\" or \"he governed.\" حَكَمٌ means \"judge\" or \"arbitrator,\" reflecting the root's emphasis on justice, balance, and decisive governance. The root also carries meanings of restraining, controlling, ensuring firmness, and precision in decision-making, highlighting the themes of authority and wisdom. ٱلْحَكَمُ, one of Allah’s (ﷻ) perfect names, means \"The Judge\" or \"The Arbitrator,\" signifying His role as the ultimate and perfect authority who resolves all matters with flawless justice and wisdom.",
  "1390": "حَكَمَ and related words stem from the root ح-ك-م, and as the root verb, it means \"he judged,\" \"he governed,\" or \"he decided.\" This verb embodies the act of making judgments, governing affairs, or exercising authority. The connection lies in the application of wisdom and discernment to make decisions, aligning with the root's emphasis on judgment and governance. This term highlights the importance of wise decision-making and just governance, highlighting the role of wisdom in leadership and justice.",
  "1391": "حَكِيمٌ and related words stem from the root ح-ك-م, with the root verb حَكَمَ meaning \"he judged\" or \"he governed.\" حَكِيمٌ means \"wise\" or \"full of wisdom,\" reflecting the understanding and good judgment needed for sound decisions and governance. ٱلْحَكِيمُ, one of Allah's (ﷻ) perfect names, means \"The All-Wise,\" signifying His perfect wisdom in all actions and decrees. It emphasizes that everything Allah (ﷻ) does is based on profound wisdom and justice, even if beyond human understanding. The connection to حَكَمَ highlights divine authority and wisdom, inspiring trust in Allah’s (ﷻ) decrees and encouraging us to pursue fairness and good judgment in our own actions.",
  "1392": "حَلَائِلُ and related words stem from the root ح-ل-ل, with the root verb حَلَّ meaning \"he untied\" or \"he loosened.\" From this comes أَحَلَّ, meaning \"he made lawful,\" and تَحَلَّلَ, meaning \"he became free from restriction.\" حَلَائِلُ (plural of حَلِيلَةٌ) means \"wives.\" The connection lies in the lawful untying of social bonds that permits marriage, transforming previously forbidden relationships into permissible unions. This term highlights the sanctity and legitimacy of marriage in Islam, emphasizing the divine facilitation of companionship and family through lawful means.",
  "1393": "حَلَالٌ and related words stem from the root ح-ل-ل, with the root verb حَلَّ meaning \"he untied\" or \"he loosened.\" From this comes أَحَلَّ, meaning \"he made lawful,\" and تَحَلَّلَ, meaning \"he became free from restriction.\" حَلَالٌ means \"lawful\" or \"permissible.\" The root dimensions include untying, resolving, and making accessible, emphasizing removing restrictions and transitioning from prohibition to permissibility. The connection lies in untying knots, symbolizing opening pathways to what is lawful. حَلَالٌ reflects what is made permissible by Allah (ﷻ), guiding believers toward lawful choices while ensuring harmony between divine boundaries and rightful freedom.",
  "1394": "حَلَفَ and related words stem from the root ح-ل-ف, and as the root verb, it means \"he swore an oath.\" This verb signifies making a solemn commitment, and when invoking the name of Allah (ﷻ), it carries great weight and seriousness in Islam. The root also conveys meanings of firmness, determination, and binding obligation, highlighting how an oath is not merely a statement but a pledge of truth and accountability. The connection lies in the moral responsibility and integrity required when swearing, emphasizing the root’s focus on truthfulness, commitment, and the sacred nature of one's word.",
  "1395": "حَلَلْتُمْ and related words stem from the root ح-ل-ل, with the root verb حَلَّ meaning \"he untied\" or \"he loosened.\" From this comes أَحَلَّ, meaning \"he made lawful,\" and تَحَلَّلَ, meaning \"he became free from restriction.\" حَلَلْتُمْ means \"you (all) have entered\" or \"you are released,\" signifying a transition into permissibility. The connection lies in untying or loosening restrictions, marking the shift from prohibition to allowance. It signifies release into a lawful state, where what was once restricted is now permissible, reflecting the root’s focus on removal of restrictions and lawful transition.",
  "1396": "حَلِيمٌ and related words stem from the root ح-ل-م, with the root verb حَلُمَ meaning \"he was forbearing,\" \"patient,\" or \"exercised self-restraint.\" حَلِيمٌ means \"forbearing\" or \"gentle,\" reflecting the root's emphasis on restraining anger and showing patience. The name ٱلْحَلِيمُ, one of Allah’s (ﷻ) perfect names, signifies His infinite patience and forbearance, as He delays punishment, giving time for repentance. This name reminds us to emulate Allah’s (ﷻ) forbearance by exercising patience and kindness in our interactions, embodying His attribute of gentleness.",
  "1397": "حَلَّافٌ and related words stem from the root ح-ل-ف, with the root verb حَلَفَ meaning \"he swore an oath.\" The word حَلَّافٌ is an intensive form meaning \"habitual swearer\" or \"one who swears frequently.\" The root also conveys meanings of firmness, binding commitment, and affirming sincerity with strong resolve. The connection lies in how this word describes a person who frequently engages in swearing oaths, often diminishing the gravity and seriousness emphasized by the root. This term highlights the contrast between the intended solemnity of oaths and the misuse that arises from habitual swearing, serving as a reminder of the weight of one’s word and the importance of sincerity.",
  "1398": "حَمَأٌ and related words stem from the root ح-م-أ, with the root verb حَمِئَ meaning \"it (water) was mixed with black mud.\" حَمَأٌ means \"mud,\" particularly of a dark, murky nature. The root dimensions emphasize thickness, heaviness, and an unrefined state, reflecting the earth in its raw form. The connection lies in its role as the fundamental substance of creation, highlighting humanity’s origin from humble, earthy beginnings. It emphasizes life’s physical nature and the humility of human origin, reinforcing the contrast between earthly composition and the higher purpose Allah (ﷻ) has ordained for creation.",
  "1399": "حَمَلَ and related words stem from the root ح-م-ل, and as the root verb, it means \"he carried\" or \"he bore.\" The connection is straightforward, involving the act of carrying or bearing something from one place to another. This term encompasses both physical carrying and metaphorical bearing of responsibilities or burdens. It reflects the human experience of supporting others and managing one's own obligations.",
  "1400": "حَمُولَةٌ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" حَمُولَةٌ means \"beasts of burden\" or \"loads carried by animals.\" The connection lies in referring to animals like camels or oxen that carry heavy loads, essential for transportation and trade in ancient times. It highlights humanity's reliance on these creatures and highlights themes of provision, journeying, and the movement of goods and people.",
  "1401": "حَمِئَةٌ and related words stem from the root ح-م-أ, with the root verb حَمِئَ meaning \"it (water) was mixed with black mud.\" حَمَأٌ means \"mud,\" while حَمِئَةٌ means \"muddy\" or \"containing clay.\" The connection lies in describing something as dense, murky, and immersed in mud, emphasizing its unrefined and obscured nature. This reflects themes of concealment, depth, and an unclear state, where something is covered or enshrouded by its surroundings, reinforcing the root’s association with heaviness and obscurity.",
  "1402": "حَمِيدٌ and related words stem from the root ح-م-د, with the root verb حَمِدَ meaning \"he praised\" or \"he thanked.\" حَمِيدٌ means \"praiseworthy\" or \"worthy of praise,\" describing one deserving commendation for admirable qualities or actions. ٱلْحَمِيدُ, one of Allah’s (ﷻ) perfect names, means \"The Praiseworthy,\" emphasizing His absolute perfection and the continuous praise He receives from all creation. This name signifies that Allah (ﷻ) is praised in all circumstances, not only for His countless blessings but also for His perfect wisdom, justice, and mercy.",
  "1403": "حَمِيمٌ and related words stem from the root ح-م-م, with the root verb حَمَّ meaning \"it became hot\" or \"he heated.\" حَمِيمٌ means \"scalding water\" or \"intimate relation.\" The connection lies in the intensity implied by heat, representing either the scalding nature of boiling water or the intense emotions of close companionship. In the Qur'an, حَمِيمٌ often refers to the boiling water of punishment in Hellfire, symbolizing severe torment, while in another context, it denotes a close friend who shares in one's joys and sorrows.",
  "1404": "حَمِيَّةٌ and related words stem from the root ح-م-ي, with the root verb حَمَى meaning \"he protected from harm,\" or \"he made forbidden,\" and حَمِيَ meaning \"it was hot,\" or \"he was enraged,\" or \"it was forbidden.\" حَمِيَّةٌ means \"anger, mockery, ridicule, or disrespect,\" reflecting intense emotions driven by pride or fervent defense. The root connects to themes of heat and intensity, mirroring the internal fervor and protective instincts that fuel such emotions. In the Qur'an, حَمِيَّةٌ is associated with misguided zeal or arrogance, particularly linked to tribalism and the times of ignorance. It serves as a warning against excessive pride and wrongful defense of actions or affiliations, highlighting the dangers of unrestrained passion.",
  "1405": "حَمَّالَةٌ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" حَمَّالَةٌ is an intensive form meaning \"carrier\" or \"porter,\" describing someone who habitually or excessively carries loads. In the Qur'an, it refers to حَمَّالَةَ الْحَطَبِ (\"the carrier of firewood\"), which holds a dual meaning: symbolizing a person who spreads harmful gossip or fuels discord—akin to one who carries wood to stoke a fire—and the literal act of carrying firewood. This highlights the destructive nature of such behavior and its impact on individuals and communities.",
  "1406": "حَمْدٌ and related words stem from the root ح-م-د, with the root verb حَمِدَ meaning \"he praised\" or \"he thanked.\" حَمْدٌ means \"praise\" or \"gratitude,\" signifying the highest form of acknowledgment and appreciation. The connection is direct, embodying both praise and thanks, particularly towards Allah (ﷻ), in full recognition of His perfection and boundless blessings. It expresses not only admiration but also deep reverence and submission, arising from awareness of Allah’s (ﷻ) greatness, mercy, and wisdom. It is at the heart of devotion, as reflected in \"ٱلْحَمْدُ لِلَّهِ,\" meaning \"All praise is due to Allah (ﷻ),\" an expression affirming that every blessing and moment of gratitude belongs solely to Him.",
  "1407": "حَمْلٌ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" حَمْلٌ means \"load,\" \"burden,\" or \"pregnancy.\" The connection lies in what is being carried, whether it's a physical object, a responsibility, or an unborn child. This term embodies the concept of bearing weight, whether tangible or intangible, and reflects on the significance and challenges of carrying such loads.",
  "1408": "حَناجِرُ and related words stem from the root ح-ن-ج-ر, meaning \"throats,\" a vital part for speech and swallowing. In the Qur'an, it is used metaphorically to depict extreme fear or anxiety, as in \"hearts reaching the throats,\" symbolizing the constriction of breath and speech during intense emotional states. The word is also linked to the root ح-ج-ر, where حَجَرَ means \"he prevented or hindered,\" and حَجَرٌ means \"stone,\" emphasizing the idea of obstruction or restriction. This connection illustrates how the throat, in moments of fear or distress, can feel immobilized or constricted, akin to the rigidity of stone.",
  "1409": "حَنَانٌ and related words stem from the root ح-ن-ن, with the root verb حَنَّ meaning \"he yearned\" or \"he was compassionate.\" حَنَانٌ means \"compassion,\" \"affection,\" or \"mercy.\" The root conveys themes of deep emotional connection, warmth, and tenderness, emphasizing a profound care and longing for others. It reflects the emotional bond that fosters kindness and empathy. In a broader sense, حَنَانٌ encapsulates the divine attribute of mercy, higihlighting the importance of nurturing relationships and showing compassion to others.",
  "1410": "حَنِيذ and related words stem from the root ح-ن-ذ, with the root verb حَنَذَ meaning \"he roasted\" or \"he roasted meat on embers.\" حَنِيذ means \"roasted\" or \"grilled,\" typically referring to meat. The connection lies in the method of cooking meat by direct exposure to heat. This term evokes images of hospitality and generosity, as roasted meat was often prepared for honored guests, highlighting cultural values of kindness and sharing.",
  "1411": "حَنِيفٌ and related words stem from the root ح-ن-ف, with the root verb حَنَفَ meaning \"he inclined (toward truth)\" or \"he turned away from error.\" حَنِيفٌ means \"upright,\" \"true in faith,\" or \"monotheistic.\" The root conveys themes of deliberate inclination, emphasizing a conscious choice to turn toward truth and righteousness and away from falsehood or deviation. This inclination reflects a deep commitment to seeking what is pure and correct. The term also connects to broader root dimensions, such as steadfastness and determination in maintaining integrity and devotion.",
  "1412": "حَوَارِيُّونَ and related words stem from the root ح-و-ر, with the root verb حَارَ meaning \"he returned or reverted.\" حَوَارِيٌّ means \"one who whitens clothes or garments by washing and beating them,\" which was the original trade of the disciples of Prophet Yeshua (ﷺ). They were given the name حَوَارِيُّونَ because of this trade. The root conveys themes of returning and purification, symbolizing their role in returning to the truth, maintaining purity of faith, and faithfully following Prophet Yeshua (ﷺ) and his mission.",
  "1413": "حَوايا and related words stem from the root ح-و-ي, with the root verb حَوَىٰ meaning \"he collected, brought, or gathered together,\" or \"it became contracted or wasted away,\" referring to a state of being curved and compressed or withered. حَوايا (plural of حَوِيَّة) means \"intestines\" or \"entrails.\" The root conveys themes of containment, contraction, and enclosure, reflecting how the intestines gather, hold, and process what passes through them. This connection highlights the idea of internal compression and curved structure, emphasizing the role of the intestines in enclosing and processing what is collected within.",
  "1414": "حَوْلٌ and related words stem from the root ح-و-ل, with the root verb حَالَ meaning \"he or it changed or transformed,\" \"he or it moved or shifted,\" or \"he or it intervened or came between.\" حَوْلٌ means \"year,\" \"power,\" or \"strength,\" and can also mean \"around\" or \"surrounding,\" referring to the space around something. The root reflects themes of cyclical change (as in the passage of a year), strength to bring about change, and encompassing presence (as in being around something). The connection lies in the interplay between temporal cycles, the capacity for influence or movement, and the protective or surrounding nature of strength and presence.",
  "1415": "حَيَّ and related words stem from the root ح-ي-ي, with the root verb حَيِيَ meaning \"he was shy\" or \"he felt modesty,\" and حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" The root conveys themes of life, renewal, and awareness. The connection lies in the idea that life and modesty are intertwined—just as life is sustained through vitality and renewal, modesty reflects an inner awareness that refines one’s actions and interactions. Both meanings emphasize a state of presence, whether through physical life or a conscious sense of humility and restraint.",
  "1416": "حَيَاةٌ and related words stem from the root ح-ي-ي, with the root verb حَيِيَ meaning \"he was shy\" or \"he felt modesty,\" and حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" حَيَاةٌ translates as \"life\" or \"existence,\" referring to the state of being alive. The root conveys themes of vitality, renewal, and consciousness. The connection lies in the idea that life is not merely existence but a state of continuous renewal and awareness. Just as modesty reflects an inner consciousness that refines behavior, life is sustained through a constant process of growth and regeneration, emphasizing both physical vitality and mindful presence.",
  "1417": "حَيَوانٌ and related words stem from the root ح-ي-ي, with the root verb حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" حَيَوانٌ translates as \"life\" or \"living,\" representing the essence of dynamic and enduring vitality. The root conveys themes of continuous renewal, movement, and sustained existence. The connection lies in how life is not static but constantly regenerating, much like liveliness and freshness imply an ongoing state of motion and renewal, emphasizing the ever-flowing nature of existence.",
  "1418": "حَيٌّ and related words stem from the root ح-ي-ي, with the root verb حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" حَيٌّ means \"alive\" or \"living.\" The root conveys themes of vitality, renewal, and continuous existence. ٱلْحَيُّ, one of Allah’s (ﷻ) perfect names, means \"The Ever-Living,\" signifying His eternal existence and absolute self-sufficiency. The connection lies in how all created beings experience change and dependence, whereas Allah (ﷻ) is beyond limitation, unchanging, and independent, emphasizing the need to seek vitality and sustenance from Him alone.",
  "1419": "حَيَّا and related words stem from the root ح-ي-ي, with the root verb حَيِيَ meaning \"he was shy\" or \"he felt modesty,\" and حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" حَيَّا means \"he greeted,\" \"he honored or showed regard,\" or \"he acted with consideration.\" The root conveys themes of respect, renewal, and awareness. Greeting someone is more than just an exchange of words—it brings warmth, strengthens relationships, and creates an atmosphere of kindness and energy. Just as modesty reflects care for others and liveliness brings renewal, greeting embodies both, showing respect and fostering a connected and considerate community.",
  "1420": "حَيَّةٌ and related words stem from the root ح-ي-ي, with the root verb حَيَّ meaning \"he lived\" or \"he became fresh or lively.\" حَيَّةٌ translates as \"snake\" or \"serpent.\" The root conveys themes of movement, vitality, and continuous motion. The connection lies in the snake’s agile and ever-shifting nature, as it moves with fluidity and precision. Its ability to glide effortlessly and remain alert reflects a controlled liveliness, aligning with the root’s theme of sustained motion and responsiveness.",
  "1421": "The particle حَيْثُ means \"where\" or \"wherever,\" specifying location, circumstance, or situation. It functions as an adverb of place and condition, indicating location, cause, or context depending on its usage in a sentence. It connects actions or events to their specific setting, providing contextual grounding. The word conveys meanings of place, reasoning, and temporal reference, emphasizing how events unfold within defined locations or circumstances.",
  "1422": "حَيْرَانُ and related words stem from the root ح-ي-ر, with the root verb حَارَ meaning \"he was perplexed,\" \"he was bewildered,\" \"he changed his state,\" or \"he wavered or hesitated.\" حَيْرَانُ means \"confused or perplexed, unable to see the right course.\" The root reflects themes of uncertainty, hesitation, and being at a loss, emphasizing a state of mental disorientation. The connection lies in the experience of internal conflict or doubt, where one struggles to find direction, wavering between choices without clarity.",
  "1423": "حُبُكٌ and related words stem from the root ح-ب-ك, with the root verb حَبَكَ meaning \"he wove.\" حُبُكٌ means \"woven structures\" or \"paths,\" referring to intricately designed or tightly constructed formations. The root conveys meanings of weaving, binding, and intricate construction. The connection lies in the detailed and meticulous weaving, symbolizing the harmony and precision in the design of the universe.",
  "1424": "حُبٌّ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved.\" حُبٌّ means \"love,\" referring to deep affection, attachment, or desire for someone or something. The root conveys themes of nurturing, desirability, and connection, symbolizing an essential and foundational bond. The connection lies in the idea of love as a powerful force that binds and sustains relationships, much like a seed nurtures life and growth, making this word a profound expression of emotional and spiritual connection.",
  "1425": "حُجُرَةٌ and related words stem from the root ح-ج-ر, with the root verb حَجَرَ meaning \"he prevented\" or \"he restrained.\" حُجُرَةٌ means \"room\" or \"chamber.\" The connection lies in the room being an enclosed space that restrains and prevents access, reflecting the root's sense of restriction. A room sets boundaries, offering privacy and protection by limiting entry, thus embodying the concept of confinement inherent in the root.",
  "1426": "حُجُورٌ and related words stem from the root ح-ج-ر, with the root verb حَجَرَ meaning \"he prevented\" or \"he restrained.\" حُجُورٌ is the plural of حِجْرٌ, meaning \"laps.\" The connection lies in the lap as a place of closeness and protection, symbolizing a secure area that holds and prevents harm. Just as the root conveys meanings of restraint and prohibition, the lap reflects this by providing a safe and nurturing space, emphasizing the protective nature of care and guardianship.",
  "1427": "حُجَّةٌ and related words stem from the root ح-ج-ج, with the root verb حَجَّ meaning \"he performed pilgrimage\" or \"he overcame another in an argument, plea, proof, or testimony.\" حُجَّةٌ means \"argument,\" referring to something that justifies or substantiates a claim. The root conveys assertion, proof, and the act of prevailing through evidence. Just as حَجَّ signifies a deliberate journey toward truth and submission in pilgrimage, حُجَّةٌ represents the journey of establishing truth through clear reasoning and decisive proof. Both meanings reflect a purposeful striving—whether in devotion to Allah (ﷻ) or in the pursuit of clarity and conviction.",
  "1428": "حُدُودٌ and related words stem from the root ح-د-د, with the root verb حَدَّ meaning \"he sharpened\" or \"he prevented, impeded, withheld, or restrained.\" حُدُودٌ means \"limits,\" \"boundaries,\" or \"ordinances.\" The connection lies in the act of defining and restricting, much like a sharpened edge marks a clear division. Boundaries prevent transgression, ensuring order and discipline. Just as something sharp separates and restrains, limits establish structure, guiding actions within set parameters. This reflects control, protection, and the enforcement of established guidelines.",
  "1429": "حُرُمَاتٌ and related words stem from the root ح-ر-م, with the root verb حَرُمَ meaning \"it was forbidden or prohibited,\" and حَرَّمَ meaning \"he forbade, prohibited, or made unlawful.\" The root broadly conveys meanings of prohibition, sacredness, protection, and respect. حُرُمَاتٌ means \"sacred rites\" or \"things held inviolable,\" referring to what must be honored and protected from violation. This term also carries the meaning of \"violations,\" as it denotes what is prohibited or dishonored when sacred boundaries are transgressed. The connection lies in the emphasis on inviolability and reverence, reflecting the root's focus on sacredness and prohibition.",
  "1430": "حُرٌّ and related words stem from the root ح-ر-ر, with the root verb حَرَّ meaning \"he was free.\" حُرٌّ means \"free person\" or \"noble.\" The connection lies in the state of being free from bondage and possessing noble qualities, reflecting the root’s emphasis on freedom, dignity, and elevation. Just as something unrestricted moves with independence, a حُرٌّ is one who is not enslaved, embodying self-determination and honor. The word also conveys purity and refinement, as true nobility is associated with moral integrity and untainted character.",
  "1431": "حُزْنٌ and related words stem from the root ح-ز-ن, with the root verb حَزِنَ meaning \"he was sad\" or \"he grieved.\" حُزْنٌ means \"grief,\" \"sorrow,\" or \"sadness,\" emphasizing the depth of emotional pain. The root broadly conveys themes of difficulty, emotional weight, and the challenges associated with enduring loss or hardship. The connection lies in experiencing hardship or distress, directly relating to the root's connotation of heaviness. This term embodies the profound sense of loss that weighs upon the heart and the internal struggle to overcome it.",
  "1432": "حُسُومٌ and related words stem from the root ح-س-م, with the root verb حَسَمَ meaning \"he cut off\" or \"he ended decisively.\" حُسُومٌ means \"cutting off entirely\" or \"severing completely.\" The connection lies in the finality and totality of removal, whether referring to physical destruction, the ending of a matter without continuation, or the elimination of something beyond recovery. This root conveys a sense of absolute cessation, emphasizing a forceful and irreversible conclusion.",
  "1433": "حُسْبَانٌ and related words stem from the root ح-س-ب, with the root verb حَسِبَ meaning \"he reckoned\" or \"he calculated.\" حُسْبَانٌ means \"calculation\" or \"reckoning,\" referring to the process of accounting. The connection lies in computation and assessment, directly relating to the root's emphasis on reckoning. This root conveys themes of precise measurement and universal order, reflected in celestial calculations, highlighting harmony and precision in creation.",
  "1434": "حُسْنٌ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he was beautiful.\" حُسْنٌ means \"beauty\" or \"goodness,\" referring to the quality of being excellent. The root conveys themes of inherent virtue, aesthetic charm, and moral superiority. The connection lies in embodying aesthetic or moral virtues, directly relating to the root's emphasis on excellence. This term captures what is admirable and pleasing, both outwardly and inwardly.",
  "1435": "حُسْنَىٰ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he was beautiful.\" It means \"best\" or \"most beautiful,\" often signifying the highest standard of goodness and excellence. The root conveys perfection, superior virtue, and ultimate beauty, highlighting what is most refined and praiseworthy. The connection lies in reaching the pinnacle of goodness, where excellence is fully realized. This term often denotes the best possible outcome or reward, embodying ideal results and the highest forms of virtue. It is also used in الْأَسْمَاءُ الْحُسْنَىٰ, referring to the most beautiful names of Allah, which encompass His perfect and exalted attributes.",
  "1436": "الْحُسْنَيَيْنِ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he was beautiful.\" الْحُسْنَيَيْنِ means \"two good things\" or \"two best outcomes,\" specifically referring to the two favorable outcomes for believers: victory in battle or martyrdom in the cause of Allah (ﷻ). The root conveys themes of goodness, balance, and favorability. The connection lies in viewing both triumph and sacrifice as forms of success, directly relating to the root's emphasis on goodness and excellence. This term reflects the deep faith of believers, who regard either outcome as a manifestation of Allah's (ﷻ) favor and mercy.",
  "1437": "حُصُونٌ and related words stem from the root ح-ص-ن, with the root verb حَصُنَ meaning \"it was fortified,\" and حَصَّنَ meaning \"he fortified,\" \"he protected,\" or \"he made inaccessible.\" حُصُونٌ (plural of حِصْنٌ) means \"fortresses\" or \"strongholds,\" referring to structures built for protection and defense. The connection lies in fortification and security, emphasizing strength, resilience, and the strategic measures taken to guard against threats."
};
